// AUTO-GENERATED from seo-rules.json by scripts/build-checklist.mjs — do not edit.
export default {"name":"Astro SEO Launch Kit","description":"A comprehensive, current, myth-free SEO launch checklist for Astro sites on Cloudflare Pages or Vercel.","version":"1.0.0","rulesVersion":"2026-06-24","counts":{"total":209,"bySeverity":{"critical":48,"high":97,"medium":49,"low":15},"automatable":185},"sections":[{"key":"foundations","name":"Foundations & Astro Config","description":"The config and architecture decisions everything else depends on: the site URL, static prerendering, the right adapter, content collections, and how the <head> is assembled."},{"key":"crawlability","name":"Crawlability & Indexation","description":"Whether search engines can find, fetch, and index your pages: robots.txt, sitemaps, noindex hygiene, and content/links that exist in the server-rendered HTML."},{"key":"metadata","name":"Metadata, Head & Social","description":"The per-page tags that decide how pages look in search results and when shared: titles, descriptions, Open Graph, Twitter cards, favicons, charset, and language."},{"key":"structured-data","name":"Structured Data (Schema.org)","description":"JSON-LD that makes pages eligible for rich results and helps engines understand entities: Organization, WebSite, Article, Product, and BreadcrumbList."},{"key":"performance","name":"Performance & Core Web Vitals","description":"The speed and stability signals Google measures from real users: LCP, INP, and CLS, plus the loading, caching, font, and JS tactics that move them."},{"key":"images","name":"Images & Media","description":"Fast, accessible, indexable media via astro:assets: explicit dimensions, modern formats, responsive srcset, alt text, and correct lazy/eager loading."},{"key":"urls","name":"URLs, Redirects & i18n","description":"A clean, canonical, non-duplicating URL surface: canonical tags, www/HTTPS/trailing-slash redirects, parameter handling, and hreflang."},{"key":"accessibility","name":"Accessibility & Mobile UX","description":"Inclusive, mobile-friendly markup that overlaps strongly with quality/UX signals: landmarks, headings, contrast, focus, labels, and tap targets."},{"key":"platform","name":"Platform & Deployment (Cloudflare / Vercel)","description":"Getting the deploy right: the correct adapter, HTTPS/SSL, a single canonical host, security headers, caching, and platform-specific gotchas."},{"key":"trust","name":"Analytics, Monitoring & Trust","description":"Proving the site works and earning trust: analytics, Search Console/Bing verification, uptime/error monitoring, and the E-E-A-T pages users and Google expect."},{"key":"antipatterns","name":"Anti-Patterns to Avoid","description":"Outdated or risky tactics that waste effort or get you penalized: keyword stuffing, cloaking, indexable staging, dead meta tags, and FID-era advice."}],"rules":[{"id":"foundations-content-collections-routes-generated","section":"foundations","title":"Generate every content-collection page via getStaticPaths (v5 entry.id)","severity":"critical","stage":"build","automatable":true,"check_type":"body_regex","what":"Markdown/MDX in content collections does not auto-create pages. A dynamic route (src/pages/blog/[...id].astro in v5) must call getCollection() in getStaticPaths() and return every entry. In the v5 content layer entries expose `id` (the old `slug` property was removed) and the config lives at src/content.config.ts (not src/content/config.ts).","why":"Without getStaticPaths the collection content has no URL: no page is built, nothing enters the sitemap, and the content is unindexable.","fix":"In src/pages/blog/[...id].astro:\n```js\nexport async function getStaticPaths() {\n  const posts = await getCollection('blog');\n  return posts.map(p => ({ params: { id: p.id }, props: { post: p } }));\n}\n```\nUse p.id (not p.slug). Define the collection with a loader in src/content.config.ts.","how_to_check":"Compare counts: `find src/content/blog -name '*.md' | wc -l` against `find dist/blog -name '*.html' | wc -l` (allowing for drafts). They should match; a mismatch means routes are missing.","common_mistakes":"Using removed entry.slug in v5; keeping the old src/content/config.ts path; filtering getStaticPaths by an env flag that silently drops posts in production.","platform_notes":"None — getStaticPaths runs at build time on both platforms' CI.","sources":["https://docs.astro.build/en/guides/content-collections/","https://docs.astro.build/en/guides/upgrade-to/v5/"]},{"id":"foundations-jsonld-injection-safe","section":"foundations","title":"Inject JSON-LD with set:html + JSON.stringify inside <head>","severity":"critical","stage":"build","automatable":true,"check_type":"json_ld","what":"Emit every JSON-LD block as `<script type=\"application/ld+json\" set:html={JSON.stringify(schemaObj)} />` and place it in the document <head>. Never build JSON-LD with raw string interpolation or template literals, and avoid injecting it client-side into <body> after hydration.","why":"Astro escapes element text by default; set:html bypasses that, and JSON.stringify handles quote/character escaping so titles with quotes or angle brackets cannot corrupt the JSON or open an injection vector. <head> placement also avoids Googlebot's ~2MB crawl cutoff (data low in a large <body> may never be parsed) and is parsed more reliably by AI/third-party crawlers; client-injected schema may be missed before the crawl timeout.","fix":"In a layout/BaseHead component within <head>: `<script type=\"application/ld+json\" set:html={JSON.stringify(schema)} />`. For typed authoring, optionally use astro-seo-schema (schema-dts backed): `import { Schema } from 'astro-seo-schema'`.","how_to_check":"Parse built HTML, select `head script[type='application/ld+json']` (cheerio), assert >= 1 node on pages carrying structured data, and JSON.parse each block's contents — any parse failure or a block found only in <body> is a fail.","common_mistakes":"Backtick template literals embedding dynamic values instead of JSON.stringify on an object; appending the schema via a client framework after page load.","platform_notes":"None — both platforms serve the prerendered <head> as-is.","sources":["https://stephen-lunt.dev/blog/astro-structured-data/","https://docs.astro.build/en/reference/directives-reference/","https://developers.google.com/search/docs/appearance/structured-data/intro-structured-data"]},{"id":"foundations-robots-txt-200-text-plain","section":"foundations","title":"robots.txt returns 200 with Content-Type text/plain","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"robots","what":"GET /robots.txt must return HTTP 200 with Content-Type: text/plain.","why":"A 404/5xx robots.txt makes crawlers fall back to crawling everything, while a 401/403 is treated by Google as a site-wide crawl block. A wrong content type can cause the file to download instead of being read.","fix":"Static sites: put robots.txt in public/. Dynamic: src/pages/robots.txt.ts returning `new Response(body, { headers: { 'Content-Type': 'text/plain' } })`. Avoid having both a public/robots.txt and a conflicting src/pages route.","how_to_check":"`curl -I https://example.com/robots.txt` -> status 200 and a Content-Type header containing text/plain.","common_mistakes":"Two conflicting robots.txt sources; serving application/octet-stream so the browser downloads the file.","platform_notes":"Both Cloudflare Pages and Vercel serve public/ files directly; no extra config for a static robots.txt.","sources":["https://ai-kit.net/blog/robots-txt-astro-cloudflare","https://docs.astro.build/en/reference/configuration-reference/"]},{"id":"foundations-site-config-production-url","section":"foundations","title":"Set site in astro.config to the exact production HTTPS origin","severity":"critical","stage":"build","automatable":true,"check_type":"html_head","what":"The `site` option in astro.config.mjs must be the full production HTTPS origin (e.g. https://www.example.com) with no trailing slash. It must not be localhost, an http:// URL, a *.vercel.app/*.pages.dev preview URL, or undefined.","why":"Astro.site is the base for every absolute URL the site emits: canonical tags, og:url, og:image, hreflang hrefs, and all @astrojs/sitemap <loc> values are built from `new URL(path, Astro.site)`. If unset, canonicals become undefined/relative and the sitemap integration refuses to emit absolute URLs; if set to a staging/preview domain, every canonical and sitemap entry points at the wrong host. This is a compound critical failure touching nearly every other SEO signal.","fix":"defineConfig({ site: 'https://www.example.com' }) with no trailing slash. For multi-environment builds read an env var: `site: process.env.SITE_URL ?? 'https://www.example.com'`, and set SITE_URL in the platform's environment-variable settings (production = canonical domain, preview = preview URL). Build canonicals with `new URL(Astro.url.pathname, Astro.site).href`.","how_to_check":"GET / and parse <link rel=\"canonical\"> href: assert it is absolute and its scheme+host exactly match the production origin. In CI also assert dist/sitemap-0.xml exists and every <loc> starts with the production origin, and that `grep -r 'localhost' dist/ --include='*.html' --include='*.xml'` returns nothing.","common_mistakes":"Never updating the initial scaffold value http://localhost:4321; pointing site at the Vercel/Pages preview URL instead of the custom domain; including a trailing slash, which produces doubled slashes in generated URLs; leaving site unset entirely.","platform_notes":"Cloudflare Pages: set SITE_URL under Settings > Environment Variables (Production). Vercel: set SITE_URL under Project Settings > Environment Variables (Production). Otherwise build-time only, no platform difference.","sources":["https://docs.astro.build/en/reference/configuration-reference/","https://docs.astro.build/en/guides/integrations-guide/sitemap/"]},{"id":"foundations-ssr-adapter-installed","section":"foundations","title":"Install the correct platform adapter when any route uses SSR","severity":"critical","stage":"build","automatable":true,"check_type":"manual","what":"If output is 'server' or any route sets prerender=false, the matching adapter must be installed and configured: @astrojs/cloudflare for Cloudflare Pages/Workers, @astrojs/vercel for Vercel. Pure static sites need no adapter.","why":"Without the right adapter, server-rendered routes throw build errors or silently fall back, producing broken pages/404s in production. The adapter also wires up redirects, image optimization, and edge/function deployment.","fix":"Run `npx astro add cloudflare` or `npx astro add vercel` to add the adapter to defineConfig. On Cloudflare use `adapter: cloudflare({ platformProxy: { enabled: true } })` so local dev simulates D1/KV/R2. Ensure the adapter matches the actual deployment target.","how_to_check":"If any .astro file contains `export const prerender = false` or output is 'server', grep astro.config.* for an adapter import and confirm it matches the deploy target; the build must complete with no adapter-related errors. Then deploy and confirm SSR routes return dynamic (not stale static) content.","common_mistakes":"Installing @astrojs/vercel but deploying to Cloudflare (or vice versa), causing runtime failures; forgetting platformProxy for Cloudflare local dev.","platform_notes":"Cloudflare: @astrojs/cloudflare with platformProxy for local bindings. Vercel: @astrojs/vercel auto-detects region from Vercel env.","sources":["https://docs.astro.build/en/guides/on-demand-rendering/","https://docs.astro.build/en/guides/deploy/cloudflare/"]},{"id":"foundations-static-prerender-indexable-pages","section":"foundations","title":"Prerender all indexable pages to static HTML (output static, no needless SSR)","severity":"critical","stage":"build","automatable":true,"check_type":"html_element","what":"Every SEO-critical route must be statically prerendered. In Astro v5 output defaults to 'static'; routes with `export const prerender = false` are server-rendered per request and excluded from the auto-generated sitemap. output: 'hybrid' was removed in v5 — use 'static' with per-route prerender=false opt-out (or 'server' with explicit prerender=true on static pages).","why":"Static HTML is immediately available, cache-friendly at the edge, and delivers identical content to every requester including crawlers. SSR pages are not auto-listed in the sitemap and can drift from the static contract. Data needed at build time should be fetched in getStaticPaths, not by flipping a content page to SSR.","fix":"Keep the default `output: 'static'` and do nothing extra for content pages. Fetch remote data at build time via getStaticPaths instead of setting prerender=false on an article/listing route. Reserve prerender=false for genuinely request-dependent routes (forms, auth, personalization). Do not use output: 'hybrid' in v5 — it throws a build error.","how_to_check":"After build, assert dist/ contains a .html file for every content page and that no server-only route appears in /sitemap-0.xml. Pages with prerender=false will be absent from dist/.","common_mistakes":"Setting prerender=false on a blog post just because it calls an API; using output: 'hybrid' (removed in v5).","platform_notes":"SSR routes require the matching adapter (covered separately). Pure static sites need no adapter.","sources":["https://docs.astro.build/en/guides/on-demand-rendering/","https://docs.astro.build/en/guides/upgrade-to/v5/","https://astro.build/blog/astro-5/"]},{"id":"foundations-base-config-matches-deployment","section":"foundations","title":"Set base only for subdirectory deployments, otherwise leave it default","severity":"high","stage":"build","automatable":true,"check_type":"http_status","what":"The astro `base` option must match the deployment path: set `base: '/blog'` only when the site lives at example.com/blog/, and leave it unset (default '/') for root deployments. A wrong base prefixes all asset and internal-link paths incorrectly.","why":"A mismatched base breaks asset URLs (404s on /_astro/ files), internal navigation, and canonical URLs. Cloudflare Pages and Vercel both deploy to root by default, so base is usually unnecessary.","fix":"For subdirectory deployments set `defineConfig({ base: '/blog' })` and reference internal URLs and public/ assets with the base prefix (import.meta.env.BASE_URL). For root deployments on Cloudflare Pages/Vercel, do not set base (avoid even base: '/', which can introduce double-slash issues). Note BASE_URL is also affected by trailingSlash.","how_to_check":"Fetch the homepage and inspect <script src> / <link href> for /_astro/ assets: paths must carry the correct base prefix and return 200. Confirm <link rel=canonical> has no unexpected path prefix or double slash.","common_mistakes":"Setting base on a root-deployed site (assets 404); forgetting base on a subdirectory deployment; forgetting to update internal hrefs after setting base.","platform_notes":"Cloudflare Pages and Vercel deploy to root by default (no base). GitHub Pages-style subdirectory hosting requires base.","sources":["https://docs.astro.build/en/reference/configuration-reference/","https://github.com/withastro/astro/issues/4229"]},{"id":"foundations-clean-lowercase-slugs","section":"foundations","title":"Use lowercase, hyphen-separated, human-readable URL slugs","severity":"high","stage":"build","automatable":true,"check_type":"body_regex","what":"Generated URLs should be /blog/my-post-title — lowercase, words separated by hyphens, no uppercase letters or underscores (e.g. not /blog/MyPostTitle or /blog/my_post_title).","why":"Search engines and users prefer lowercase hyphenated URLs; case-sensitive hosts can serve mixed-case variants as duplicate content.","fix":"The v5 content layer derives the entry id from the filename — name files lowercase-hyphenated. To normalize programmatically, supply a custom `generateId()` in the loader that lowercases and slugifies. The frontmatter `slug` override field does not exist in the v5 content layer; use generateId() instead. Add 301 redirects when changing existing URLs.","how_to_check":"`find dist -name '*[A-Z_]*' -name '*.html'` should return nothing; spot-check several sitemap URLs for lowercase/hyphen formatting.","common_mistakes":"CMS content with camelCase filenames producing camelCase ids; underscore URLs migrated without redirects; expecting a frontmatter slug field to override the URL in v5.","platform_notes":"Both Cloudflare Pages and Vercel treat file paths as case-sensitive by default.","sources":["https://docs.astro.build/en/guides/content-collections/","https://fsjs.dev/build-seo-optimized-static-sites-astro/"]},{"id":"foundations-collection-schema-required-seo-fields","section":"foundations","title":"Enforce required SEO frontmatter via the collection Zod schema","severity":"high","stage":"build","automatable":true,"check_type":"manual","what":"The defineCollection Zod schema (in src/content.config.ts, the v5 path) must mark title, description, and pubDate as required, ideally with sensible length bounds, and must use a loader. Missing fields should fail the build, not ship.","why":"A missing title or description breaks that page's meta tags and OG card. Build-time schema validation catches it before deploy instead of silently publishing SEO-broken content.","fix":"In src/content.config.ts:\n```js\nconst blog = defineCollection({\n  loader: glob({ pattern: '**/*.md', base: './src/content/blog' }),\n  schema: z.object({\n    title: z.string().min(10).max(65),\n    description: z.string().min(50).max(160),\n    pubDate: z.coerce.date(),\n    draft: z.boolean().default(false),\n  }),\n});\n```\nUse z.coerce.date() since frontmatter dates are strings.","how_to_check":"Add a markdown file missing `title` and run `astro build`; it must throw a Zod validation error and fail the build. Statically, confirm title/description are not .optional() in src/content.config.ts.","common_mistakes":"Making all fields optional; omitting length validation; using the old src/content/config.ts path; using z.date() instead of z.coerce.date(); forgetting the required v5 loader.","platform_notes":"None — Zod validation runs at build time.","sources":["https://docs.astro.build/en/guides/content-collections/","https://joost.blog/astro-seo-complete-guide/"]},{"id":"foundations-custom-404-returns-404","section":"foundations","title":"Custom 404 page returns a real HTTP 404 (no soft 404)","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"src/pages/404.astro must exist and be served with an HTTP 404 status for unknown URLs — never a 200 (soft 404) or a 302.","why":"Soft 404s confuse Googlebot, which can index empty error pages as real content and waste crawl budget. A true 404 tells crawlers the URL does not exist.","fix":"Create src/pages/404.astro. On Cloudflare Pages (static) 404.html is auto-served with a 404 status. On Cloudflare Workers add `not_found_handling` to wrangler.toml. For SSR, return the 404 response from middleware/the adapter. Verify on a real deployment.","how_to_check":"`curl -s -o /dev/null -w '%{http_code}' https://example.com/this-does-not-exist-xyz123` must print 404 (not 200/302).","common_mistakes":"Cloudflare Workers missing not_found_handling; Vercel static output showing the platform default 404 without the custom 404 status; assuming dev behavior matches production.","platform_notes":"Cloudflare Pages static: auto 404. Cloudflare Workers: wrangler.toml not_found_handling. Vercel: confirm on a real deploy; may need adapter-level config.","sources":["https://docs.astro.build/en/guides/deploy/cloudflare/","https://github.com/withastro/astro/issues/9578"]},{"id":"foundations-drafts-excluded-from-production","section":"foundations","title":"Exclude draft entries from production pages and sitemap","severity":"high","stage":"build","automatable":true,"check_type":"sitemap","what":"Content entries with draft: true must not generate HTML pages or sitemap entries in production builds — and the filter must be applied to both the listing AND the getStaticPaths route, not just the index.","why":"Accidentally published drafts can be indexed, leak unreleased content, and waste crawl budget. Filtering only the index leaves the individual page reachable and indexable.","fix":"Filter in getStaticPaths and in any listing query: `await getCollection('blog', ({ data }) => import.meta.env.PROD ? !data.draft : true)` (drafts visible in dev, hidden in prod). Define `draft: z.boolean().default(false)` in the schema.","how_to_check":"Build, then confirm no known draft slug exists in dist/ (e.g. `find dist -name 'draft-*.html'` empty) and that /sitemap-0.xml contains no draft URLs.","common_mistakes":"Filtering drafts from the index listing but still generating the individual route, leaving an unlisted-but-live page.","platform_notes":"import.meta.env.PROD is true in both Cloudflare Pages and Vercel build environments.","sources":["https://docs.astro.build/en/guides/content-collections/"]},{"id":"foundations-faceted-nav-param-urls-managed","section":"foundations","title":"Control faceted/filter parameter URLs to prevent index bloat","severity":"high","stage":"pre-launch","automatable":false,"check_type":"manual","what":"On sites with faceted navigation (filter/sort parameters), parameter combinations that create duplicate or low-value pages must be kept from being crawled/indexed — via robots.txt Disallow patterns, canonicals to the unfiltered page, or by keeping filter state out of indexable URLs (URL fragments or JS-only filtering).","why":"Each filter combination is a unique URL; a modest catalogue times several filter dimensions can generate millions of near-duplicate URLs, exhausting crawl budget and bloating the index. Google's GSC URL Parameters tool was removed, so it cannot be relied on.","fix":"In Astro SSG, implement filtering client-side and keep state in URL fragments (#color=red) or apply it via JS without changing the URL. If filter state lives in query params (?color=red), add Disallow patterns in public/robots.txt (e.g. Disallow: /*?color=) or set a canonical on every filter variant pointing to the unfiltered page.","how_to_check":"Crawl from internal links, collect param-bearing URLs, and verify each is either Disallowed in robots.txt, carries a canonical to the base URL, or simply returns the base content with that canonical.","common_mistakes":"Letting all query params be crawled/indexed; misapplied canonicals on filter pages; relying on the removed GSC URL Parameters tool.","platform_notes":"None.","sources":["https://developers.google.com/search/docs/crawling-indexing/crawling-managing-faceted-navigation"]},{"id":"foundations-minimal-deferred-client-directives","section":"foundations","title":"Hydrate islands with the least-eager client directive that works","severity":"high","stage":"build","automatable":true,"check_type":"lighthouse","what":"Each interactive island should use the least-eager directive that still delivers the needed UX: client:load only for truly critical first-screen interactions, client:idle for secondary above-fold UI, client:visible for below-fold, client:media for viewport-conditional. Avoid wrapping whole layout shells or static lists in hydrated framework components.","why":"Every client:load island adds JS to the initial bundle evaluated on the main thread, raising TBT/INP and delaying LCP. client:idle (requestIdleCallback) and client:visible (IntersectionObserver) defer hydration so the first paint and Core Web Vitals improve. A content-focused Astro page should ship very little JS.","fix":"Audit every `client:` directive and downgrade where possible: nav dropdown above the fold = client:load; comments at page bottom = client:visible; sidebar newsletter = client:idle; mobile-only menu = client:media=\"(max-width: 768px)\". Wrap a list in one island rather than rendering many tiny islands.","how_to_check":"Run Lighthouse / measure CWV (TBT/INP) and total JS: `find dist/_astro -name '*.js' | xargs wc -c | tail -1` — a content page should ship well under ~20 KB JS. In DevTools Coverage, unused JS on initial load should be low. Justify each `client:load` occurrence.","common_mistakes":"Defaulting to client:load everywhere; mapping a list into many small islands; hydrating a framework component that has no interactivity.","platform_notes":"None.","sources":["https://docs.astro.build/en/concepts/islands/","https://dev.to/lovestaco/astros-client-directives-when-and-where-to-use-each-165g"]},{"id":"foundations-no-seo-content-in-unrendered-islands","section":"foundations","title":"Keep SEO-critical content out of client:only and server:defer islands","severity":"high","stage":"build","automatable":true,"check_type":"body_regex","what":"H1s, primary article/body text, and important metadata must live in server-rendered HTML, not inside client:only components (which emit zero server HTML) or server:defer Server Islands (whose deferred content is fetched client-side, leaving only the fallback slot server-rendered). client:load/idle/visible components DO include static HTML and are safe for content.","why":"Googlebot may not execute the client-side JS that hydrates client:only or fetches server:defer content, so that content can go unindexed. Only what is present in the raw initial HTML is guaranteed to be crawled.","fix":"Reserve client:only and server:defer for personalized/non-critical UI (avatars, cart counts, recommendations). Keep all crawlable content in the static shell. For Server Islands, ensure the fallback slot contains real content. Audit usages: `grep -r 'client:only\\|server:defer' src/`.","how_to_check":"`curl -s https://example.com/blog/sample-post | grep -o '<h1[^>]*>.*</h1>'` should return the post H1; load a page with JS disabled and confirm primary content is still readable.","common_mistakes":"Wrapping a whole section (headings + body) in a client:only React component when only one button needed hydration; putting the article H1/body inside a server:defer island for personalization.","platform_notes":"client:only and Server Islands need an SSR adapter on both platforms; the static shell is served from the edge while island content is fetched from the origin function.","sources":["https://docs.astro.build/en/concepts/islands/","https://docs.astro.build/en/guides/server-islands/"]},{"id":"foundations-single-basehead-no-duplicate-tags","section":"foundations","title":"Emit all head metadata from one BaseHead component with no duplicate tags","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"All head metadata (title, description, canonical, OG, Twitter, icons, charset, viewport, robots) must come from a single reusable component (e.g. src/components/BaseHead.astro) included once in every layout, and each tag must appear exactly once in the rendered <head> — one <title>, one meta description, one canonical, one of each OG/Twitter tag.","why":"A single source of truth guarantees every page has the complete, consistent set of head tags. Astro appends page-level <head> content to layout <head> content rather than replacing it, so defining a tag in both a page and BaseHead produces duplicates; Google uses the first canonical it sees and social scrapers get confused by duplicate OG tags.","fix":"Build src/components/BaseHead.astro with a typed props interface (title, description, ogImage, ogType, robots, canonicalOverride) and import it in every layout. Pass page/post-specific values as props — never re-declare the same meta tags in a page-level <head> block. Avoid mixing a hand-built BaseHead with a third-party SEO component that emits the same tags.","how_to_check":"Static: `grep -r '<title>' src/ --include='*.astro' | grep -v 'BaseHead'` should return nothing. Runtime/built HTML: assert each of <title>, meta[name=description], link[rel=canonical], og:title, twitter:card occurs exactly once per page (count > 1 = fail).","common_mistakes":"A page bypassing BaseHead via a different layout that also emits <title>; meta description in both BaseHead and a page <head>; astro-seo plus a hand-built BaseHead both rendering the same tags.","platform_notes":"None — build-time concern.","sources":["https://eastondev.com/blog/en/posts/dev/20251202-astro-seo-complete-guide/","https://joost.blog/astro-seo-complete-guide/","https://github.com/jonasmerlin/astro-seo"]},{"id":"foundations-trailing-slash-enforced","section":"foundations","title":"Enforce one trailing-slash form with a 301 redirect at the platform","severity":"high","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"Pick one trailing-slash convention and enforce it with a server-side redirect: with trailingSlash 'never', /page/ must 301 to /page; with 'always', /page must 301 to /page/. Both forms must never serve 200 simultaneously. Astro's trailingSlash config controls route matching/build output only — it does NOT emit HTTP redirects.","why":"/page and /page/ are distinct URLs to Google; serving both is duplicate content and splits link equity.","fix":"Set trailingSlash in astro.config.mjs, then enforce the matching redirect at the platform. Cloudflare Pages: add `_redirects` entries (or a Redirect Rule). Vercel: set the `trailingSlash` key in vercel.json. Make the platform setting consistent with Astro's config to avoid conflicting redirects.","how_to_check":"GET the wrong form (e.g. /any-page/ when config is 'never') and assert status 301 with Location pointing to the canonical form; run the reverse test for 'always'.","common_mistakes":"Setting trailingSlash in Astro but nowhere at the platform; platform config conflicting with astro.config; Cloudflare emitting 308 instead of 301.","platform_notes":"Cloudflare Pages needs explicit _redirects. Vercel uses the trailingSlash key in vercel.json. Both can conflict with Astro config — test on a real deploy.","sources":["https://realmorrisliu.com/thoughts/fixing-astro-seo-cloudflare-trailing-slash/","https://mirzapandzo.com/astro-vercel-trailingslash-and-redirects","https://developers.cloudflare.com/pages/configuration/serving-pages/"]},{"id":"foundations-jsonld-single-graph-no-mixed-formats","section":"foundations","title":"Consolidate multiple schemas into one @graph and use JSON-LD only","severity":"medium","stage":"build","automatable":true,"check_type":"json_ld","what":"When a page needs several schema types (e.g. Article + BreadcrumbList + WebPage), combine them in a single ld+json block using a top-level @graph array with @id cross-references, rather than many separate script blocks. Use JSON-LD exclusively — do not also describe the same entity in Microdata or RDFa.","why":"@graph lets entities reference each other via @id (the pattern major SEO frameworks use) and keeps @context declared once. Multiple separate blocks are valid but weaker; describing the same entity in both JSON-LD and Microdata/RDFa sends conflicting signals and adds maintenance overhead (Google treats the three formats as equally valid but duplication is the real risk).","fix":"Use a SchemaGraph.astro component that emits `{ '@context': 'https://schema.org', '@graph': [...schemas] }`, giving each entity an @id like `${canonicalUrl}#article` / `#breadcrumb`. Remove leftover itemscope/itemprop/typeof/RDFa attributes from migrated themes once JSON-LD is in place.","how_to_check":"Per page, count `script[type='application/ld+json']` blocks; if >1, recommend @graph consolidation, and when @graph is used assert it is a non-empty array. Grep rendered HTML for `itemscope`, `itemprop`, `typeof=\"schema:`, `property=\"schema:`, `vocab=\"https://schema.org\"` and flag any entity described in both JSON-LD and Microdata/RDFa.","common_mistakes":"Each component emitting its own ld+json block; repeating @context inside @graph; adding JSON-LD without removing original Microdata attributes from a purchased theme.","platform_notes":"None.","sources":["https://developers.google.com/search/docs/appearance/structured-data/intro-structured-data","https://developer.yoast.com/features/schema/functional-specification/"]},{"id":"foundations-view-transitions-no-cls","section":"foundations","title":"Prevent layout shift when using View Transitions (ClientRouter)","severity":"medium","stage":"post-launch","automatable":false,"check_type":"manual","what":"If using Astro's <ClientRouter /> (the v5 rename of <ViewTransitions />), page navigations must not cause layout shifts. Shared elements need matching transition:name values and matching computed dimensions across pages, since post-navigation shifts count toward CLS.","why":"View Transitions animate between source and target elements; mismatched sizes/positions produce visible jumps that hurt UX and CLS.","fix":"Add <ClientRouter /> to the layout <head>. Tag shared elements with the same `transition:name` on both pages and give them identical width/height. Test a baseline with `<ClientRouter fallback=\"none\">`. Use the current <ClientRouter /> name (the <ViewTransitions /> alias still works).","how_to_check":"Navigate between pages with the DevTools Performance panel recording and look for Layout Shift entries during the transition; CLS should stay < 0.1 across navigation events.","common_mistakes":"Tagging hero images with transition:name but not matching width/height across pages; assuming post-navigation shifts do not count toward CLS; using the deprecated <ViewTransitions /> name.","platform_notes":"None — browser feature. Cross-document transitions are native in Chrome/Edge 126+; Firefox 144 and Safari 18.2+ support same-document transitions (cross-document support is partial/in progress).","sources":["https://docs.astro.build/en/guides/view-transitions/"]},{"id":"crawlability-404-real-status","section":"crawlability","title":"404 pages return HTTP 404/410, not a soft 404","severity":"critical","stage":"post-launch","automatable":true,"check_type":"http_status","what":"Requests to non-existent URLs must return HTTP 404 (or 410 for permanently removed pages), not HTTP 200 with not-found content. Empty search/filter result pages must not present as thin 200 pages.","why":"Soft 404s waste crawl budget (Googlebot re-fetches them as valid pages), pollute the index with thin pages, and are flagged as errors in Search Console.","fix":"Create `src/pages/404.astro`. In static output Astro emits a `404.html` served with a true 404 by both platforms. In SSR output you must set `Astro.response.status = 404` in the frontmatter, or it returns 200.","how_to_check":"curl -sI https://example.com/this-does-not-exist-xyz123 -> assert HTTP 404 (or 410). Repeat for several random paths and a known empty-results URL.","common_mistakes":"Catch-all routes returning 200; zero-result search pages returning 200; SSR 404.astro missing the explicit status; old pages redirecting to the homepage (a soft 404).","platform_notes":"Cloudflare Pages SSR/hybrid: do NOT add `export const prerender = true` to 404.astro — it triggers Cloudflare error 1042 (Astro GH #13932, open as of 2025). Vercel SSR has had a 404-status regression (GH #14877) — verify on your adapter version.","sources":["https://developers.google.com/crawling/docs/crawl-budget","https://github.com/withastro/astro/issues/13932","https://vercel.com/kb/guide/custom-404-page"]},{"id":"crawlability-jsonld-matches-visible-content","section":"crawlability","title":"Structured data marks up only content visible on the same page","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Every JSON-LD field must correspond to content genuinely visible to a human on the same page, and the @type must match the page's primary content. Do not mark up hidden, modal, off-page, or JS-lazy-loaded content. AggregateRating may only appear when the rating and representative reviews are visible (ratingValue 1.0-5.0; ratingCount matching the visible count).","why":"Google's policies prohibit marking up hidden or mismatched content; violations trigger a structured-data manual action that suppresses all rich results for the property.","fix":"Drive schema values from the same frontmatter/API data that renders the visible page. Conditionally include AggregateRating only when `reviews.length > 0` and compute ratingValue from the rendered reviews. Add a build-time check that key fields (e.g. Article.headline) appear in the rendered text/`<h1>`.","how_to_check":"For Article: assert ld+json `headline` matches `<h1>` after normalization. For Product: assert `offers.price` matches the visible price. For AggregateRating: assert ratingValue 1.0-5.0, integer ratingCount, and at least one visible review element on the page.","common_mistakes":"AggregateRating with no visible reviews; Article schema on a hub/nav page; `ratingValue: '4.8/5'` (must be `'4.8'`); schema for content injected only by client-side JS.","platform_notes":"For Astro SSR on Cloudflare/Vercel, ensure server-rendered HTML matches the data used to build the JSON-LD.","sources":["https://developers.google.com/search/docs/appearance/structured-data/sd-policies","https://developers.google.com/search/docs/appearance/structured-data/review-snippet"]},{"id":"crawlability-jsonld-pages-crawlable","section":"crawlability","title":"Pages with structured data are crawlable and indexable","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Every page carrying JSON-LD must be crawlable (not Disallowed in robots.txt) and indexable (no noindex meta tag or X-Robots-Tag). Blocked or noindexed pages are ineligible for rich results regardless of markup quality.","why":"Google's structured data policies explicitly state pages with restricted Googlebot access cannot be served rich results.","fix":"Ensure robots.txt does not Disallow key paths (/blog/, /products/) and that those pages set no noindex. For SSR (prerender=false) pages, confirm they do not inherit a stale default noindex from the layout.","how_to_check":"For each URL with ld+json: test the path against robots.txt rules (no Disallow match) and GET it asserting no `noindex` in `meta[name=robots]` or the `X-Robots-Tag` header. Confirm via the Rich Results Test (no 'Page could not be fetched').","common_mistakes":"Staging robots.txt deployed to production blocking the path; SSR pages inheriting a default noindex.","platform_notes":"Audit Cloudflare Pages `_headers` and Vercel `vercel.json` headers for X-Robots-Tag rules affecting these paths.","sources":["https://developers.google.com/search/docs/appearance/structured-data/sd-policies"]},{"id":"crawlability-no-accidental-noindex","section":"crawlability","title":"No production page carries an accidental noindex directive","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"html_head","what":"No page intended to be indexed may contain `<meta name=\"robots\" content=\"noindex\">` / `<meta name=\"googlebot\" content=\"noindex\">`, nor an `X-Robots-Tag: noindex` response header. This is the #1 cause of 'why is my site not in Google' at launch.","why":"A stray noindex from dev/staging carried into production removes pages from the index entirely within days, and is invisible to standard uptime monitoring.","fix":"Audit your base layout for conditional noindex logic. Gate on `import.meta.env.PROD` and never default to noindex: `const robots = import.meta.env.PROD ? undefined : 'noindex,nofollow'`. Only render the tag for genuinely restricted pages. Ensure the production deploy is a true production build (PROD true).","how_to_check":"GET every intended-to-be-indexed page -> parse <head> for `meta[name=robots]` / `meta[name=googlebot]` and assert content does not contain `noindex`; also assert the `X-Robots-Tag` response header has no `noindex`.","common_mistakes":"A layout with `noindex={isDev || isPreview}` that evaluates true in prod; a CMS/template field left at noindex from a migration; a per-page default never overridden.","platform_notes":"Cloudflare Pages `_headers` and Vercel `vercel.json` headers can set `X-Robots-Tag` globally — audit those files for accidental noindex rules.","sources":["https://developers.google.com/search/docs/crawling-indexing/robots-meta-tag","https://developers.google.com/search/docs/crawling-indexing/block-indexing"]},{"id":"crawlability-no-disallow-all-production","section":"crawlability","title":"Production robots.txt must not block crawling of the site","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"robots","what":"The production robots.txt must not contain a catch-all `Disallow: /` under `User-agent: *` (or `User-agent: Googlebot`), nor any rule that blocks the main site content. robots.txt must also be reachable at /robots.txt with HTTP 200 and Content-Type text/plain.","why":"A staging robots.txt copied to production is the most common catastrophic launch bug: a single `Disallow: /` silently deindexes the entire site within days, and is invisible to uptime monitors. A 5xx on robots.txt makes Googlebot fall back to its last cached version.","fix":"Prefer a static `public/robots.txt`. For environment-specific rules, generate it from `src/pages/robots.txt.ts` (`export const GET`) gated on `import.meta.env.PROD` (Vite replaces it at build time) and mark `export const prerender = true` for SSR/hybrid. Add a post-deploy CI assertion: `curl -s https://yourdomain.com/robots.txt | grep -i 'disallow: /'` must return nothing.","how_to_check":"GET /robots.txt -> assert HTTP 200 and Content-Type text/plain; parse all User-agent groups and assert no bare `Disallow: /` (or `/*`) applies to `*` or any Googlebot agent.","common_mistakes":"Copying a staging/preview robots.txt to production; a CI pipeline that does not differentiate environments; placing robots.txt in src/ instead of public/.","platform_notes":"Neither Cloudflare Pages nor Vercel injects a default robots.txt; the file is entirely owned by your project and served from the build output root.","sources":["https://searchengineland.com/robots-txt-seo-453779","https://www.searchviu.com/en/robots-txt-staging-environment/","https://docs.astro.build/en/guides/integrations-guide/sitemap/"]},{"id":"crawlability-sitemap-present-and-served","section":"crawlability","title":"sitemap-index.xml is present, returns 200, and uses absolute HTTPS URLs","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"sitemap","what":"@astrojs/sitemap must be installed and registered, and the generated sitemap-index.xml must be served at the site root with HTTP 200, an XML Content-Type, and a `<sitemapindex>` root. Every `<loc>` in the child sitemaps must be an absolute `https://` URL on the canonical hostname.","why":"A missing/404 sitemap or one with relative or wrong-origin URLs is one of the most common crawlability failures on freshly launched sites; without it Google relies solely on link discovery and may index the wrong origin.","fix":"`npx astro add sitemap`, then set `site: 'https://www.example.com'` in astro.config.mjs (required — the integration uses it as the base for all `<loc>` and throws without it). The sitemap is generated only at build, never by `astro dev`. For SSR/hybrid ensure the sitemap files land in the prerendered (static) portion of the build.","how_to_check":"GET /sitemap-index.xml -> assert 200, Content-Type contains `xml`, body contains `<sitemapindex`. GET each child /sitemap-N.xml -> assert every `<loc>` starts with the canonical `https://` origin and none start with `/` or `http://`.","common_mistakes":"Installing the package but not adding `sitemap()` to integrations; omitting `site:` or pointing it at localhost/staging; checking only in dev; assuming SSR auto-generates sitemap entries.","platform_notes":"Both Cloudflare Pages and Vercel serve the static XML from the build root with no extra config.","sources":["https://docs.astro.build/en/guides/integrations-guide/sitemap/","https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap"]},{"id":"crawlability-gsc-verified-and-monitored","section":"crawlability","title":"Search Console property is verified and indexation is monitored","severity":"high","stage":"post-launch","automatable":true,"check_type":"external_tool","what":"The production domain must be verified in Google Search Console (Domain property preferred), and the Pages/Coverage report must show no significant unintended exclusions ('Crawled - currently not indexed', 'Discovered - currently not indexed', 'Blocked by robots.txt') for pages you want to rank.","why":"GSC is the primary feedback loop for indexation, coverage errors, and crawl-budget pressure — failures here are invisible to plain HTTP checks. High 'Discovered - not indexed' volume signals crawl-budget or quality problems.","fix":"Verify via a DNS TXT record (easiest on Cloudflare/Vercel) or by placing the HTML verification file in `public/`. Then review the Pages report weekly for the first month and via the URL Inspection API for key pages.","how_to_check":"GSC URL Inspection API (`searchconsole.urlInspection.index.inspect`) on a sample of key pages -> assert indexingState INDEXING_ALLOWED and crawlState CRAWLED; review the Pages report's Excluded buckets for important URLs.","common_mistakes":"Verifying only a URL-prefix property (misses http/https/www variants); ignoring GSC for months; treating all exclusions as harmless.","platform_notes":"DNS TXT verification is simplest when DNS is managed in Cloudflare or Vercel.","sources":["https://support.google.com/webmasters/answer/7451001","https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap"]},{"id":"crawlability-no-broken-or-orphan-pages","section":"crawlability","title":"No broken internal links and no orphaned indexable pages","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"No internal `<a href>` may point to a 4xx/5xx URL, and every indexable page must be reachable from at least one internal anchor link (not just the XML sitemap).","why":"Broken links waste crawl budget and signal poor quality; orphan pages (sitemap-only, no internal links) are crawled rarely, lack hierarchy context, and rank poorly because Google discovers pages primarily through links.","fix":"Run a post-build/live crawl (e.g. `astro-broken-link-checker`, Screaming Frog) — note `astro check` validates TypeScript, not link targets. Ensure every content-collection entry generated by `getStaticPaths` is linked from an index/archive/category page built via `getCollection`.","how_to_check":"Crawl from the homepage following only `<a href>` links: collect all discovered URLs, GET each and assert HTTP 200; then diff the sitemap URL set against the crawled set and flag any sitemap URL not reachable by link.","common_mistakes":"Markdown links to deleted pages; renamed slugs without redirects; hardcoded localhost/staging links; customPages entries with no internal links.","sources":["https://developers.google.com/crawling/docs/crawl-budget"]},{"id":"crawlability-noindex-not-disallowed-and-not-in-sitemap","section":"crawlability","title":"noindex pages are crawlable but excluded from the sitemap","severity":"high","stage":"pre-launch","automatable":true,"check_type":"sitemap","what":"Pages you want deindexed must use noindex WITHOUT a robots.txt Disallow (the crawler must fetch the page to see the directive), and they must NOT appear in the XML sitemap. Conversely, sitemap entries must point only to indexable pages.","why":"A page blocked by robots.txt can never have its noindex read, so it can persist in the index indefinitely. Listing a noindex page in the sitemap sends contradictory signals, wastes crawl budget, and surfaces GSC data-quality errors.","fix":"Choose one method per page: noindex (no Disallow) for removal from results; Disallow only for pages you never want crawled. Keep a shared `NOINDEX_PATTERNS` constant referenced by both the layout's noindex logic and the sitemap `filter()`: `sitemap({ filter: (page) => !NOINDEX_PATTERNS.some(p => page.includes(p)) })`.","how_to_check":"For each noindex URL: assert it is NOT disallowed by robots.txt. For each `<loc>` in the sitemap: GET it and assert no `noindex` meta tag or X-Robots-Tag header.","common_mistakes":"Combining Disallow + noindex thinking they 'double block'; adding noindex in a template but forgetting the sitemap filter.","sources":["https://developers.google.com/search/docs/crawling-indexing/block-indexing","https://docs.astro.build/en/guides/integrations-guide/sitemap/"]},{"id":"crawlability-preview-deploys-noindexed","section":"crawlability","title":"Preview/staging deployments are blocked from indexing","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_header","what":"Preview and staging environments must not be indexable. Both platforms auto-noindex some preview surfaces but leave notable gaps that must be closed manually.","why":"Indexed preview deployments create duplicate content that dilutes signals and can cause Google to pick the wrong canonical.","fix":"Vercel: auto-sets `X-Robots-Tag: noindex` on non-production *.vercel.app previews, but NOT on a custom domain assigned to a non-production branch — add it via vercel.json headers. Cloudflare Pages: auto-noindexes branch preview hash URLs but NOT the production `project.pages.dev` subdomain — add `https://*.pages.dev/* X-Robots-Tag: noindex` to `_headers`.","how_to_check":"curl -I against each preview URL (and the *.pages.dev / preview custom domain) -> assert the `X-Robots-Tag` header contains `noindex`.","common_mistakes":"Assuming Vercel auto-noindex covers custom domains on preview branches; assuming the Cloudflare production pages.dev subdomain is auto-noindexed.","platform_notes":"Vercel: gap is custom domains on non-prod branches. Cloudflare Pages: gap is the production project.pages.dev subdomain — must be set in _headers.","sources":["https://vercel.com/kb/guide/are-vercel-preview-deployment-indexed-by-search-engines","https://developers.cloudflare.com/pages/configuration/preview-deployments/"]},{"id":"crawlability-robots-allows-css-js","section":"crawlability","title":"robots.txt does not block CSS/JS assets and is syntactically valid","severity":"high","stage":"pre-launch","automatable":true,"check_type":"robots","what":"No Disallow rule may block paths serving CSS or JavaScript Googlebot needs to render pages (Astro emits hashed assets to `/_astro/`). The file must also be valid per the Robots Exclusion Protocol (UTF-8, no BOM, each directive on its own line, User-agent before Allow/Disallow).","why":"Googlebot renders with headless Chromium; blocking CSS/JS forces blind rendering that suppresses rankings and can break layout. Malformed robots.txt causes crawlers to mis-parse or ignore rules entirely.","fix":"Ensure `public/robots.txt` has no `Disallow: /_astro/`, `/assets/`, `/css/`, or `/js/`. Validate with a parser such as the `robots-parser` npm package in a build/CI test, or GSC Settings > robots.txt.","how_to_check":"GET /robots.txt -> resolve all Disallow rules against known asset dirs (/_astro/, /assets/, /js/, /css/) and flag any match -> feed the file to a robots.txt parser and assert 0 parse errors.","common_mistakes":"Blanket-blocking `/_astro/` to 'hide' design; copy-pasting a CMS robots.txt with legacy paths; missing blank line between agent groups; CRLF line endings.","sources":["https://searchengineland.com/robots-txt-seo-453779","https://www.conductor.com/academy/robotstxt/"]},{"id":"crawlability-robots-references-sitemap","section":"crawlability","title":"robots.txt references the sitemap with an absolute URL","severity":"high","stage":"pre-launch","automatable":true,"check_type":"robots","what":"robots.txt must contain a `Sitemap:` directive pointing to the absolute URL of the sitemap index, e.g. `Sitemap: https://example.com/sitemap-index.xml` (not the relative path and not sitemap-0.xml).","why":"The `Sitemap:` directive is the lightest-weight way for all crawlers (not just Googlebot) to discover the sitemap without manual submission. The robots spec requires an absolute URL.","fix":"Add `Sitemap: https://yoursite.com/sitemap-index.xml` to `public/robots.txt`, or in a `src/pages/robots.txt.ts` endpoint return `Sitemap: ${new URL('sitemap-index.xml', site).href}`. The URL must match `site` in astro.config.mjs.","how_to_check":"GET /robots.txt -> grep `^Sitemap:` -> assert value is an absolute https:// URL ending in sitemap-index.xml -> GET that URL -> assert HTTP 200.","common_mistakes":"Relative path; pointing to sitemap-0.xml instead of the index; omitting the directive.","sources":["https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap","https://docs.astro.build/en/guides/integrations-guide/sitemap/"]},{"id":"crawlability-sitemap-only-indexable-canonical-urls","section":"crawlability","title":"Sitemap lists only canonical, indexable, live URLs","severity":"high","stage":"build","automatable":true,"check_type":"sitemap","what":"Every publicly indexable route must appear in the sitemap, and only those: no draft/admin pages, no redirects, no 4xx/5xx, no parameter/facet/tag-archive duplicates. Draft posts should never generate routes in the first place.","why":"Omitting published pages causes crawl gaps; including drafts, redirects, or non-canonical URLs wastes crawl budget, weakens the sitemap's (weak) canonical signal, and triggers GSC coverage errors.","fix":"Filter routes at generation: `getCollection('blog', ({data}) => !data.draft)` so drafts never become pages. Exclude utility paths with the sitemap `filter()` option (e.g. exclude `/admin/`, `/tags/`, URLs with `?`); use `serialize()` returning undefined for fine-grained exclusion. Remember content-collection entries do not auto-create routes.","how_to_check":"Count `<url>` entries vs `find dist -name '*.html' | wc -l` (minus known non-indexable pages); diff should be zero or explained. Then GET each `<loc>` and assert HTTP 200 (no 3xx/4xx) and no noindex.","common_mistakes":"Including tag/author/paginated pages that are noindexed; including parameter URLs from filters; not removing deleted pages from the sitemap.","sources":["https://docs.astro.build/en/guides/integrations-guide/sitemap/","https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap"]},{"id":"crawlability-sitemap-size-and-index-submission","section":"crawlability","title":"Sitemap files stay within size limits and the index URL is submitted","severity":"high","stage":"post-launch","automatable":true,"check_type":"sitemap","what":"Each sitemap file must stay under 50,000 URLs and 50 MB uncompressed; larger sites use a sitemap index of numbered child files. The sitemap-index.xml (not sitemap-0.xml) is what gets submitted to Google Search Console and Bing Webmaster Tools.","why":"Google ignores entries beyond the limits, leaving URLs undiscovered. Submitting sitemap-0.xml on a large site submits only the first batch; submitting the index covers every child sitemap.","fix":"@astrojs/sitemap defaults `entryLimit` to 45,000 and auto-splits into sitemap-index.xml + sitemap-0/1/2.xml. Tune with `sitemap({ entryLimit: 10000 })` if needed. Submit /sitemap-index.xml in GSC and import the GSC property (or submit the index URL) in Bing Webmaster Tools.","how_to_check":"Parse sitemap-index.xml -> for each child GET it -> assert `<url>` count <= 50000 and byte size <= 52428800. Via GSC Sitemaps API assert a submitted sitemap with errors:0 and isPending:false.","common_mistakes":"Submitting sitemap-0.xml on a large site; submitting before DNS propagates; not re-submitting after a domain migration; skipping Bing.","sources":["https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap","https://docs.astro.build/en/guides/integrations-guide/sitemap/","https://support.google.com/webmasters/answer/7451001"]},{"id":"crawlability-sitemap-ssr-routes-included","section":"crawlability","title":"Indexable SSR (prerender=false) routes are added to the sitemap manually","severity":"high","stage":"build","automatable":false,"check_type":"manual","what":"@astrojs/sitemap auto-discovers only statically built routes. On-demand rendered routes (prerender=false / output:'server') that should be indexed must be added via the `customPages` option or a custom sitemap endpoint.","why":"Indexable SSR content (e.g. DB-driven product pages) never appears in the auto-generated sitemap, so Googlebot must rely on internal links alone, slowing indexation.","fix":"Add known SSR URLs via `sitemap({ customPages: ['https://example.com/product/123', ...] })` (note: customPages accepts only a static string array — passing an async function throws a build error). For DB-driven sites, build `src/pages/sitemap.xml.ts` that queries at build/request time, or set `prerender = true` on the pages so the integration discovers them.","how_to_check":"List all routes with `prerender = false` that should be indexed and confirm each appears in /sitemap-0.xml (via customPages or a custom endpoint).","common_mistakes":"Assuming the integration includes SSR routes because they work in the browser; passing a function to customPages; generating a build-time sitemap that omits dynamic DB content.","platform_notes":"Applies identically with the @astrojs/cloudflare and @astrojs/vercel SSR adapters.","sources":["https://docs.astro.build/en/guides/integrations-guide/sitemap/","https://github.com/withastro/astro/issues/12437"]},{"id":"crawlability-sitemap-trailingslash-consistency","section":"crawlability","title":"Sitemap URLs match the site's trailing-slash convention","severity":"high","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"Every sitemap URL must use the same trailing-slash convention as the live, canonicalized site, and requesting each `<loc>` must not redirect. Align `site`, `trailingSlash`, and `build.format` in astro.config.mjs.","why":"Google treats `/page/` and `/page` as distinct URLs. If the sitemap URL redirects to the canonical form, the sitemap entry becomes a non-canonical/soft mismatch that weakens the canonical signal and wastes crawl budget.","fix":"Set `trailingSlash: 'never'` or `'always'` and a matching `build.format` ('file' = no slash, 'directory' = slash). @astrojs/sitemap inherits trailingSlash. On Cloudflare Pages, add explicit `_redirects` to enforce trailing-slash at the HTTP level (config alone can cause unexpected 308s). On Vercel, set `trailingSlash` in `vercel.json`.","how_to_check":"Parse all `<loc>` -> assert consistent trailing slash per config -> GET each and assert the final URL after redirects equals the sitemap URL exactly (no 3xx).","common_mistakes":"Mixing `build.format: 'directory'` with `trailingSlash: 'never'`; relying on Astro config alone on Cloudflare Pages without _redirects.","platform_notes":"Cloudflare Pages needs explicit `_redirects` entries; Vercel honors `trailingSlash` in vercel.json at the edge. Both can override/conflict with Astro's config.","sources":["https://realmorrisliu.com/thoughts/fixing-astro-seo-cloudflare-trailing-slash/","https://mirzapandzo.com/astro-vercel-trailingslash-and-redirects","https://docs.astro.build/en/reference/configuration-reference/"]},{"id":"crawlability-ai-crawler-policy-intentional","section":"crawlability","title":"robots.txt AI crawler policy is intentional (training vs search bots)","severity":"medium","stage":"pre-launch","automatable":false,"check_type":"manual","what":"robots.txt should make a deliberate, documented choice for AI training crawlers (GPTBot, ClaudeBot, Google-Extended, Bytespider) vs AI search/retrieval bots (OAI-SearchBot, Claude-SearchBot, PerplexityBot), which are distinct bots with different purposes.","why":"Blocking GPTBot stops training-data collection but does NOT remove the site from ChatGPT search answers (OAI-SearchBot does that). Conflating them causes either unwanted training use or invisible AI-answer presence; AI search drives meaningful referral traffic by 2026.","fix":"In `public/robots.txt`, add explicit rules per business intent, e.g. allow retrieval bots and block training bots, while keeping `User-agent: *` / `Allow: /` so Googlebot is never blocked. Include the `Sitemap:` directive. The `astro-ai-robots-txt` package can help generate these rules.","how_to_check":"Read /robots.txt and confirm at least one AI crawler (GPTBot/ClaudeBot/Google-Extended) has an explicit Allow/Disallow matching the documented decision, and that the wildcard rule does not block all bots.","common_mistakes":"An accidental `User-agent: * / Disallow: /` from dev that also blocks Google; blocking GPTBot expecting it to remove the site from ChatGPT search.","sources":["https://www.mersel.ai/blog/how-to-block-or-allow-ai-bots-on-your-website","https://delucis.github.io/astro-ai-robots-txt/"]},{"id":"crawlability-content-images-use-img","section":"crawlability","title":"Content images use <img>/astro:assets, not CSS background-image","severity":"medium","stage":"build","automatable":false,"check_type":"manual","what":"Information-carrying images (product photos, article heroes, team photos) must be rendered as HTML `<img>` (ideally via astro:assets), not CSS `background-image`, which Google does not index for Google Images. Purely decorative backgrounds (gradients, textures) may stay in CSS.","why":"Background images are not indexed for Google Images and cannot carry alt text. Using `<Image>` also enables alt text, srcset/format optimization, and CLS prevention.","fix":"Replace CSS background-image heroes with `<Image src={heroImg} alt='...' />` plus `object-fit: cover` for the same visual effect.","how_to_check":"Audit rendered CSS for `background-image: url()` declarations and cross-reference against the content-image inventory; content-carrying images in background-image are violations (human judgment required for content-vs-decorative).","common_mistakes":"Hero/feature sections built with `div style='background-image:url(...)'`, blocking Google Images indexing.","sources":["https://developers.google.com/search/docs/appearance/google-images"]},{"id":"crawlability-content-in-initial-html","section":"crawlability","title":"Indexable content and links are in the server-rendered HTML, not JS-only","severity":"medium","stage":"build","automatable":true,"check_type":"body_regex","what":"All indexable content (body text, headings, internal links, structured data) must be present in the initial HTML response, not injected only by client-side JavaScript after load.","why":"Googlebot indexes raw HTML immediately and re-renders JS at a variable delay (hours to weeks); content available only after JS execution may be indexed late or not at all. Astro SSG delivers full HTML by default — preserve that advantage.","fix":"Keep primary content in `.astro` templates. Ensure Astro Islands (client:load/visible/idle) render only supplementary UI, never the main indexable text or navigation links.","how_to_check":"GET the page and inspect the raw HTML body without executing JS -> assert critical text content and internal `<a href>` links are present in the string (e.g. disable JS in DevTools and confirm content/links remain).","common_mistakes":"Loading blog body text via a client:load island; fetching navigation links via JavaScript (orphaning downstream pages).","sources":["https://docs.astro.build/en/reference/configuration-reference/"]},{"id":"crawlability-image-sitemap-entries","section":"crawlability","title":"Image sitemap entries are present for indexable images","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"sitemap","what":"For sites where image search matters, the sitemap should include `<image:image>` entries (xmlns:image namespace) with `<image:loc>` for indexable images. @astrojs/sitemap declares the namespace by default but does NOT auto-populate image entries.","why":"Image sitemaps help Google discover images (especially JS-rendered ones) and are a positive signal for Google Images traffic. Only `image:image` + `image:loc` are supported — Google removed image:caption/title/geo_location/license in May 2022.","fix":"Populate image entries via the `serialize()` hook in astro.config.mjs, returning an object with an `images` array (each at minimum `{ url }` as an absolute HTTPS URL). For large sites, enumerate images per page with `getCollection()`. Ensure `site:` is set so URLs are absolute.","how_to_check":"GET /sitemap-0.xml -> assert root declares `xmlns:image='http://www.google.com/schemas/sitemap-image/1.1'` -> count `<image:image>` children (must be >0 for image-heavy sites) -> assert every `<image:loc>` is absolute HTTPS and returns 200.","common_mistakes":"Assuming the integration auto-adds image entries (it only declares the namespace); adding deprecated image child tags; relative image:loc URLs.","sources":["https://developers.google.com/search/docs/crawling-indexing/sitemaps/image-sitemaps","https://docs.astro.build/en/guides/integrations-guide/sitemap/"]},{"id":"crawlability-no-deprecated-rich-result-schema","section":"crawlability","title":"No deprecated Google rich-result schema types in production","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Remove JSON-LD using types whose Google rich-result support was retired: HowTo, Book Actions, ClaimReview, Course Info/EmployerAggregateRating, Estimated Salary, Learning Video, Special Announcement, Vehicle Listing (June 2025), and Sitelinks Search Box/SearchAction-on-WebSite (Nov 2024). FAQPage rich results retired May 2026 — treat as informational only, not an error.","why":"Deprecated rich-result markup generates Search Console warnings and false expectations and bloats markup. These types remain valid schema.org; the issue is the absence of SERP features, not a syntax error.","fix":"Audit `dist/` for deprecated type names and maintain an allowlist of currently supported types. `schema-dts` helps but may lag Google's deprecations — treat it as a dev aid, not a complete policy check.","how_to_check":"For every ld+json block (including nested @type), assert none match the hard-deprecated list (HowTo, BookAction, ClaimReview, CourseInstance, EmployerAggregateRating, LearningResource, SpecialAnnouncement, Vehicle); flag FAQPage and SearchAction-on-WebSite as informational warnings.","common_mistakes":"Copying an older Astro SEO template with HowTo/FAQPage; a generic schema library that still ships deprecated types.","sources":["https://www.engagecoders.com/google-retires-7-structured-data-features-to-streamline-search-results/","https://developers.google.com/search/blog/2024/10/sitelinks-search-box"]},{"id":"crawlability-pagination-crawlable-urls","section":"crawlability","title":"Paginated content uses crawlable URLs, anchor links, and self-canonicals","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"Each page in a paginated series must have a unique crawlable URL via path or query parameter (never a `#` fragment), standard `<a href>` links to adjacent pages, and a self-referencing canonical (page 2 canonicals to page 2, not page 1). Do not rely on rel=next/prev for Google.","why":"Google deprecated rel=next/prev (2019) and does not crawl URLs discovered only through them — only via visible anchor links. Fragment-based pagination (`#page=2`) is never sent to the server, so those pages are invisible to crawlers.","fix":"Use `getStaticPaths` with the `paginate()` helper (generates `/blog/2/`, `/blog/3/`). Render `<a href={page.url.prev}>`/`<a href={page.url.next}>` and a self-canonical: `new URL(Astro.url.pathname, Astro.site).href`. rel=next/prev may stay for Bing/accessibility but not as the only discovery path.","how_to_check":"GET page 2 of a series -> assert the URL uses a path/query segment and no `#` fragment -> assert `<link rel=canonical>` is self-referencing -> assert at least one visible `<a href>` pagination link exists.","common_mistakes":"Canonicalizing all paginated pages to page 1; rel-only links with no anchors; JS infinite scroll or `#page=2` with no unique URLs.","sources":["https://developers.google.com/search/docs/specialty/ecommerce/pagination-and-incremental-page-loading","https://www.journeyfurther.com/articles/how-does-google-handle-pagination-links-in-2025"]},{"id":"crawlability-rss-feed-autodiscoverable","section":"crawlability","title":"RSS feed exists and is autodiscoverable","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"html_head","what":"Blog/news sites should expose /rss.xml (or /feed.xml) and include `<link rel='alternate' type='application/rss+xml' href='/rss.xml'>` in the `<head>` of every page.","why":"RSS feeds are consumed by aggregators, Google News, and increasingly AI agents; the autodiscovery link lets browsers and crawlers find the feed without guessing the URL.","fix":"Install @astrojs/rss and create `src/pages/rss.xml.ts` with `export async function GET(ctx)` returning `rss({ title, description, site: ctx.site, items })`. In Astro v5 use `p.id` (not `p.slug`) and build links from it. Add the autodiscovery `<link>` to the shared layout head.","how_to_check":"GET /rss.xml -> assert 200 and Content-Type application/rss+xml (or xml), with `<channel><title>`, `<link>`, and >=1 `<item>` having `<link>` and `<pubDate>`. Fetch the homepage HTML -> assert the `link[rel=alternate][type='application/rss+xml']` is present in `<head>`.","common_mistakes":"Using `Astro.site` instead of `ctx.site`; using deprecated `export const get`; `p.slug` instead of `p.id` in v5; not adding the autodiscovery link to every page.","sources":["https://docs.astro.build/en/recipes/rss/","https://joost.blog/astro-seo-complete-guide/"]},{"id":"crawlability-sitemap-lastmod-accurate","section":"crawlability","title":"Sitemap lastmod reflects real content changes (omit changefreq/priority)","severity":"medium","stage":"build","automatable":false,"check_type":"manual","what":"`<lastmod>` should reflect when the page content actually changed, not the build timestamp. changefreq and priority are ignored by Google — omit them or leave at defaults.","why":"Google uses lastmod to prioritize re-crawling only when it is consistently accurate; a lastmod that always equals the build date is treated as unreliable and ignored.","fix":"Use the sitemap `serialize()` hook to derive lastmod from git commit date (`execSync('git log -1 --format=%cI -- <file>')`) or a frontmatter `updatedAt` field (see docs.astro.build/en/recipes/modified-time/). Never set `lastmod: new Date()` globally.","how_to_check":"GET /sitemap-0.xml -> parse `<lastmod>` for a page unchanged for weeks -> assert it does not equal today's date. Edit one post, rebuild, and confirm only its lastmod changed.","common_mistakes":"Global `lastmod: new Date()` destroying Google's trust in the signal; believing changefreq/priority affect crawl scheduling.","platform_notes":"Git history is available in both Cloudflare Pages and Vercel build environments for the serialize() hook.","sources":["https://docs.astro.build/en/recipes/modified-time/","https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap"]},{"id":"crawlability-sitemap-valid-xml","section":"crawlability","title":"Sitemap XML is UTF-8 encoded with properly escaped URLs","severity":"medium","stage":"build","automatable":true,"check_type":"sitemap","what":"Sitemap files must be UTF-8 and valid XML: `&`, `'`, `\"`, `<`, `>` entity-escaped (e.g. `&` -> `&amp;`) and non-ASCII characters percent-encoded in URLs.","why":"An invalid XML sitemap (encoding errors, un-escaped entities) is rejected by Google entirely — a single malformed `<loc>` can invalidate the whole file.","fix":"@astrojs/sitemap escapes URLs from getStaticPaths automatically. When injecting URLs via `customPages` or `serialize()`, escape `&` as `&amp;` and percent-encode non-ASCII/space characters before injection.","how_to_check":"GET /sitemap-0.xml -> run through an XML parser (xmllint/DOMParser) -> assert 0 parse errors and UTF-8 charset (or absent, which defaults to UTF-8).","common_mistakes":"Injecting raw DB URLs with `&` into customPages without escaping; URLs with unencoded spaces.","sources":["https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap"]},{"id":"crawlability-xrobots-for-non-html","section":"crawlability","title":"Non-HTML files use X-Robots-Tag for indexing control","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"http_header","what":"For non-HTML resources (PDFs, Word docs, images) that should not be indexed, use the `X-Robots-Tag: noindex` HTTP response header — `<meta>` robots tags only work in HTML.","why":"Meta robots tags are ignored in non-HTML files; X-Robots-Tag is the only mechanism that controls indexing for those file types (and PDFs are crawled).","fix":"Cloudflare Pages: add `/docs/* \\n  X-Robots-Tag: noindex` to `_headers`. Vercel: add a rule under `headers` in `vercel.json`. Astro SSR: set the header in the API route/middleware response.","how_to_check":"curl -I each non-HTML URL meant to be noindexed -> assert the `X-Robots-Tag` response header contains `noindex`.","common_mistakes":"Putting a meta noindex on the linking HTML instead of the file header; assuming PDFs aren't crawled.","platform_notes":"Both Cloudflare `_headers` and Vercel `vercel.json` headers support glob patterns for these files.","sources":["https://developers.google.com/search/docs/crawling-indexing/robots-meta-tag","https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers/X-Robots-Tag"]},{"id":"crawlability-large-site-crawl-budget","section":"crawlability","title":"Large sites (10k+ pages) block crawl-budget-wasting URLs","severity":"low","stage":"post-launch","automatable":false,"check_type":"manual","what":"For sites with 10,000+ frequently-changing indexable pages, audit and eliminate crawl-budget waste: infinite calendar/date paths, session-ID and sort/order/ref parameters, printer-friendly variants, and low-value tag/category combinations. Block via robots.txt or consolidate via canonicals. Typical Astro blogs/portfolios do not need this.","why":"Google's crawl-budget guidance is explicitly scoped to large/frequently-updated sites; for smaller sites crawl budget is not a practical concern (per Google's Gary Illyes).","fix":"Use @astrojs/sitemap `filter()` to exclude low-value pages and robots.txt Disallow patterns for parameter-based duplicates.","how_to_check":"Crawl the site and count URLs bearing ?sort=, ?order=, ?ref=, ?session= -> assert each is robots-blocked or canonicalized to the parameter-free URL. In GSC Crawl Stats, a crawled:indexed ratio > 3:1 indicates waste.","common_mistakes":"Applying crawl-budget work to small sites; ignoring GSC Crawl Stats; not auditing parameters from tag clouds/sorting controls.","sources":["https://developers.google.com/crawling/docs/crawl-budget"]},{"id":"crawlability-llms-txt-optional","section":"crawlability","title":"llms.txt (and optional llms-full.txt) for AI/LLM guidance","severity":"low","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"Optionally provide a curated Markdown `/llms.txt` mapping the site's most important pages, and optionally `/llms-full.txt` with full content. Low effort, negligible downside; most useful for developer-tool/documentation sites.","why":"Google confirmed (July 2025, Gary Illyes) it does not use llms.txt, and no major LLM provider has committed to production use as of 2026. Some AI coding assistants and developer tools do retrieve it; it has no confirmed effect on Google rankings or AI Overview citations.","fix":"Create `public/llms.txt` (or `src/pages/llms.txt.ts` with `export const prerender = true`) starting with an H1, a one-line blockquote description, and a curated list of Markdown links to real pages. For llms-full.txt, render content to plain Markdown with `Content-Type: text/plain; charset=utf-8`.","how_to_check":"GET /llms.txt -> assert 200, Content-Type text/plain, body starts with `#` and contains at least one Markdown link `[text](url)` to a real (200) page.","common_mistakes":"Overstating SEO value; dumping all pages instead of a curated subset; serving as text/html; linking to 404/redirect URLs; making llms-full.txt excessively large (>~5 MB).","platform_notes":"Static file in public/ works identically on Cloudflare Pages and Vercel.","sources":["https://llmstxt.org/","https://www.itechmanthra.com/blog/google-says-normal-seo-works-for-ranking-in-ai-overviews-and-llms-txt-wont-be-used/"]},{"id":"crawlability-prefetch-strategy-appropriate","section":"crawlability","title":"Prefetch strategy is appropriate for site size and SSR cost","severity":"low","stage":"pre-launch","automatable":false,"check_type":"manual","what":"Avoid prefetch `strategy: 'load'` with `prefetchAll: true` on large or SSR-heavy sites — it fetches every link on page load, generating excessive requests. Prefer the more conservative `'viewport'` strategy.","why":"Prefetch is transparent to Googlebot (it doesn't run prefetch scripts), but 'load' on a link-heavy or SSR site generates thousands of requests per page load, slowing real users and raising server costs.","fix":"In astro.config: `prefetch: { prefetchAll: true, defaultStrategy: 'viewport' }`. ClientRouter sets prefetchAll: true by default — review it for large/SSR sites.","how_to_check":"Load a content-heavy page (50+ links) with DevTools Network open and count prefetch requests on load; with 'viewport' only visible-link requests should appear (far fewer than 'load').","common_mistakes":"prefetchAll with strategy:'load' on a site with hundreds of internal links.","platform_notes":"Vercel Serverless Functions cost per invocation — be cautious with 'load' if prefetched routes are server-rendered. Cloudflare Pages has no egress fees for static assets.","sources":["https://docs.astro.build/en/guides/prefetch/"]},{"id":"metadata-charset-utf8","section":"metadata","title":"<meta charset=\"UTF-8\"> first in <head>, within first 1024 bytes","severity":"critical","stage":"build","automatable":true,"check_type":"html_head","what":"<meta charset=\"UTF-8\"> is the first child of <head> and appears within the first 1024 bytes of the document.","why":"HTML5 requires UTF-8 declared early; otherwise browsers guess the encoding and render mojibake on accented/CJK/emoji characters, and Google can misparse titles and descriptions.","fix":"Keep Astro's default `<meta charset=\"UTF-8\" />` as the very first child of <head> in BaseHead.astro. Do not let any integration inject elements (scripts, etc.) before it, and do not replace it with the legacy http-equiv Content-Type form.","how_to_check":"`curl -s https://example.com | head -c 1024 | grep -i 'charset'` must match, and the charset meta must be the first meta tag in <head>.","common_mistakes":"A third-party script injected via injectElement before charset; copying a legacy `<meta http-equiv=\"Content-Type\">` template.","sources":["https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Elements/meta","https://web.dev/learn/html/metadata"]},{"id":"metadata-html-lang","section":"metadata","title":"html[lang] set to a valid BCP-47 language code","severity":"critical","stage":"build","automatable":true,"check_type":"html_element","what":"The root <html> element carries a non-empty lang attribute with a valid BCP-47 tag matching the page's actual language (e.g. lang=\"en\", lang=\"en-US\", lang=\"is\").","why":"Google and screen readers use lang for language serving, translation suppression, and hreflang matching. Missing lang fails WCAG 3.1.1 (Level A) and breaks Google language targeting.","fix":"In the root layout: `<html lang={lang ?? 'en'}>`, exposing `lang` as a prop. For multilingual sites set it from Astro's built-in i18n routing via `Astro.currentLocale`.","how_to_check":"Assert document.documentElement.getAttribute('lang') is non-empty and matches /^[a-z]{2,3}(-[A-Z]{2,3})?$/. Lighthouse accessibility audit also flags a missing/invalid lang.","common_mistakes":"lang left empty; lang=\"en\" on a non-English site; lang missing so the document inherits no language.","sources":["https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Elements/meta","https://www.w3.org/WAI/WCAG21/Understanding/language-of-page.html"]},{"id":"metadata-og-image","section":"metadata","title":"Valid og:image (and twitter:image) at 1200x630 with absolute HTTPS URL","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"html_head","what":"Every page has <meta property=\"og:image\"> and <meta name=\"twitter:image\"> pointing to an absolute HTTPS URL that returns HTTP 200 with image/* content type. The image is 1200x630 px (1.91:1), JPEG or PNG (WebP acceptable as of 2025), under ~300 KB, with og:image:width=1200, og:image:height=630, and og:image:alt declared.","why":"og:image controls the share preview on Slack, X, LinkedIn, Facebook, iMessage, and WhatsApp; missing or broken images yield blank previews and lost clicks. Relative URLs are not resolved by Facebook/X. Declaring width/height saves the crawler an extra fetch; 1200x630 is the cross-platform standard.","fix":"In BaseHead.astro build an absolute URL: `<meta property=\"og:image\" content={new URL(ogImage, Astro.site).href} />` (set `site` in astro.config.mjs). Add og:image:width/height/alt and mirror to twitter:image. Store static images at 1200x630 in public/og/, or generate them (see dynamic OG rule).","how_to_check":"Extract og:image from HTML; assert it is absolute https://, then `curl -sI <url>` returns 200 with Content-Type image/*; verify actual dimensions are 1200x630 (image-size lib) and width/height/alt meta are present. Validate visually in opengraph.xyz or the Facebook Sharing Debugger.","common_mistakes":"Relative path in content; image behind auth (401/403); the homepage image reused on every page; 1200x675 (YouTube ratio); missing og:image:width/height.","platform_notes":"Vercel: generate on demand with @vercel/og in an Astro endpoint. Cloudflare Pages: use workers-og / Satori in a Pages Function.","sources":["https://opengraphdebug.com/posts/og-image-requirements","https://www.krumzi.com/blog/open-graph-image-sizes-for-social-media-the-complete-2026-guide","https://myogimage.com/blog/og-image-tips-2025-social-sharing-guide"]},{"id":"metadata-title-present-and-unique","section":"metadata","title":"Unique, non-empty <title> on every page","severity":"critical","stage":"build","automatable":true,"check_type":"html_head","what":"Every page has exactly one non-empty <title> element in <head>, and no two pages share the same title value (home, blog index, pagination, tag archives, and 404 all included).","why":"The title is the strongest on-page relevance signal; a missing title forces Google to fabricate one. Duplicate titles cause keyword cannibalization and crawl-quality flags in GSC, and Google rewrites duplicated titles.","fix":"In src/layouts/BaseHead.astro accept a required `title` prop (no default fallback) and render `<title>{title}</title>`; type it as `string` so the build errors when omitted. For content collections, mark `title` required in the Zod schema in src/content.config.ts. Add an `astro:build:done` integration that collects all titles from dist/**/*.html into a Set and fails on duplicates.","how_to_check":"Parse build output: `find dist -name '*.html' | xargs grep -L '<title>'` must be empty, and `grep -rh '<title>' dist --include='*.html' | sort | uniq -d` must return nothing. In a request, assert document.querySelector('title') exists with trimmed length > 0.","common_mistakes":"Layout renders an empty <title></title> fallback; blog posts inherit a generic site title; /blog/page/2 reuses the /blog title; 404 reuses the home title.","platform_notes":"Build-time concern; no Cloudflare Pages / Vercel difference.","sources":["https://developers.google.com/search/docs/appearance/title-link","https://www.semrush.com/blog/duplicate-title-tags/"]},{"id":"metadata-viewport","section":"metadata","title":"Mobile viewport meta tag present and non-restrictive","severity":"critical","stage":"build","automatable":true,"check_type":"html_head","what":"Every page has <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\"> and does NOT set user-scalable=no or maximum-scale=1.","why":"Without a viewport tag mobile browsers render at 980px desktop width and scale down, harming mobile-first indexing and Core Web Vitals; Lighthouse flags it as critical. Disabling zoom violates WCAG 1.4.4.","fix":"In BaseHead.astro: `<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />`. Never add user-scalable=no or maximum-scale=1.","how_to_check":"Assert document.querySelector('meta[name=\"viewport\"]').content includes width=device-width and initial-scale=1 and excludes user-scalable=no / maximum-scale=1. Lighthouse 'Viewport' audit automates the presence check.","common_mistakes":"Adding user-scalable=no or maximum-scale=1; placing the viewport tag after scripts.","sources":["https://developers.google.com/search/docs/crawling-indexing/special-tags","https://web.dev/learn/html/metadata"]},{"id":"metadata-favicon-set-complete","section":"metadata","title":"Complete favicon set: favicon.ico, 32px PNG, SVG, and apple-touch-icon","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"The site serves a complete icon set: /favicon.ico (32x32, no redirect) as universal fallback; a 32x32 PNG (`<link rel=icon type=image/png sizes=32x32>`); an SVG favicon (`<link rel=icon type=image/svg+xml>`, ideally dark-mode aware); and a 180x180 apple-touch-icon (`<link rel=apple-touch-icon>`). All referenced links resolve to HTTP 200 with correct content types.","why":"Browsers, OS bookmark folders, RSS readers, and Slack fetch /favicon.ico unconditionally; iOS uses apple-touch-icon for home-screen icons (falling back to an ugly screenshot otherwise); modern browsers prefer SVG/PNG. An incomplete set means blank tab/home-screen icons and 404s in logs - a trust signal.","fix":"Put favicon.ico, favicon.svg, favicon-32x32.png, apple-touch-icon.png in public/ (copied verbatim to dist root). In BaseHead.astro add `<link rel=\"icon\" type=\"image/svg+xml\" href=\"/favicon.svg\" />`, `<link rel=\"icon\" type=\"image/png\" sizes=\"32x32\" href=\"/favicon-32x32.png\" />`, `<link rel=\"icon\" href=\"/favicon.ico\" sizes=\"32x32\" />`, `<link rel=\"apple-touch-icon\" sizes=\"180x180\" href=\"/apple-touch-icon.png\" />`. Use the astro-favicons integration to generate all sizes from one source image.","how_to_check":"GET /favicon.ico -> 200 (image/x-icon); GET /favicon.svg -> 200 (image/svg+xml); GET the 32x32 PNG -> 200 (image/png); GET /apple-touch-icon.png -> 200 (image/png), dimensions 180x180. Parse <head> and assert all four link tags present. Audit with realfavicongenerator.net/favicon_checker.","common_mistakes":"favicon.ico in a subdirectory; apple-touch-icon missing or 16x16 upscaled (blurry); rel=apple-touch-icon-precomposed (deprecated since iOS 7); SVG link present but file 404s.","platform_notes":"Both Cloudflare Pages and Vercel serve public/ at root automatically. Cloudflare Pages applies long-lived cache headers - rename icon files (or set must-revalidate) when changing them.","sources":["https://evilmartians.com/chronicles/how-to-favicon-in-2021-six-files-that-fit-most-needs","https://rodneylab.com/astro-js-favicon/"]},{"id":"metadata-meta-description","section":"metadata","title":"Unique meta description on every page, 130-160 chars","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"Every page has a non-empty, page-specific <meta name=\"description\">, no two pages share the same value, and length is roughly 130-160 chars (core message within the first ~120 chars for mobile/rewritten snippets; hard cap 160).","why":"Without a description Google pulls an arbitrary body snippet. A unique, well-sized description is the main lever for SERP click-through (though not a ranking factor); duplicate descriptions are flagged in GSC and over-length ones are truncated.","fix":"Accept a required `description` prop in BaseHead.astro and render `<meta name=\"description\" content={description} />`. In content collections enforce `description: z.string().min(70).max(165)`. Add an astro:build:done check for empties, duplicates, and length outliers.","how_to_check":"`grep -rL 'name=\"description\"' dist --include='*.html'` empty (none missing); `grep -roh 'name=\"description\" content=\"[^\"]*\"' dist --include='*.html' | sort | uniq -d` empty (no duplicates); measure content length and flag <70 or >165.","common_mistakes":"content={description ?? ''} so the tag exists but is empty; tag/pagination pages share one templated description; auto-generated first-paragraph descriptions running 200+ chars.","sources":["https://developers.google.com/search/docs/appearance/snippet","https://sitebulb.com/hints/duplicate-content/urls-with-duplicate-title-and-meta-descriptions/"]},{"id":"metadata-og-core-properties","section":"metadata","title":"Core Open Graph properties set (title, description, url, type, site_name)","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"Every page sets og:title, og:description, og:url, og:type, and og:site_name using the `property` attribute. og:url is absolute https:// and equals the canonical href; og:type is 'website' (or 'article' for posts); og:site_name is the brand name (not the URL).","why":"These are the required/expected OGP fields that build the link unfurl card on LinkedIn, Slack, Discord, Facebook, and iMessage. Mismatched og:url vs canonical splits social share counts; using `name` instead of `property` is a frequent breakage.","fix":"In BaseHead.astro: `<meta property=\"og:title\" content={title} />`, `<meta property=\"og:description\" content={description} />`, `<meta property=\"og:url\" content={canonicalURL} />` (reuse the canonical variable), `<meta property=\"og:type\" content={ogType ?? 'website'} />` ('article' in post layouts), and `<meta property=\"og:site_name\" content={SITE_NAME} />` from src/config.ts. Always use `property=`, not `name=`.","how_to_check":"Assert each og:* tag exists with non-empty content; og:url is absolute https:// and equals link[rel=canonical] href; og:type is lowercase 'website'/'article'; blog posts use 'article'. View in opengraph.xyz / LinkedIn Post Inspector.","common_mistakes":"Using name=\"og:title\"; og:url with UTM params or http://; trailing-slash mismatch with canonical; capital 'Article'; og:site_name set to the domain.","sources":["https://ogp.me/","https://env.dev/guides/opengraph"]},{"id":"metadata-twitter-card","section":"metadata","title":"twitter:card set to summary_large_image (with Twitter card fields)","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"Every page has <meta name=\"twitter:card\" content=\"summary_large_image\">. twitter:title, twitter:description, twitter:image, twitter:image:alt and (when the brand has an account) twitter:site=@handle are recommended; all use the `name` attribute. X falls back to og:* for content but NOT for card type, so twitter:card must be set explicitly.","why":"Without twitter:card, X renders a minimal/no-image card; summary_large_image produces the large banner that maximizes click-through. Card type has no OG equivalent, so it cannot be inherited. twitter:image:alt provides accessibility for the card.","fix":"In BaseHead.astro: `<meta name=\"twitter:card\" content=\"summary_large_image\" />` plus `<meta name=\"twitter:title\" content={title} />`, `<meta name=\"twitter:description\" content={description} />`, `<meta name=\"twitter:image\" content={socialImageURL} />`, `<meta name=\"twitter:image:alt\" content={ogImageAlt ?? title} />`. Add twitter:site only if a handle is configured; never render it empty. Use `name=`, not `property=`.","how_to_check":"Assert meta[name=\"twitter:card\"].content === 'summary_large_image'. Assert twitter:image (if present) is absolute https://; twitter:image:alt non-empty; twitter:site (if present) starts with '@'. Validate with a Twitter/X card validator.","common_mistakes":"property=\"twitter:card\"; using 'summary' instead of summary_large_image; relative twitter:image; rendering empty twitter:site=\"\" when no account exists.","sources":["https://developer.twitter.com/en/docs/twitter-for-websites/cards/overview/summary-card-with-large-image","https://www.opengraph.to/articles/missing-twitter-card"]},{"id":"metadata-dynamic-og-images","section":"metadata","title":"Per-page dynamic OG images, not one shared fallback","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"Content pages (blog posts, products) reference a unique, programmatically generated 1200x630 OG image embedding the page title/brand, rather than a single static /og.png reused everywhere.","why":"Cards showing the actual page title materially lift social click-through. One shared image across all pages triggers duplicate-image warnings in social validators and signals low effort.","fix":"Create a prerendered Astro endpoint, e.g. src/pages/og/[slug].png.ts with `export const prerender = true`, using @vercel/og (Satori) or astro-og-canvas to render to PNG at build time; reference it per page as `<meta property=\"og:image\" content={new URL(`/og/${slug}.png`, Astro.site).href} />` plus og:image:width/height.","how_to_check":"For sample pages, extract og:image from HTML, GET it, and assert status 200, Content-Type image/png|jpeg, size > ~5 KB, and that the path is page-specific (not one shared /og.png). Confirm distinct cards in the X Card Validator and Facebook Sharing Debugger.","common_mistakes":"One static /og.png for all pages; generating at runtime on SSR routes without caching; dimensions not exactly 1200x630; forgetting og:image:width/height.","platform_notes":"Cloudflare Pages SSR runs @vercel/og in the Worker (128 MB limit; prefer prerendered output). Vercel supports @vercel/og natively in Edge Functions.","sources":["https://knaap.dev/posts/dynamic-og-images-with-any-static-site-generator/","https://astro-paper.pages.dev/posts/dynamic-og-image-generation-in-astropaper-blog-posts/"]},{"id":"metadata-single-h1-heading-hierarchy","section":"metadata","title":"One H1 per page with a logical, unskipped heading hierarchy","severity":"medium","stage":"build","automatable":true,"check_type":"html_element","what":"Each page has exactly one <h1> and headings descend without skipping levels (H1 -> H2 -> H3; H1 -> H3 is invalid). Google does not penalize multiple H1s, but a single focused H1 and ordered headings are the accessibility best practice (WCAG 1.3.1 / 2.4.6).","why":"71.6% of screen-reader users navigate by headings (WebAIM 2024); a single H1 and ordered nesting give clear document structure and help engines infer topic/subtopic relationships. This is best practice, not a hard ranking signal.","fix":"Keep the H1 in page content (not BaseHead.astro); for Markdown/MDX ensure exactly one top-level `# Heading` and avoid a duplicate H1 in the layout. Enforce heading order in content via a remark/rehype plugin, and add an astro:build:done check (or axe 'heading-order' rule) over dist HTML.","how_to_check":"`find dist -name '*.html' | xargs grep -c '<h1' | grep -v ':1$'` lists pages with zero or multiple H1s. Run axe 'heading-order' to flag skipped levels per page.","common_mistakes":"Header logo wrapped in H1 plus a content H1; blog template emits H1 for the title and the markdown also starts with '# Title'; jumping H2 -> H4 for visual styling.","sources":["https://yoast.com/how-to-use-headings-on-your-site/","https://www.w3.org/WAI/tutorials/page-structure/headings/"]},{"id":"metadata-title-length-brand-pattern","section":"metadata","title":"Title length ~50-60 chars with a consistent brand suffix","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"body_regex","what":"Inner-page titles are ~50-60 characters (front-loaded topic) and append the brand as a suffix, e.g. 'Page Title | Brand'; the home page uses 'Brand - Tagline'. Total stays under ~65 chars / ~600 px so the brand isn't truncated.","why":"Titles over ~600 px are truncated in SERPs, cutting the brand or key qualifier. Google rewrote 76% of titles in Q1 2025; brand-prefix removal was the most common action (63% of rewrites), so a front-loaded topic with a brand suffix and a controlled length survives rewrites best.","fix":"In BaseHead.astro: `<title>{title} | {SITE_NAME}</title>` (SITE_NAME from src/config.ts), with a flag for the home-page format. Add a build-time `astro:build:done` warning when title length < 30 or > 65, or when a non-home title doesn't end with the configured ` | Brand` / ` - Brand` suffix.","how_to_check":"Parse each dist title, strip entities, and flag length < 30 or > 65; assert non-home titles match /[|\\-] BrandName$/. Confirm no truncation in totheweb.com's title/description pixel tool.","common_mistakes":"Brand suffix pushes long organic titles over 65 chars; some pages add the brand and others don't; inconsistent brand spelling; not stripping HTML entities before measuring.","sources":["https://searchengineland.com/google-changed-76-of-title-tags-in-q1-2025-heres-what-that-means-454847","https://zyppy.com/title-tags/meta-title-tag-length/"]},{"id":"metadata-web-app-manifest","section":"metadata","title":"Complete web app manifest with required PWA fields and icons","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"A manifest.webmanifest is linked in <head> and contains name, short_name, start_url, display (standalone/minimal-ui), background_color, theme_color (matching the theme-color meta), and an icons array with at least 192x192 and 512x512 PNGs plus a maskable variant.","why":"A valid manifest is the prerequisite for the browser install prompt and is gated by Lighthouse's installability audit. short_name labels the installed app, theme_color tints chrome, and maskable icons prevent clipping on Android adaptive shapes.","fix":"Place public/manifest.webmanifest with the required fields and a maskable icon (`purpose: 'maskable'`). In BaseHead.astro: `<link rel=\"manifest\" href=\"/manifest.webmanifest\" />`. Keep manifest theme_color in sync with `<meta name=\"theme-color\">`.","how_to_check":"GET /manifest.webmanifest -> 200 with Content-Type application/manifest+json; parse JSON and assert name non-empty, display in {standalone,minimal-ui,fullscreen}, start_url present, and icons include 192x192 and 512x512; GET each icon -> 200. Run Lighthouse and assert installable.","common_mistakes":"display: browser (no install prompt); manifest linked but 404; missing maskable icon; icon paths that 404; theme_color mismatch with the meta tag.","platform_notes":"Both Cloudflare Pages and Vercel serve public/ at root with the correct Content-Type; no extra config needed.","sources":["https://web.dev/learn/pwa/web-app-manifest","https://developer.chrome.com/docs/lighthouse/pwa/installable-manifest"]},{"id":"metadata-no-keywords-meta","section":"metadata","title":"No legacy <meta name=\"keywords\"> tag","severity":"low","stage":"build","automatable":true,"check_type":"body_regex","what":"No <meta name=\"keywords\"> appears in any page's HTML.","why":"Google has ignored the keywords meta since 2009 and Bing/Yandex ignore it too; it adds noise and needlessly exposes keyword strategy to competitors.","fix":"Remove any `<meta name=\"keywords\">` from Layout/Head components and audit third-party SEO integrations (some inject it by default).","how_to_check":"`grep -r 'name=\"keywords\"' dist/` returns empty.","common_mistakes":"Legacy SEO component libraries that still inject keywords meta by default.","sources":["https://developers.google.com/search/blog/2009/09/google-does-not-use-keywords-meta-tag"]},{"id":"metadata-service-worker-offline","section":"metadata","title":"Service worker registered with an offline fallback (PWA baseline)","severity":"low","stage":"pre-launch","automatable":true,"check_type":"lighthouse","what":"A service worker is registered that caches static assets (cache-first) and returns a branded offline fallback page when the network is unavailable, with the manifest start_url served by the SW.","why":"A service worker is required for the PWA install prompt and is checked by Lighthouse; an offline fallback reduces bounce on flaky networks. Not a direct ranking factor, but installable PWAs index reliably and see higher engagement.","fix":"Add vite-plugin-pwa in astro.config.mjs (VitePWA with registerType:'autoUpdate', a Workbox globPatterns set, and a manifest) and create a src/pages/offline.astro fallback preloaded in the SW install event. For static sites use Workbox generateSW mode.","how_to_check":"Run Lighthouse and assert the installability/SW checks pass; in DevTools > Application > Service Workers confirm status 'activated and running', then toggle Offline and reload to confirm the branded fallback renders.","common_mistakes":"Registering a SW with no offline fallback; caching HTML cache-first indefinitely (stale content); not clearing old caches on update.","platform_notes":"The SW is a plain JS file served identically by Cloudflare Pages and Vercel; for SSR routes the SW can cache responses but not intercept dynamic rendering.","sources":["https://vite-pwa-org.netlify.app/frameworks/astro","https://web.dev/articles/install-criteria"]},{"id":"metadata-theme-color","section":"metadata","title":"theme-color meta tag(s) for browser chrome tinting","severity":"low","stage":"pre-launch","automatable":true,"check_type":"html_head","what":"A <meta name=\"theme-color\" content=\"#RRGGBB\"> is present; sites with dark mode declare two, each with a prefers-color-scheme media attribute. Values are static hex/rgb, not CSS variables.","why":"Mobile Chrome and Samsung Internet tint the address bar and task switcher to the brand color, giving a polished, PWA-like feel even when the site is not installed.","fix":"In BaseHead.astro: `<meta name=\"theme-color\" media=\"(prefers-color-scheme: light)\" content=\"#ffffff\" />` and `<meta name=\"theme-color\" media=\"(prefers-color-scheme: dark)\" content=\"#0a0a0a\" />`, matching each mode's background and the manifest theme_color.","how_to_check":"Assert meta[name=\"theme-color\"] exists with a valid hex/rgb value; if two are declared, assert both carry a media attribute. Verify the address bar tint on Android Chrome.","common_mistakes":"Using a CSS variable like var(--color) (must be a literal); omitting the tag entirely; theme-color not matching the manifest.","sources":["https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Elements/meta/name/theme-color","https://css-tricks.com/meta-theme-color-and-trickery/"]},{"id":"structured-data-product-content-match","section":"structured-data","title":"Product/LocalBusiness schema values match visible page content","severity":"critical","stage":"post-launch","automatable":true,"check_type":"json_ld","what":"Price, priceCurrency, availability, and NAP (name/address/phone) emitted in Product, Offer, or LocalBusiness JSON-LD must match the values visibly rendered on the page (and, for local businesses, the Google Business Profile listing). Markup must never assert data the user cannot see on the page.","why":"Google's structured-data spam policies prohibit markup that misrepresents visible content. A mismatch is a documented manual-action trigger that suppresses ALL rich results for the site. The Rich Results Test only validates syntax and does NOT catch this.","fix":"Derive schema values from the same data source as the rendered HTML. Use one frontmatter/collection field (e.g. post.data.price) for both the visible `<p>{price}</p>` and offers.price, and store NAP once in src/consts.ts for both the visible `<address>` and the LocalBusiness block. Never hardcode values in schema separately from the UI. After a CMS price change, rebuild static pages (webhook-triggered deploy) or use SSR for frequently changing prices.","how_to_check":"For each product/local page: extract offers.price (and address/telephone) from ld+json and the visible price/NAP via a CSS selector. Normalize (strip currency symbols and whitespace) and assert equality within 0.01 tolerance for price and exact-after-normalization for NAP.","common_mistakes":"Showing a sale price on the page but the regular price in schema; CMS price updated without a static rebuild; JS-rendered price differing from server-rendered schema; schema phone '555-555-5555' vs visible '(555) 555-5555'.","platform_notes":"On Cloudflare Pages and Vercel static builds, a CMS data change requires a rebuild to resync schema with HTML; use a deploy webhook or SSR (Workers/Vercel Functions) for volatile data.","sources":["https://developers.google.com/search/docs/appearance/structured-data/sd-policies","https://developers.google.com/search/docs/appearance/structured-data/local-business"]},{"id":"structured-data-valid-json-ld-clean","section":"structured-data","title":"All JSON-LD is valid and passes the Schema.org validator with zero errors","severity":"critical","stage":"build","automatable":true,"check_type":"json_ld","what":"Every page's `<script type=\"application/ld+json\">` block must contain syntactically valid JSON and pass the Schema.org Markup Validator (validator.schema.org) with zero errors (warnings reviewed). The schema.org validator catches type mismatches and invalid property values the Google Rich Results Test ignores.","why":"Invalid JSON-LD (trailing commas, unescaped quotes from improper serialization) silently disqualifies a page from all rich results. The schema.org validator checks the full vocabulary, not just Google-supported types.","fix":"Always serialize objects with `<script type=\"application/ld+json\" set:html={JSON.stringify(schema)} />` (Astro's set:html avoids HTML-entity escaping that double-quote interpolation `{...}` introduces and produces invalid JSON). Optionally use `schema-dts` TypeScript types (via astro-seo-schema) for build-time type safety. In CI, extract ld+json from dist/ with cheerio and validate each block; cache results per content hash because validator.schema.org is rate-limited (~50 req/hour) — a third-party validator API or schema-dts is preferable for per-build runs.","how_to_check":"Parse every ld+json block as JSON (assert no parse error). POST each to validator.schema.org/validate (or a third-party equivalent) and assert the errors array is empty; alternatively rely on schema-dts build-time type checking.","common_mistakes":"Using `{JSON.stringify(...)}` interpolation instead of set:html (escapes quotes -> invalid JSON); only running the Rich Results Test (misses schema.org violations); calling the official validator for every page on every build and getting 429s.","sources":["https://schema.org/docs/validator.html","https://stephen-lunt.dev/blog/astro-structured-data/"]},{"id":"structured-data-article-author-person","section":"structured-data","title":"Article author is a Person with name (no titles) and a working bio URL/sameAs","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"The Article author must be `@type: Person` (not Organization) with author.name containing only the person's name (no job titles, honorifics, or publisher info) and a url to an on-site author bio page plus sameAs to professional profiles. The bio page must actually exist and not 404 (an orphaned author URL is worse than no schema).","why":"Author schema tied to a real, linkable bio page is a core E-E-A-T signal in 2026 and feeds author-entity disambiguation against the Knowledge Graph, especially for YMYL content and AI Overview citation. Google documents that titles/honorifics in author.name are a common quality error.","fix":"Define authors as a content collection in src/content/authors/. In the article schema (Astro v5 uses `id`, not `slug`, for collection entries): `author:{ '@type':'Person', name: author.name, url: new URL(`/authors/${author.id}`, Astro.site).toString(), sameAs: author.sameAs }`. Ensure the bio page at that url is built and linked from the article.","how_to_check":"Parse Article ld+json; assert author['@type'] === 'Person' and author.name is non-empty and does not match title patterns (Dr., CEO, Editor, '|', 'posted by'). If author.url present, GET it and assert 200. Warn (not error) if neither url nor sameAs is present.","common_mistakes":"author set to @type Organization for human-written content; author.name = 'Jane Smith, CEO of Acme'; author.url pointing at the homepage; orphaned bio pages; using `slug` instead of `id` in Astro v5 collections.","sources":["https://developers.google.com/search/docs/appearance/structured-data/article","https://docs.astro.build/en/guides/upgrade-to/v5/"]},{"id":"structured-data-article-blog-posts","section":"structured-data","title":"Article/BlogPosting JSON-LD on every article with headline, image, dates, author","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Every blog/editorial page must include an Article or BlogPosting block. Google lists no strictly required properties, but for rich-result eligibility emit headline, image (array of ImageObject, each >=50,000 px area and ideally >=1200px wide), datePublished (ISO 8601, timezone preferred), dateModified, and author. Providing 16:9, 4:3, and 1:1 image variants maximizes eligibility across surfaces.","why":"Article structured data enables Top Stories eligibility, article rich snippets, and Google News indexing. Google enforces headline, image, and author most strictly in practice; a missing image is the most common reason for ineligibility.","fix":"In src/layouts/BlogPost.astro using typed `CollectionEntry<'blog'>` props: `{ '@context':'https://schema.org','@type':'BlogPosting', headline: post.data.title, image:[{ '@type':'ImageObject', url: ogImageUrl, width:1200, height:630 }], datePublished: post.data.pubDate.toISOString(), dateModified:(post.data.updatedDate ?? post.data.pubDate).toISOString(), author:{...} }`. Generate aspect-ratio variants with astro:assets getImage(). Always call .toISOString() on Date objects (type frontmatter as `z.date()` in the collection schema).","how_to_check":"For each article URL: parse ld+json, find @type Article/BlogPosting; assert headline non-empty; image is a non-empty array whose urls return 200 image content-type; datePublished matches a strict ISO 8601 regex; if dateModified present it is ISO and >= datePublished; author.name non-empty. Warn if no image >=1200px wide.","common_mistakes":"Omitting image; passing a Date object without .toISOString() (serializes to [object Object] or a locale string); merging multiple authors into one author.name string; single landscape image assumed to cover all surfaces.","platform_notes":"With static output on Cloudflare Pages/Vercel, JSON-LD is pre-rendered at build; rerun `astro build` after content changes so new posts get schema.","sources":["https://developers.google.com/search/docs/appearance/structured-data/article"]},{"id":"structured-data-breadcrumblist-inner-pages","section":"structured-data","title":"BreadcrumbList on inner pages with sequential, canonical item URLs","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Every page at depth >= 2 (blog posts, product, category, docs) must include a BreadcrumbList. Each ListItem needs position (integer starting at 1, sequential, no gaps), name, and item (absolute URL); the final ListItem may omit item. Each item URL must exactly match that page's canonical URL (https, same trailing-slash convention, no params).","why":"BreadcrumbList unlocks breadcrumb rich results on desktop SERPs (Google removed the mobile visual in January 2025) and helps Google map site structure and entities for AI Overviews. URL/canonical mismatches confuse the URL graph and can void breadcrumb eligibility.","fix":"Generate breadcrumbs in the layout from `Astro.site` + `Astro.url.pathname` so URLs always match the canonical tag and respect trailingSlash. e.g. `[{pos:1,name:'Home',url:site},{pos:2,name:'Blog',url:`${site}blog/`},{pos:3,name:post.data.title}]` mapped to ListItem objects. Use data-vocabulary-free schema.org markup.","how_to_check":"For sample inner URLs: parse ld+json, find @type 'BreadcrumbList', assert itemListElement length >= 2, positions are positive integers sequential from 1, names non-empty. For each item URL: GET (follow redirects) and assert the final URL matches the declared item and the page's canonical tag points to the same URL.","common_mistakes":"position starting at 0; skipping intermediate levels (Home -> Post without Blog); relative or http:// item URLs while the canonical is https; trailing-slash mismatch causing redirects; using deprecated data-vocabulary.org markup.","platform_notes":"Align Cloudflare Pages / Vercel trailing-slash redirect rules with Astro `trailingSlash` to avoid redirect chains in breadcrumb URLs.","sources":["https://developers.google.com/search/docs/appearance/structured-data/breadcrumb","https://developers.google.com/search/blog/2025/01/simplifying-breadcrumbs"]},{"id":"structured-data-faqpage-howto-deprecated","section":"structured-data","title":"Do not rely on FAQPage or HowTo schema for rich results (deprecated)","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"FAQPage rich results stopped appearing in Google Search on May 7, 2026 (Rich Results Test support removed June 2026, Search Console API support August 2026). HowTo was removed from desktop in September 2023. Several other types were retired in June 2025 (ClaimReview, Special Announcement, Estimated Salary, Course Info, Book Actions, Learning Video, Vehicle Listing). The markup remains valid schema.org and causes no penalty, but generates no SERP feature — do not implement it expecting rich results.","why":"Teams maintaining FAQPage/HowTo markup expecting expandable rich results are wasting effort and page weight after these deprecations.","fix":"Do not add new FAQPage/HowTo implementations for SERP enhancement. Existing markup may be left (no penalty) or removed to reduce page weight. Remove HowTo schema if present.","how_to_check":"Detect FAQPage, HowTo, or the June 2025 retired types in ld+json and emit an informational warning (not a blocking error) noting no rich result will be generated.","common_mistakes":"Following pre-2024 guides that recommend FAQPage on all blog posts; expecting FAQ accordion content to render as expandable SERP rich results after May 2026.","sources":["https://developers.google.com/search/docs/appearance/structured-data/faqpage","https://www.engagecoders.com/google-retires-7-structured-data-features-to-streamline-search-results/"]},{"id":"structured-data-localbusiness-schema","section":"structured-data","title":"LocalBusiness JSON-LD on homepage for local/physical businesses","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"If the site represents a physical or local-service business, the homepage must include a LocalBusiness block (or a specific subtype: Restaurant, MedicalClinic, LegalService). No properties are strictly required, but emit name, a structured PostalAddress (streetAddress, addressLocality, addressRegion, postalCode, addressCountry), telephone in E.164 (+countrycode) format, url, and ideally geo, image, and structured openingHoursSpecification.","why":"LocalBusiness schema is a primary input to Google's local pack and Maps. NAP consistency between schema, visible page, and the Google Business Profile is critical for local ranking (NAP inconsistency is a leading cause of local ranking suppression).","fix":"In the homepage layout for local sites: `{ '@context':'https://schema.org','@type':'LocalBusiness', name: BIZ_NAME, address:{ '@type':'PostalAddress', streetAddress:'...', addressLocality:'...', addressRegion:'...', postalCode:'...', addressCountry:'US' }, telephone:'+1-555-555-5555', url: Astro.site }`. Store all NAP and hours constants once in src/consts.ts and reuse them for the visible `<address>` element.","how_to_check":"Fetch homepage ld+json; find @type matching LocalBusiness or subtype; assert name, address.streetAddress, address.addressLocality, address.addressCountry non-empty; assert telephone (if present) starts with '+'. (NAP-vs-visible matching is covered by the content-match rule.)","common_mistakes":"Using generic @type 'Organization' when a subtype applies; omitting addressCountry; telephone without country code; free-text opening hours instead of structured dayOfWeek/opens/closes.","sources":["https://developers.google.com/search/docs/appearance/structured-data/local-business"]},{"id":"structured-data-organization-homepage","section":"structured-data","title":"Organization (or specific subtype) JSON-LD on the homepage with logo and sameAs","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"The homepage must include an Organization block (or a more specific subtype: LocalBusiness, OnlineStore, NGO). Google documents no required properties, but emit @context, @type, name, url, logo, and a sameAs array of official social/directory profiles. The logo must be a publicly reachable raster image (PNG/JPEG/WebP, not SVG) at least 112x112 px. Place Organization schema only on the homepage, not every page.","why":"Organization schema is the primary signal Google uses to build the Knowledge Panel, disambiguate brand identity, and attach the logo/social profiles to the site, supporting E-E-A-T and (in 2026) AI Overview brand citation. sameAs links are independent entity-existence evidence; Wikidata is the strongest sameAs target for Knowledge Graph reconciliation.","fix":"In src/pages/index.astro (or a layout gated on `Astro.url.pathname === '/'`): `{ '@context':'https://schema.org','@type':'Organization', name: SITE_NAME, url: import.meta.env.SITE, logo:{ '@type':'ImageObject', url: LOGO_URL }, sameAs: SOCIAL_LINKS }`. Serve the logo via astro:assets from src/assets/ (PNG >=112px). Keep SITE_NAME and a SOCIAL_LINKS array (LinkedIn, X, Facebook, Instagram, YouTube, GitHub, Wikidata) in src/consts.ts.","how_to_check":"Fetch homepage; parse ld+json; find @type matching Organization or subtype; assert name and url are non-empty. GET logo.url -> assert 200, Content-Type starts with image/ and is not image/svg+xml, dimensions >=112x112. For each sameAs URL assert absolute HTTPS and 200 (warn, not error, if sameAs absent).","common_mistakes":"Using @type 'WebSite' alone to represent the brand; omitting or pointing logo at an SVG; putting Organization schema on every page; listing a personal social account instead of the brand page; omitting Wikidata.","sources":["https://developers.google.com/search/docs/appearance/structured-data/organization","https://ahrefs.com/blog/google-knowledge-graph/"]},{"id":"structured-data-product-schema","section":"structured-data","title":"Product JSON-LD on product pages with name and offers/rating","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Every single-product page must include Product JSON-LD with name plus at least one of review, aggregateRating, or offers. In offers, price must be a numeric string with no currency symbol, priceCurrency a valid ISO 4217 code, and availability a schema.org URL. priceValidUntil is optional but, if present, must be a future date.","why":"Product schema unlocks product snippets (price, availability, star ratings) in SERPs. Missing name or all three of review/aggregateRating/offers prevents eligibility. An expired priceValidUntil can silently suppress the snippet.","fix":"In src/layouts/Product.astro: `{ '@context':'https://schema.org','@type':'Product', name: product.name, image:[product.image], offers:{ '@type':'Offer', price: product.price.toString(), priceCurrency:'USD', availability:'https://schema.org/InStock' } }`. Omit priceValidUntil on static sites unless you can keep it current (rebuild cron or SSR); if included, set a future date.","how_to_check":"For each product URL: parse ld+json, find @type 'Product'; assert name non-empty and at least one of review/aggregateRating/offers present. If offers: assert price is numeric-only string, priceCurrency is a 3-letter ISO 4217 code, availability is a schema.org URL. If priceValidUntil present, assert it parses as ISO and is > Date.now().","common_mistakes":"price formatted as '$19.99'; availability as plain text 'In Stock'; Product schema on a category/listing page; a stale priceValidUntil copied from a template.","platform_notes":"For static builds, ensure price data is available at build time or use SSR (Cloudflare Workers / Vercel Functions) for frequently changing prices; a stale priceValidUntil silently suppresses snippets after it passes.","sources":["https://developers.google.com/search/docs/appearance/structured-data/product-snippet"]},{"id":"structured-data-rich-results-test-eligible","section":"structured-data","title":"Rich Results Test confirms eligibility for each schema type in use","severity":"high","stage":"post-launch","automatable":true,"check_type":"external_tool","what":"After deploy, run Google's Rich Results Test on at least one representative live URL per schema type in use (homepage for Organization/WebSite, an article for Article, a product page for Product, an inner page for BreadcrumbList, a video page for VideoObject). Each should show eligible with zero ERROR-severity issues.","why":"The Rich Results Test exercises Google's actual parser and Google-specific field requirements, not just schema.org validity. It is the authoritative tool for Google rich-result eligibility.","fix":"Test the live preview URL after deploy. Automate via the API: `POST https://searchconsole.googleapis.com/v1/urlTestingTools/richResultsTest:run?url=<url>` with a Google API key, in a post-deploy CI step against the preview URL.","how_to_check":"Call the Rich Results Test API for each representative URL; assert testStatus.status is 'COMPLETE', richResultsItems is non-empty for types expected to produce rich results, and each item has zero ERROR-severity issues.","common_mistakes":"Testing only localhost (the tool needs a public URL); checking only the homepage and missing article/product template errors; expecting FAQPage/HowTo to show eligibility (deprecated).","platform_notes":"Cloudflare Pages (`<branch>.<project>.pages.dev`) and Vercel (`<project>-<hash>.vercel.app`) preview URLs are public and work with the Rich Results Test.","sources":["https://search.google.com/test/rich-results","https://developers.google.com/search/docs/appearance/structured-data"]},{"id":"structured-data-videoobject-video-pages","section":"structured-data","title":"VideoObject JSON-LD on pages where a video is the primary content","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Any page whose primary content is a video (embedded YouTube/Vimeo, self-hosted, or `<video>`) must include a VideoObject block with name, description, a publicly fetchable thumbnailUrl, uploadDate (ISO 8601), and contentUrl or embedUrl. Include duration (ISO 8601, e.g. PT5M30S) to improve eligibility.","why":"VideoObject markup is the only path to Google's Video rich results (video carousel, key moments, SERP thumbnail). Pages embedding video without it get no SERP video treatment, and in 2026 AI search uses VideoObject alongside transcripts for video understanding.","fix":"In the video/blog layout, inject VideoObject (in the same @graph as Article if applicable): `{ '@type':'VideoObject', name: post.data.videoTitle, description: post.data.videoDescription, thumbnailUrl: post.data.videoThumbnail, uploadDate: post.data.pubDate.toISOString(), contentUrl: post.data.videoUrl, duration:'PT5M30S' }` via `<script type=\"application/ld+json\" set:html={JSON.stringify(schema)} />`.","how_to_check":"For each page containing an `<iframe>` or `<video>`: parse ld+json, assert a VideoObject node with non-empty name, description, thumbnailUrl, uploadDate (ISO 8601) and at least one of contentUrl/embedUrl. Validate via Rich Results Test selecting 'Video'.","common_mistakes":"thumbnailUrl behind auth or robots-blocked so Googlebot cannot fetch it; non-ISO uploadDate; VideoObject on a page where the video is not actually watchable; hardcoded view counts that go stale; omitting duration.","platform_notes":"Pure JSON-LD in static HTML on both platforms; ensure the thumbnailUrl domain is not blocked in robots.txt.","sources":["https://developers.google.com/search/docs/appearance/structured-data/video"]},{"id":"structured-data-website-site-name","section":"structured-data","title":"WebSite JSON-LD on homepage for site-name eligibility (no SearchAction)","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"The homepage must include a WebSite block with @type 'WebSite', name (the display site name), and url (canonical homepage). Do NOT add a potentialAction SearchAction block: Google deprecated the Sitelinks Search Box on November 21, 2024 and it produces no SERP feature (leaving it in causes no error, but should not be added to new builds). Place WebSite schema only on the homepage.","why":"Google's site-name feature in SERPs reads from WebSite.name; without it Google guesses from the <title> and may truncate or pick wrongly. The WebSite type and site-name function remain fully supported after the SearchAction deprecation.","fix":"Co-locate with the Organization block on the homepage: `{ '@context':'https://schema.org','@type':'WebSite', name: SITE_NAME, url: import.meta.env.SITE }`. Set `site:` in astro.config.mjs to the deployed domain so url matches the canonical. If a legacy potentialAction/SearchAction block exists, remove it.","how_to_check":"Fetch homepage; parse ld+json; find @type 'WebSite'; assert name non-empty and url matches the canonical homepage URL (respecting Astro trailingSlash). Flag any potentialAction SearchAction as an informational deprecated-markup notice (not a blocking error).","common_mistakes":"Relying on <title> instead of WebSite schema; url pointing at a non-root page; name/url mismatch between WebSite and Organization; copying older tutorials that still add SearchAction.","platform_notes":"Ensure Astro `site` matches the actual deployed domain on Cloudflare Pages or Vercel.","sources":["https://developers.google.com/search/blog/2024/10/sitelinks-search-box","https://developers.google.com/search/docs/appearance/structured-data/intro-structured-data"]},{"id":"structured-data-gsc-enhancements-monitoring","section":"structured-data","title":"Monitor Search Console Enhancements for structured-data errors post-launch","severity":"medium","stage":"post-launch","automatable":false,"check_type":"manual","what":"After indexing begins, check Google Search Console > Search Appearance > Rich Results (Enhancements). Every active schema type should show a Valid count; investigate and resolve any Error or Warning items. Connect GSC to the property before launch and check within 1-2 weeks of the first crawl.","why":"GSC is the only surface that reports structured-data errors at scale across all indexed pages, catching issues Google's crawler finds that the Rich Results Test (single-URL) does not.","fix":"No Astro code change. Verify ownership (HTML file or DNS TXT; Vercel offers a GSC marketplace integration) before launch, then monitor the Enhancements section. Optionally query the URL Inspection API with a service account for per-URL rich-result status.","how_to_check":"Log in to GSC > Search Appearance > Rich Results and review each enhancement type's error/warning counts; or query the URL Inspection API (requires OAuth/service-account) and flag any type with error_count > 0. Human interpretation of trends is required, so this is not fully automatable.","common_mistakes":"Never checking GSC after launch; ignoring warnings that suppress rich results; not connecting GSC before launch; looking for FAQPage/HowTo reports that no longer exist.","platform_notes":"Both Cloudflare Pages and Vercel support HTML-file or DNS-TXT verification; Vercel has a GSC marketplace integration that simplifies it.","sources":["https://support.google.com/webmasters/answer/9044175"]},{"id":"structured-data-imageobject-primary-image","section":"structured-data","title":"Primary content image has ImageObject markup with stable URL and dimensions","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Pages with a primary content image (articles, products) should expose that image as an ImageObject with @type, url (or contentUrl), width, and height — either standalone or nested as the Article/Product image property. The image URL must be stable across deploys (not a hash that changes every build). For licensing-eligible images, add license and creditText.","why":"Google uses ImageObject markup (and og:image) as primary sources for selecting thumbnails in Search and Discover and for Google Images rich features. For Article rich results, the image property with dimensions is what satisfies the recommended image requirement.","fix":"Inject in <head>: `<script type=\"application/ld+json\" set:html={JSON.stringify({ '@context':'https://schema.org','@type':'ImageObject', url: imageUrl, width:1200, height:800, name:'Alt text' })} />`, or nest the same object as the Article/Product `image` property. Ensure imageUrl is a stable path (avoid a build-hash URL that rotates each deploy).","how_to_check":"GET page HTML, extract ld+json; assert @type 'ImageObject' (correct casing) OR that the Article/Product/Recipe schema includes an image with url and width/height. Validate via Rich Results Test.","common_mistakes":"Omitting width/height; using @type 'image' (lowercase) instead of 'ImageObject'; pointing url at a build-hash URL that changes every deploy.","platform_notes":"On Cloudflare Pages/Vercel ensure the schema image URL is content-stable (astro:assets content-hashed URLs are stable across deploys when the source is unchanged).","sources":["https://developers.google.com/search/docs/appearance/google-images","https://developers.google.com/search/docs/appearance/structured-data/image-license-metadata"]},{"id":"structured-data-profilepage-author-bio","section":"structured-data","title":"ProfilePage JSON-LD on author bio pages","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Each author bio page should include a ProfilePage block whose @id is the bio page's canonical URL and whose mainEntity is a Person with name, image, description, and a non-empty sameAs array of absolute social/profile URLs.","why":"Google's ProfilePage documentation explicitly supports static author bio pages, enabling the author photo/handle in SERPs. In 2026, Person sameAs in ProfilePage markup aids entity disambiguation against the Knowledge Graph and supports AI Overview author resolution and E-E-A-T.","fix":"In src/pages/authors/[id].astro or AuthorLayout.astro: `{ '@context':'https://schema.org','@type':'ProfilePage', '@id': Astro.url.href, mainEntity:{ '@type':'Person', name: author.name, image: author.photo, description: author.bio, sameAs:[author.twitter, author.linkedin, author.github] } }` injected with set:html.","how_to_check":"For each author page URL: parse ld+json, assert a ProfilePage node with @id matching the canonical URL, mainEntity['@type'] === 'Person', mainEntity.name non-empty, and mainEntity.sameAs a non-empty array of absolute URLs. Validate via Rich Results Test.","common_mistakes":"Placing Person schema only on article pages without a dedicated bio page; relative URLs in sameAs; omitting @id; placing the schema on the homepage instead of the bio URL.","sources":["https://developers.google.com/search/docs/appearance/structured-data/profile-page"]},{"id":"structured-data-webpage-graph-linking","section":"structured-data","title":"Connect entities in a single @graph with @id cross-references (WebPage layer)","severity":"low","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"As a quality-of-implementation enhancement, emit one @graph per page that links the entities via @id: a WebPage (or subtype AboutPage/ContactPage/CollectionPage/ItemPage) tying together WebSite (isPartOf), BreadcrumbList (breadcrumb), and the primary Article/Product entity. Not required for any current rich result.","why":"WebPage entities form the linking layer of a well-formed @graph, giving Google explicit relationships between Page, breadcrumb, primary entity, and site — improving entity understanding in the Knowledge Graph (the pattern used by Yoast and The SEO Framework).","fix":"Add to the page @graph: `{ '@type':'WebPage', '@id':`${canonicalUrl}#webpage`, url: canonicalUrl, name: pageTitle, isPartOf:{ '@id':`${siteUrl}#website` }, breadcrumb:{ '@id':`${canonicalUrl}#breadcrumb` } }`, and for articles add `mainEntity:{ '@id':`${canonicalUrl}#article` }`. Give each entity a matching @id so they cross-reference.","how_to_check":"For each page @graph, if a WebPage (or subtype) entity is present assert its url matches the canonical URL and its isPartOf/breadcrumb @id references resolve to other entities in the same graph. Absence is an informational note, not an error.","common_mistakes":"Confusing WebSite (the whole site) with WebPage (one page); emitting disconnected ld+json blocks with no shared @id linking instead of a single @graph.","sources":["https://developer.yoast.com/features/schema/functional-specification/"]},{"id":"performance-cls-threshold","section":"performance","title":"CLS is under 0.1 at the 75th percentile","severity":"critical","stage":"post-launch","automatable":true,"check_type":"lighthouse","what":"Cumulative Layout Shift must be <=0.1 at the 75th percentile (0.1-0.25 = needs improvement; >0.25 = poor). CLS accumulates across the entire page lifetime, not just load.","why":"Layout shifts degrade UX and are a Core Web Vitals ranking input. They commonly spike on launch day when real fonts, ads, banners, or embeds load for the first time.","fix":"Use astro:assets <Image /> (auto-injects width/height); supply explicit dimensions for public-folder, Markdown/MDX and remote images; self-host fonts with tuned fallback metrics; reserve space for dynamic content and wrap iframes in aspect-ratio containers. See the dedicated image-dimension, font, dynamic-content and iframe CLS rules below.","how_to_check":"Lighthouse: lighthouse <URL> --output=json | jq '.audits[\"cumulative-layout-shift\"].numericValue' must be < 0.1. For field data, CrUX cumulative_layout_shift p75 < 0.1.","common_mistakes":"Images without explicit width/height; web fonts loaded without preload/fallback tuning; banners or cookie notices injected above-the-fold after load without reserved space.","platform_notes":"No platform difference for CLS itself.","sources":["https://web.dev/articles/optimize-cls","https://docs.astro.build/en/guides/images/"]},{"id":"performance-crux-field-data-passing","section":"performance","title":"All three Core Web Vitals pass in CrUX field data at p75","severity":"critical","stage":"post-launch","automatable":true,"check_type":"external_tool","what":"After ~28 days of real-user traffic, the Chrome User Experience Report (CrUX) field data at the 75th percentile must show 'Good' for LCP (<2.5 s), INP (<200 ms), and CLS (<0.1). This is the ground-truth signal Google uses for the Page Experience ranking input.","why":"Google ranks on CrUX field data, not lab scores. A perfect Lighthouse score does not guarantee good field metrics — real users on slow mobile networks frequently experience worse. CrUX is the only authoritative pass/fail.","fix":"There is no single config change — field metrics are the combined outcome of all LCP/INP/CLS optimizations below. Monitor via Google Search Console's Core Web Vitals report, the PageSpeed Insights field-data panel, the CrUX API, or a RUM tool. Astro's static output gives a strong baseline; keep islands minimal.","how_to_check":"CrUX API: POST https://chromeuxreport.googleapis.com/v1/records:queryRecord?key=<KEY> with body {\"origin\":\"https://yourdomain.com\",\"metrics\":[\"largest_contentful_paint\",\"interaction_to_next_paint\",\"cumulative_layout_shift\"]} and assert all three show category FAST at p75. Or open pagespeed.web.dev and verify the field-data panel shows three green 'Good' badges.","common_mistakes":"Celebrating a 100 lab score on launch day without rechecking ~30 days later; CrUX lags by 28 days. New/low-traffic sites may never appear in CrUX (requires roughly 1000+ Chrome users/month) — fall back to RUM and lab data.","sources":["https://www.corewebvitals.io/core-web-vitals","https://github.com/GoogleChrome/web-vitals","https://www.digitalapplied.com/blog/core-web-vitals-2026-inp-lcp-cls-optimization-guide"]},{"id":"performance-img-explicit-dimensions","section":"performance","title":"Every <img> has explicit width and height (or layout prop) to reserve space","severity":"critical","stage":"build","automatable":true,"check_type":"html_element","what":"All <img> elements must carry numeric width and height attributes (or an astro:assets layout prop) so the browser can compute the intrinsic aspect ratio and reserve space before the image downloads.","why":"Without dimensions, browsers render images at 0x0 until download completes, then reflow — a primary CLS source. The 2025 Web Almanac reports 62% of mobile pages (65% desktop) still have at least one unsized image.","fix":"Local imports: Astro infers width/height automatically. Public-folder images: pass width/height explicitly. Remote images: pass width+height, or inferSize={true} (build-time request), or layout='constrained'|'full-width'|'fixed' (stable since v5.10) which auto-generates sizes/srcset. In CSS pair with img { height: auto; max-width: 100%; } — never width: auto, which overrides the aspect-ratio hint.","how_to_check":"Parse rendered HTML: document.querySelectorAll('img') with a missing width or height attribute (and no inline aspect-ratio) should be empty. Run Lighthouse --only-audits=cls and assert CLS < 0.1.","common_mistakes":"Public-folder images without explicit dimensions; CSS width: auto overriding the HTML aspect-ratio hint; inferSize on a remote domain not in image.domains/remotePatterns (silently no-ops).","platform_notes":"No platform difference — this is a build-time HTML output check.","sources":["https://web.dev/articles/optimize-cls","https://docs.astro.build/en/reference/modules/astro-assets/","https://almanac.httparchive.org/en/2025/performance"]},{"id":"performance-inp-threshold","section":"performance","title":"INP is under 200 ms at the 75th percentile","severity":"critical","stage":"post-launch","automatable":true,"check_type":"external_tool","what":"Interaction to Next Paint (which replaced FID on 12 March 2024) measures the worst interaction latency across the full page lifetime. Good: <=200 ms; needs improvement: 200-500 ms; poor: >500 ms. Lighthouse cannot measure INP — only field data (CrUX) reveals it.","why":"INP is an official Core Web Vitals ranking input. It catches post-load interaction freezes that FID missed. Astro's zero-JS default makes INP failures rare for content sites but they appear once interactive islands and third-party scripts are added.","fix":"Prefer client:idle / client:visible over client:load for non-critical islands; avoid spawning large islands inside map() loops; keep DOM under ~1400 nodes; break long event handlers into smaller tasks; defer/facade third-party scripts. See dedicated INP/TBT rules below.","how_to_check":"CrUX API: POST https://chromeuxreport.googleapis.com/v1/records:queryRecord?key=<KEY> with metrics [\"interaction_to_next_paint\"] and assert p75 < 200. Use Lighthouse TBT (<200 ms) only as a directional lab proxy; for the live page use the Web Vitals Chrome extension while interacting.","common_mistakes":"Wrapping entire page sections in client:load components; running heavy synchronous JS in click handlers without yielding; loading chat/GTM scripts synchronously.","platform_notes":"No platform difference — INP is purely a client-side JS execution concern.","sources":["https://web.dev/blog/inp-cwv-march-12","https://web.dev/articles/optimize-inp"]},{"id":"performance-lcp-image-priority","section":"performance","title":"LCP/hero image is eager + fetchpriority=high (never lazy-loaded), exactly one per page","severity":"critical","stage":"build","automatable":true,"check_type":"html_element","what":"The image that will be the LCP element must use loading='eager' (never loading='lazy') and carry fetchpriority='high', and only one image per page should be marked high priority.","why":"Lazy-loading the LCP image is the single largest avoidable LCP regression (the ~16-17% of pages doing it per the 2025 Web Almanac); fetchpriority='high' cuts LCP by 200-800 ms by promoting it past competing scripts/fonts. Multiple high-priority images compete and cancel the benefit.","fix":"On the hero <Image /> or <Picture />, set priority={true} (Astro v5.10+), which atomically applies loading='eager', fetchpriority='high', and decoding='sync'. Do not set priority on more than one image per page, and do not apply a global lazy default to above-the-fold images.","how_to_check":"Parse rendered HTML: the LCP <img> must NOT have loading='lazy' and SHOULD have fetchpriority='high'; assert document.querySelectorAll('img[fetchpriority=\"high\"]').length === 1 and it is the visual LCP candidate. Lighthouse audit 'lcp-lazy-loaded' must report 0 violations.","common_mistakes":"Wrapping the hero in a generic component that applies lazy by default; applying priority/fetchpriority to a logo or every image 'just in case'.","platform_notes":"Both Cloudflare Pages and Vercel respect these attributes; no extra config needed.","sources":["https://unlighthouse.dev/learn-lighthouse/lcp/lcp-lazy-loaded","https://addyosmani.com/blog/fetch-priority/","https://docs.astro.build/en/reference/modules/astro-assets/"]},{"id":"performance-lcp-threshold","section":"performance","title":"LCP is under 2.5 s at the 75th percentile","severity":"critical","stage":"post-launch","automatable":true,"check_type":"lighthouse","what":"Largest Contentful Paint must be 2.5 s or below at the 75th percentile of real page views (2.5-4 s = needs improvement; >4 s = poor). A slow LCP is the most common reason static sites fail Core Web Vitals.","why":"LCP is a direct Core Web Vitals ranking input. Because Astro ships zero JS by default, TTFB and resource-load duration dominate LCP, so it is highly controllable.","fix":"Set the hero <Image /> with priority={true} (Astro v5.10+, which applies loading='eager', fetchpriority='high', decoding='sync'), use <Picture formats={['avif','webp']} /> for smaller payloads, configure site in astro.config.mjs so assets serve from the CDN edge, and keep TTFB low. See the dedicated LCP-image, preload, TTFB and render-blocking rules below.","how_to_check":"PSI API: GET https://pagespeedonline.googleapis.com/pagespeedonline/v5/runPagespeed?url=<URL>&strategy=mobile&category=performance and assert lighthouseResult.audits['largest-contentful-paint'].numericValue < 2500. For field data use the CrUX origin/url record.","common_mistakes":"Lazy-loading the hero, serving the hero from public/ (bypasses astro:assets optimization), and not setting fetchpriority='high' on the LCP candidate.","platform_notes":"Cloudflare Pages serves from a 330+ PoP edge with tiered cache; Vercel's edge cache must be warm for real-world LCP.","sources":["https://web.dev/articles/optimize-lcp","https://developer.mozilla.org/en-US/blog/fix-image-lcp/"]},{"id":"performance-cache-hashed-assets-immutable","section":"performance","title":"Hashed assets (_astro/*) are served immutable; HTML is served short/no-cache","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_header","what":"Content-hashed assets (CSS/JS/fonts/images under _astro/) must be served Cache-Control: public, max-age=31536000, immutable, while HTML documents must be served no-cache (or public, max-age=0, must-revalidate) and never immutable.","why":"Hashed asset URLs never change, so immutable caching eliminates revalidation round trips on repeat visits. But if HTML is long-cached, returning visitors get stale HTML referencing deleted asset hashes, producing broken pages.","fix":"Cloudflare Pages: add a public/_headers file (copied to dist/) with a /_astro/* rule setting public, max-age=31536000, immutable and a /*.html (or /*) rule setting public, max-age=0, must-revalidate. Vercel: add vercel.json headers rules: an /_astro/(.*) immutable rule and a short-TTL rule for HTML. Do not rely on platform defaults — Cloudflare Pages has shipped max-age=0, must-revalidate for ALL files including _astro/* (GitHub issue #16692), so set the rule explicitly.","how_to_check":"curl -sI <URL>/_astro/FILE.HASH.js | grep -i cache-control must include max-age=31536000 and immutable; curl -sI <URL>/ | grep -i cache-control must show max-age=0/no-cache and must NOT contain immutable.","common_mistakes":"Applying the immutable policy to HTML; relying on platform defaults that omit immutable on hashed assets; not adding an explicit /_astro/* rule.","platform_notes":"Cloudflare Pages: _headers file at project root; default for hashed assets is NOT immutable (issue #16692) so override it. Vercel: static HTML is not edge-cached by default; _astro/* needs an explicit vercel.json rule (unlike _next/static which is automatic).","sources":["https://github.com/withastro/astro/issues/16692","https://developers.cloudflare.com/pages/configuration/serving-pages/","https://vercel.com/docs/caching/cache-control-headers"]},{"id":"performance-cls-dynamic-content-iframes","section":"performance","title":"Dynamic content, banners, and iframes/embeds reserve space (aspect-ratio / fixed)","severity":"high","stage":"build","automatable":false,"check_type":"manual","what":"Any element inserted or expanded after first paint — cookie banners, newsletter popups, ad slots, skeleton loaders, and iframes (YouTube, Maps, Calendly, Twitter/X) — must have its space reserved before content arrives.","why":"Content inserted around existing content, or an unsized iframe collapsing to 0 height then expanding, causes layout shift that can push CLS above 0.1 single-handedly. Cookie banners and embeds are the most common post-launch CLS sources.","fix":"Cookie banners: position: fixed (fixed elements do not contribute to CLS). Iframes/embeds: wrap in <div style='aspect-ratio:16/9;width:100%'> with the iframe absolutely filling it, plus loading='lazy' and title. Ad slots: set min-height to the largest expected size. Skeletons: match real-content dimensions exactly. For YouTube prefer a thumbnail+play facade that swaps in the iframe on click.","how_to_check":"curl -sL <URL> | grep '<iframe' | grep -v 'aspect-ratio\\|height' flags unsized iframes. Then throttle to Slow 3G in DevTools, reload, and watch for jumps; check Lighthouse 'Avoid large layout shifts' for dynamic-content/iframe entries.","common_mistakes":"Injecting a cookie consent banner via JS without reserved space; pasting a YouTube/Twitter embed without an aspect-ratio container; Google Maps embed with width:100% but no height.","platform_notes":"No platform difference.","sources":["https://web.dev/articles/optimize-cls","https://www.corewebvitals.io/core-web-vitals/cumulative-layout-shift"]},{"id":"performance-compression-enabled","section":"performance","title":"Brotli (or zstd/gzip) compression is active for text responses","severity":"high","stage":"post-launch","automatable":true,"check_type":"http_header","what":"All text responses (HTML, CSS, JS, SVG, JSON) must be served compressed, negotiated via Accept-Encoding. Brotli is preferred (~14-25% smaller than gzip); Zstandard is also valid on Cloudflare.","why":"Compression reduces bytes on the wire, directly improving FCP and LCP for every text asset.","fix":"No Astro config — handled at the CDN/platform layer. On Cloudflare free plan the default is zstd (not Brotli); if Safari support matters, note Safari does not accept zstd — use Cloudflare Compression Rules (available to all plans since Oct 2024) to force Brotli/gzip. Vercel negotiates Brotli/gzip automatically on all plans.","how_to_check":"curl -sI -H 'Accept-Encoding: br, gzip, zstd' <URL> | grep -i content-encoding should return br (or zstd/gzip). Repeat for a /_astro/*.css or *.js asset. Check the header value even if curl does not decode the body.","common_mistakes":"Assuming Cloudflare Pages free plan delivers Brotli — it defaults to Zstandard, which breaks compression negotiation on Safari. Brotli is the default only on Pro/Business; Enterprise defaults to gzip.","platform_notes":"Cloudflare default varies by plan (Free: zstd, Pro/Business: Brotli, Enterprise: gzip); Compression Rules override it. Vercel: Brotli/gzip automatic on all plans.","sources":["https://developers.cloudflare.com/speed/optimization/content/compression/","https://vercel.com/docs/edge-network/compression"]},{"id":"performance-fonts-self-host-display-swap","section":"performance","title":"Web fonts are self-hosted WOFF2 with font-display:swap, preloaded, and fallback-metric tuned","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"Web fonts must be (1) self-hosted from your own domain (not the Google Fonts CDN), (2) WOFF2, (3) declared font-display: swap (or optional), (4) preloaded for the critical subset with <link rel='preload' as='font' crossorigin>, and (5) given tuned fallback metrics (size-adjust / ascent-override / descent-override) so the swap causes near-zero CLS.","why":"Third-party font CDNs add an extra DNS+TCP+TLS round trip (100-500 ms) and send the user IP to Google; font-display:swap avoids invisible text (FOIT); preloading makes the font available before first paint; matched fallback metrics eliminate the swap-time layout jump that otherwise pushes CLS above 0.1 on text-heavy pages.","fix":"Use Astro's Fonts API (experimental experimental.fonts in v5.7+ / stable in Astro 6): configure a provider in astro.config.mjs and add <Font cssVariable='--font-inter' preload /> in the layout — it self-hosts, sets font-display, preloads, and auto-computes fallback overrides (optimizedFallbacks). On Astro 5 without the flag, self-host WOFF2 in public/fonts/ with explicit @font-face + preload, and compute size-adjust via the fontaine package or screenspan.net/fallback. Preload at most ~2 fonts to avoid competing with the LCP image.","how_to_check":"curl -sL <URL> | grep 'fonts.googleapis' returns nothing; grep 'font-display' shows swap/optional; grep for a font preload link in <head>; @font-face for the system fallback contains size-adjust or ascent-override. In DevTools Network filter by Font and confirm all font requests hit your own domain.","common_mistakes":"Using a Google Fonts <link> embed; font-display: block (FOIT up to 3 s); TTF/OTF instead of WOFF2; preloading too many fonts; swap without fallback-metric overrides.","platform_notes":"Fonts are downloaded at build time into the static asset bundle, so behavior is identical on Cloudflare Pages and Vercel; hashed font files cache immutably under _astro/.","sources":["https://docs.astro.build/en/reference/experimental-flags/fonts/","https://web.dev/articles/optimize-cls","https://astro.build/blog/astro-6/"]},{"id":"performance-http2-http3-enabled","section":"performance","title":"HTTP/2 or HTTP/3 (QUIC) is enabled on the domain","severity":"high","stage":"post-launch","automatable":true,"check_type":"http_header","what":"The site must be served over HTTP/2 (multiplexing) or HTTP/3 (QUIC). HTTP/1.1 forces serial asset downloads, multiplying latency on asset-heavy pages.","why":"HTTP/2 multiplexes many assets over one connection in parallel; HTTP/3 QUIC eliminates head-of-line blocking and offers 0-RTT reconnects, especially impactful on mobile.","fix":"Platform/CDN setting, no Astro config. Confirm the domain negotiates h2 or h3.","how_to_check":"curl -sI --http2 <URL> | grep -i 'HTTP/' should show HTTP/2 200; for HTTP/3 use curl --http3 (curl 7.66+) or http2.pro. In DevTools enable the Protocol column — requests should show h2 or h3.","common_mistakes":"Assuming Vercel supports HTTP/3 — as of mid-2025 it does not, with no announced timeline. On Cloudflare, HTTP/3 may need enabling in Dashboard > Speed > Optimization.","platform_notes":"Cloudflare Pages: HTTP/2 always on; HTTP/3 available on all plans but verify it is enabled in the dashboard. Vercel: HTTP/2 default; HTTP/3 NOT supported as of mid-2025.","sources":["https://developers.cloudflare.com/speed/optimization/protocol/http3/","https://community.vercel.com/t/how-do-i-get-http-3-enabled-on-my-site/11723"]},{"id":"performance-lcp-preload-link","section":"performance","title":"LCP image is discoverable in initial HTML and has a <link rel=preload> in <head>","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"The LCP resource URL must appear in the initial HTML source (not be JS-injected), and a <link rel='preload' as='image' fetchpriority='high'> should be present in <head> (with imagesrcset/imagesizes for responsive images) so the preload scanner fetches it before parsing <body>.","why":"fetchpriority raises priority but does not move discovery earlier; a preload link makes the browser start fetching the LCP image before stylesheets/scripts delay the parser. If the LCP image is set via JS (background-image resolved in JS, src in useEffect), it cannot be discovered until JS runs, adding hundreds of ms.","fix":"Use <Image />/<Picture /> so a native <img src> is emitted at build time. For the preload, call getImage() in the layout <head> and inject <link rel='preload' as='image' href={img.src} imagesrcset={img.srcSet.attribute} imagesizes='100vw' fetchpriority='high' />. Note: priority={true} does NOT auto-inject a preload link — add it manually. Never set the LCP via CSS background-image or a JS-driven first carousel slide unless its URL is also preloaded.","how_to_check":"GET the HTML: the LCP image URL must appear in source (curl -sL <URL> | grep the filename), and document.querySelector('link[rel=\"preload\"][as=\"image\"]') in <head> must exist with href/imagesrcset matching the LCP <img>. Lighthouse 'Preload Largest Contentful Paint image' must pass.","common_mistakes":"Preloading a different URL than the <img> resolves to (hash mismatch); preloading without imagesrcset for a responsive image; LCP src injected by a JS carousel.","platform_notes":"Cloudflare Pages static: preload href is a hashed /_astro/ URL. Vercel: href may be /_vercel/image?url=...&w=...&q=... — verify it matches what the <img> actually loads.","sources":["https://web.dev/articles/preload-responsive-images","https://www.pagespeedfix.com/blog/astro-image-optimization/","https://developer.mozilla.org/en-US/blog/fix-image-lcp/"]},{"id":"performance-no-render-blocking-resources","section":"performance","title":"No render-blocking CSS or synchronous JS in the critical path","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"Above-the-fold CSS should be inlined or non-blocking, and every external <script src> in <head> must use defer, async, or type='module'. Large global stylesheets and synchronous scripts in <head> block first render.","why":"Each blocking stylesheet adds its full load time to the LCP critical path (a 50 KB CDN stylesheet can add 300-800 ms); a synchronous <head> script pauses HTML parsing until it downloads and runs, inflating LCP/TTI and TBT.","fix":"Astro auto-inlines CSS under 4 KB (tunable via Vite build.assetsInlineLimit) and bundled client scripts are type='module' (deferred) by default. Load non-critical external CSS with the media='print' onload=\"this.media='all'\" pattern. Never paste a third-party snippet into Layout.astro <head> without defer/async; avoid is:inline synchronous scripts unless tiny and critical.","how_to_check":"Lighthouse 'Eliminate render-blocking resources' must report 0 blocking resources. curl -sL <URL> | grep '<link.*stylesheet' | grep -v 'media=' flags potentially blocking CSS; grep <head> script tags with src lacking defer/async/type=module.","common_mistakes":"Importing a full framework CSS (Bootstrap/Tailwind CDN) via <link> in the layout head; copying Intercom/Hotjar snippets without defer.","platform_notes":"No platform difference.","sources":["https://web.dev/articles/optimize-lcp","https://docs.astro.build/en/guides/styling/","https://docs.astro.build/en/reference/directives-reference/"]},{"id":"performance-no-unused-js-css-tbt","section":"performance","title":"Minimal unused/heavy JS and CSS; Total Blocking Time under 200 ms","severity":"high","stage":"build","automatable":true,"check_type":"lighthouse","what":"Bundles must not ship large volumes of unused code (target <20% unused on initial load), and Lighthouse Total Blocking Time (the lab proxy for INP) must be under 200 ms.","why":"Unused/heavy JS wastes parse and compile time on the main thread, and any task over 50 ms contributes to TBT. High TBT (>200 ms) almost always predicts poor field INP.","fix":"Rely on Vite tree-shaking; use named imports (import { debounce } from 'lodash-es') not barrel/default imports; replace heavy libs (moment -> Intl, jQuery -> native DOM); import individual icon components, not whole icon libraries. Use Astro's Tailwind integration (v4 purges at build). Audit with npx source-map-explorer dist/_astro/*.js and investigate any JS file over ~50 KB.","how_to_check":"lighthouse <URL> --output=json | jq '.audits[\"total-blocking-time\"].numericValue' < 200; Lighthouse 'Remove unused JavaScript' and 'Remove unused CSS' audits must pass; DevTools Coverage should show <50% unused for any file over 20 KB.","common_mistakes":"Importing a whole UI framework or icon set for minor interactivity; not tree-shaking lodash; loading a below-fold slideshow library synchronously.","platform_notes":"No platform difference.","sources":["https://www.debugbear.com/docs/metrics/total-blocking-time","https://web.dev/articles/optimize-inp"]},{"id":"performance-preconnect-third-party-origins","section":"performance","title":"Critical third-party origins have preconnect / dns-prefetch hints","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"Add <link rel='preconnect'> (with dns-prefetch as fallback) in <head> for each third-party origin that serves a render-critical resource, limited to roughly 4-6 origins. Use dns-prefetch only for non-critical origins.","why":"A cold connection to a third-party origin (DNS + TCP + TLS) costs 100-500 ms; preconnecting removes that latency before the first fetch. Too many preconnects waste connections.","fix":"Add hints in Layout.astro <head>, e.g. <link rel='preconnect' href='https://your-cdn.example.com' /> (add crossorigin for font origins). Astro's Fonts API generates font preconnects automatically. Keep the total under ~6.","how_to_check":"curl -sL <URL> | grep 'preconnect\\|dns-prefetch' and cross-reference against high-priority third-party origins in the DevTools Network panel — each render-critical third-party origin should have a matching preconnect.","common_mistakes":"Omitting crossorigin on font-origin preconnects; preconnecting every analytics endpoint instead of using dns-prefetch; forgetting preconnect for an image CDN hosting the LCP candidate.","platform_notes":"No platform difference.","sources":["https://www.debugbear.com/blog/resource-hints-rel-preload-prefetch-preconnect","https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Attributes/rel/preconnect"]},{"id":"performance-third-party-scripts-deferred","section":"performance","title":"Third-party scripts (GTM, analytics, chat) are deferred or facade-loaded","severity":"high","stage":"build","automatable":true,"check_type":"body_regex","what":"Every non-critical third-party script (GTM, Intercom, Zendesk, Hotjar, Meta Pixel, etc.) must load with defer/async or be replaced by a click-triggered facade. Total third-party main-thread blocking should stay under ~250 ms.","why":"A GTM container is 100-500 KB and chat widgets download 200-500 KB; loaded synchronously these are the most common cause of high TBT and poor INP in otherwise clean Astro sites.","fix":"Add third-party snippets with defer (or at the end of <body>); GTM's head script should use async. For chat widgets, render a static button facade and load the real widget on first click. Consider Cloudflare Zaraz to proxy analytics at the edge. Verify Partytown compatibility before proxying a widget through it (many use APIs incompatible with its worker proxy).","how_to_check":"curl -sL <URL> | grep -oP '<script[^>]+src=[^>]+>' | grep -v 'defer\\|async\\|type=\"module\"' must return nothing. Lighthouse 'Reduce the impact of third-party code' third-party blocking time < 250 ms; in the Network panel no third-party script should show Priority: Highest.","common_mistakes":"Pasting the GTM head snippet without async; loading a chat widget through Partytown without confirming compatibility.","platform_notes":"Cloudflare Zaraz can proxy analytics through Cloudflare's edge to reduce third-party origin overhead.","sources":["https://www.debugbear.com/blog/reduce-the-impact-of-third-party-code","https://web.dev/articles/optimize-inp"]},{"id":"performance-ttfb-fast-server-response","section":"performance","title":"Time to First Byte (TTFB) is under 800 ms","severity":"high","stage":"post-launch","automatable":true,"check_type":"external_tool","what":"TTFB (navigation request to first byte of HTML) must be under 800 ms ('good'), ideally under 600 ms. A slow TTFB caps achievable LCP.","why":"TTFB delays every subsequent resource; a page with 2 s TTFB cannot reach LCP < 2.5 s regardless of other optimizations.","fix":"Use output: 'static' wherever there is no dynamic content so HTML is pre-rendered and served from the edge; set site in astro.config.mjs. For output: 'server'/hybrid, minimize SSR computation. Serve from Cloudflare Pages or Vercel's global edge.","how_to_check":"curl -w 'TTFB: %{time_starttransfer}s\\n' -o /dev/null -s <URL> — assert time_starttransfer < 0.800. Or check PageSpeed Insights 'Server response time (TTFB)'.","common_mistakes":"Deploying a static site to a single-region origin without a CDN; adding SSR middleware to pages that could be fully static; not setting output: 'static'.","platform_notes":"Cloudflare Pages serves cached static responses with ~20-100 ms TTFB from 330+ PoPs. Vercel's first-request TTFB can be higher until the asset is promoted to the regional edge cache.","sources":["https://web.dev/articles/optimize-lcp","https://developers.cloudflare.com/pages/configuration/serving-pages/"]},{"id":"performance-below-fold-image-loading","section":"performance","title":"Below-fold images use loading=lazy and decoding=async","severity":"medium","stage":"build","automatable":true,"check_type":"html_element","what":"All non-LCP images below the fold should have loading='lazy' (Astro <Image /> default) and decoding='async' so they defer fetching and decode off the main thread. The LCP image must instead use loading='eager' and decoding='sync'.","why":"Lazy-loading below-fold images cuts initial page weight and network contention (improving LCP), and async decoding keeps the main thread free during decode (improving INP). decoding='async' on the LCP image is an anti-pattern that delays its paint.","fix":"Astro <Image /> defaults to loading='lazy' + decoding='async' when priority is not set, and priority={true} switches the LCP image to eager + sync — so correct astro:assets usage needs no manual attributes. For raw <img> in Markdown/MDX/HTML, add loading='lazy' decoding='async' manually. Do not apply a global loading='eager' to below-fold images.","how_to_check":"Parse rendered HTML: document.querySelectorAll('img:not([fetchpriority=\"high\"]):not([loading=\"lazy\"])') should be empty (allowing deliberate above-fold eager cases); the fetchpriority='high' image should have decoding='sync'. Lighthouse 'Defer offscreen images' must pass.","common_mistakes":"Adding loading='eager' globally to fix a lazy issue then leaving it on below-fold images; raw <img> in .mdx/.html without lazy/async.","platform_notes":"No platform difference (Cloudflare Rocket Loader does not affect image loading attributes).","sources":["https://docs.astro.build/en/guides/images/","https://developer.mozilla.org/en-US/docs/Web/API/HTMLImageElement/decoding"]},{"id":"performance-build-minified","section":"performance","title":"Production build output (HTML, CSS, JS) is minified and source maps are off","severity":"medium","stage":"build","automatable":true,"check_type":"body_regex","what":"astro build must emit minified HTML, CSS, and JS with no comments, whitespace, or public source maps.","why":"Minification cuts CSS/JS payload by 10-30%, reducing transfer and parse time; source maps in production needlessly expose source code.","fix":"Astro minifies CSS/JS (via Vite) and HTML by default in production. Ensure astro.config.mjs does NOT contain vite: { build: { minify: false } } left over from debugging, and keep build.sourcemap off (or hidden) for production.","how_to_check":"curl -sL <URL>/_astro/HASH.css | wc -l should be ~1 line; Lighthouse 'Minify CSS' and 'Minify JavaScript' audits must pass.","common_mistakes":"Leaving minify:false from debugging; shipping build.sourcemap:true to production.","platform_notes":"No platform difference.","sources":["https://docs.astro.build/en/guides/styling/","https://docs.astro.build/en/reference/configuration-reference/"]},{"id":"performance-cls-composited-animations","section":"performance","title":"Animations use only transform/opacity (no layout-triggering properties)","severity":"medium","stage":"build","automatable":true,"check_type":"body_regex","what":"CSS animations/transitions must use transform and opacity rather than layout-triggering properties (top/left/right/bottom/width/height/margin/padding).","why":"Animating layout properties forces per-frame layout recalculation, generates layout shifts (CLS), and blocks the main thread (INP); transform/opacity run on the GPU compositor and never trigger layout.","fix":"In component <style> blocks, replace e.g. animating left:-100%->0 with transform: translateX(-100%)->translateX(0). For accordions use grid-template-rows: 0fr->1fr instead of height:0->auto; for drawers use translateX instead of margin. Add will-change: transform only to elements that genuinely animate.","how_to_check":"Source audit: grep .astro/.css for 'transition:' or 'animation:' lines that reference layout properties without transform/opacity. Lighthouse 'Avoid non-composited animations' must pass; DevTools Rendering > Paint flashing / Layout Shift Regions confirms (green = composited, red = layout).","common_mistakes":"Animating height:0->auto for accordions; animating top for sticky headers; margin-left:-100% for off-canvas drawers.","platform_notes":"No platform difference.","sources":["https://web.dev/articles/optimize-cls","https://web.dev/articles/optimize-inp"]},{"id":"performance-dom-size-under-1400","section":"performance","title":"DOM size is under 1400 nodes on initial load","severity":"medium","stage":"build","automatable":true,"check_type":"lighthouse","what":"The initial page should have fewer than ~1400 DOM elements (Lighthouse warning threshold); beyond this, JS traversal and style/layout recalculation scale super-linearly and degrade INP.","why":"Large DOMs slow hydration and inflate INP in island-based frameworks because Astro hydrates island subtrees within the surrounding static DOM.","fix":"Paginate or virtualize large lists/tables; use client:visible for content-heavy below-fold components so they hydrate on scroll; avoid deeply nested wrapper components that add dozens of nodes per page.","how_to_check":"Lighthouse 'Avoid an excessive DOM size' must not be flagged; lighthouse <URL> --output=json | jq '.audits[\"dom-size\"].numericValue' < 1400. In the console, document.querySelectorAll('*').length.","common_mistakes":"Rendering a full post list (200 cards) on the homepage as static HTML; deep mega-menu/wrapper nesting.","platform_notes":"No platform difference.","sources":["https://web.dev/articles/optimize-inp","https://www.debugbear.com/docs/metrics/interaction-to-next-paint"]},{"id":"performance-fcp-speed-index","section":"performance","title":"First Contentful Paint under 1.8 s and Speed Index under 3.4 s (lab)","severity":"medium","stage":"post-launch","automatable":true,"check_type":"lighthouse","what":"Supporting Lighthouse metrics: FCP (first text/image/canvas paint) under 1.8 s and Speed Index (how quickly content visually populates) under 3.4 s on mobile. Neither is a direct ranking signal but both feed the Lighthouse score and correlate with LCP.","why":"FCP marks the end of the blank screen; FCP > 2 s almost always implies LCP > 2.5 s. Speed Index captures perceived load completeness (10% of the Lighthouse score).","fix":"Improved by the same levers as LCP: low TTFB, no render-blocking CSS/JS, inlined critical CSS (<4 KB), optimized/preloaded images, and font-display:swap to avoid FOIT. Astro's static HTML delivers most content in the first response, naturally producing low FCP/Speed Index.","how_to_check":"lighthouse <URL> --output=json | jq '.audits[\"first-contentful-paint\"].numericValue' < 1800 and '.audits[\"speed-index\"].numericValue' < 3400. Both must be green on mobile in PageSpeed Insights.","common_mistakes":"@import-ing a Google Font in CSS (blocks FCP); media='all' on a non-critical stylesheet.","platform_notes":"No platform difference.","sources":["https://web.dev/articles/optimize-lcp","https://www.corewebvitals.io/core-web-vitals"]},{"id":"performance-inp-long-task-breakup","section":"performance","title":"Event handlers over 50 ms break work into smaller tasks / yield","severity":"medium","stage":"build","automatable":false,"check_type":"manual","what":"Any event callback (onclick/onsubmit/onchange/keydown) running over 50 ms on the main thread must split work and yield using scheduler.yield(), setTimeout(0), requestAnimationFrame, or React startTransition/useTransition.","why":"A long synchronous handler blocks the main thread and delays the next paint, extending INP by hundreds of ms from the interaction until the frame renders.","fix":"Audit handlers in island components. Prefer await scheduler.yield() but include a cross-browser fallback (await new Promise(r => setTimeout(r, 0))) since scheduler.yield() is Chrome 129+ only (not Firefox/Safari, not Baseline). For React 18+ mark non-urgent state updates with startTransition. Move heavy sort/filter/search work off the keystroke path (debounce + yield).","how_to_check":"In the console register a PerformanceObserver for type 'longtask', interact with the page, and assert no interaction produces a task > 50 ms. In DevTools Performance, record interactions and look for red Long Task markers on the main thread.","common_mistakes":"Sorting/filtering a list synchronously on every keystroke; synchronous XHR in a handler; setState with a large payload synchronously; using scheduler.yield() without a fallback.","platform_notes":"No platform difference.","sources":["https://web.dev/articles/optimize-inp","https://developer.chrome.com/blog/use-scheduler-yield"]},{"id":"performance-lighthouse-score-90-plus","section":"performance","title":"Lighthouse Performance score is 90+ on both mobile and desktop","severity":"medium","stage":"post-launch","automatable":true,"check_type":"lighthouse","what":"The composite Lighthouse Performance score (FCP, LCP, TBT, CLS, Speed Index) must be 90+ on both mobile (throttled) and desktop, tested against the deployed build — not localhost.","why":"A 90+ mobile score means all CWV thresholds pass in lab conditions; below 90, at least one metric is likely failing and will drag down field CWV.","fix":"Astro content sites routinely score 90-100 with output: 'static' and minimal islands. Set site, run astro build, and test the built output via a preview deployment (not localhost, which skips CDN latency/compression/HTTP-2).","how_to_check":"PSI API: GET .../runPagespeed?url=<URL>&strategy=mobile&category=performance and assert lighthouseResult.categories.performance.score * 100 >= 90; repeat with strategy=desktop.","common_mistakes":"Testing only desktop (20-30 points higher); testing on localhost; ignoring the mobile score that reflects the median user.","platform_notes":"No platform difference for the score.","sources":["https://www.corewebvitals.io/core-web-vitals","https://web.dev/articles/optimize-lcp"]},{"id":"performance-loaf-rum-monitoring","section":"performance","title":"RUM with web-vitals attribution / LoAF is set up for INP root-cause monitoring","severity":"medium","stage":"post-launch","automatable":false,"check_type":"manual","what":"Real-user monitoring (the web-vitals v4+ attribution build, or a RUM tool like DebugBear or Sentry) captures Long Animation Frame (LoAF) data alongside INP events so regressions can be attributed to specific scripts/handlers in production.","why":"INP is a ranking factor and ~43% of sites still fail the 200 ms threshold. The LoAF API (Chrome 116+) is the only mechanism providing per-frame breakdowns (render/layout time + contributing script URLs); without it you see the symptom but not the cause, and lab tools cannot measure field INP at all.","fix":"npm i web-vitals@^4. In a client:load inline island: import { onINP } from 'web-vitals/attribution'; onINP(({ value, attribution }) => sendToAnalytics({ value, loafScripts: attribution.longAnimationFrameEntries?.flatMap(e => e.scripts) ?? [] })). Use client:load (not client:idle, which misses early interactions) and send data to a backend for aggregation.","how_to_check":"After interaction, confirm the analytics payload contains longAnimationFrameEntries with duration and scripts; in DevTools Performance, record an interaction and confirm the 'Long animation frames' section shows frames over 50 ms.","common_mistakes":"Using the non-attribution web-vitals build (no LoAF); loading the RUM script with client:idle; only console.log-ing instead of aggregating server-side.","platform_notes":"Client-side JS integration only — identical on Cloudflare Pages and Vercel.","sources":["https://github.com/GoogleChrome/web-vitals","https://requestmetrics.com/web-performance/long-animation-frame-loaf/"]},{"id":"performance-no-redirect-chains","section":"performance","title":"No unnecessary redirect chains on the critical path","severity":"medium","stage":"post-launch","automatable":true,"check_type":"redirect","what":"The page and its LCP resource should go through 0-1 redirects. Each redirect adds at least one round trip to TTFB.","why":"Each redirect costs 50-300 ms; a 2-hop chain adds 100-600 ms before the first HTML byte, pushing LCP above 2.5 s on mobile.","fix":"Set trailingSlash: 'never' or 'always' consistently in astro.config.mjs and match it in the platform redirect rules to avoid double redirects; redirect HTTP->HTTPS and www<->apex in a single hop directly to the final URL. Cloudflare Pages: _redirects file. Vercel: vercel.json redirects array.","how_to_check":"curl -sI -L --max-redirs 10 -w '%{num_redirects}' <URL> -o /dev/null must return 0 or 1; for the LCP image, curl -sI -L <IMAGE_URL> should show a single HTTP response.","common_mistakes":"Astro trailingSlash:'always' clashing with a platform that strips slashes (double redirect); configuring both www and apex without a direct single-hop redirect.","platform_notes":"Cloudflare Pages: _redirects. Vercel: vercel.json redirects. Keep trailing-slash behavior consistent between Astro and platform.","sources":["https://web.dev/articles/optimize-lcp","https://realmorrisliu.com/thoughts/fixing-astro-seo-cloudflare-trailing-slash/"]},{"id":"performance-vercel-isr-not-stale","section":"performance","title":"Vercel ISR does not serve SEO-critical pages indefinitely stale","severity":"medium","stage":"post-launch","automatable":true,"check_type":"http_header","what":"When using @astrojs/vercel with ISR, pages are edge-cached indefinitely after first render unless an expiration is set. SEO-critical pages (sitemap, robots, canonical pages) must have a bounded expiration or be excluded from ISR.","why":"Stale ISR responses can serve Googlebot outdated titles, canonical URLs, or structured data, causing stale metadata to be indexed.","fix":"In astro.config.mjs: adapter: vercel({ isr: { expiration: 3600, exclude: ['/sitemap-index.xml', '/sitemap-0.xml', '/robots.txt', /^\\/api\\/.+/] } }) — exclude supports string paths and RegExp. Prefer export const prerender = true for sitemap/robots so they are static and not subject to ISR; use bypassToken + the Vercel revalidation API for on-demand invalidation.","how_to_check":"curl -sI https://example.com/some-page | grep -i x-vercel-cache (HIT/MISS, not BYPASS) and curl ... | grep -i age (bounded, less than expiration). Confirm the sitemap is not served as a stale ISR response.","common_mistakes":"Enabling isr: true with no expiration (cached until next deploy); including sitemap/robots in the ISR cache.","platform_notes":"Vercel-specific. The Cloudflare Pages equivalent is edge caching via Cache-Control / Cache Rules, not ISR.","sources":["https://docs.astro.build/en/guides/integrations-guide/vercel/","https://vercel.com/docs/frameworks/frontend/astro"]},{"id":"performance-content-visibility-offscreen","section":"performance","title":"Consider content-visibility:auto for large off-screen sections","severity":"low","stage":"build","automatable":false,"check_type":"manual","what":"Apply content-visibility: auto (with contain-intrinsic-size) to large, independent below-fold sections (long FAQs, comment lists) to defer their layout/paint/composite until they approach the viewport.","why":"It skips layout, style, paint, and compositing for off-screen content, freeing the main thread earlier and improving INP. It became Baseline Newly Available on 15 September 2025 (Chrome/Edge 85+, Firefox 125+, Safari 18+).","fix":"In component <style>: .faq { content-visibility: auto; contain-intrinsic-size: 0 500px; }. The contain-intrinsic-size placeholder prevents scrollbar jumps before the section renders. Do not apply to subtrees containing position: sticky/fixed children — they do not work inside the containment boundary.","how_to_check":"curl -sL <URL> | grep 'content-visibility' to confirm it is applied to appropriate sections; in DevTools Rendering with Paint flashing, off-screen sections should only flash on entering the viewport, not on initial load (Lighthouse does not audit this directly).","common_mistakes":"Applying it to sections with sticky children; omitting contain-intrinsic-size, causing scrollbar jumps.","platform_notes":"No platform difference; safe to use without polyfill as of late 2025.","sources":["https://web.dev/articles/content-visibility","https://caniuse.com/css-content-visibility"]},{"id":"performance-prefetch-prerender-navigation","section":"performance","title":"Astro prefetch (and optional client prerender) enabled for instant internal navigation","severity":"low","stage":"build","automatable":true,"check_type":"html_element","what":"Astro's built-in prefetch preloads internal links on hover/focus/viewport, and optionally experimental.clientPrerender upgrades that to full Speculation Rules prerendering in Chromium (with prefetch fallback in Firefox/Safari), making subsequent navigations feel near-instant.","why":"Prefetching/prerendering drops perceived LCP and TTFB on navigation toward zero when the next page is already cached, a meaningful perceived-performance win for content sites with heavy internal linking.","fix":"In astro.config.mjs set prefetch: { prefetchAll: true } (or prefetch: true with per-link data-astro-prefetch). With <ClientRouter /> prefetchAll defaults to true. For full prerender add experimental: { clientPrerender: true } (requires prefetch) and tune eagerness per link (data-astro-prefetch='viewport'|'moderate'|...). Use moderate/conservative on large/dynamic sites; never prerender authenticated or mutation-on-load routes.","how_to_check":"Confirm prefetch is not false in astro.config.mjs; in rendered HTML check for data-astro-prefetch attributes (and a <script type=speculationrules> tag in Chromium builds when clientPrerender is on). In DevTools, hovering a link should trigger a low-priority prefetch request.","common_mistakes":"prefetchAll on a site with thousands of posts (excess bandwidth); prerendering routes that run analytics/session writes or require auth cookies; using 'immediate' eagerness site-wide.","platform_notes":"Works on both Cloudflare Pages and Vercel; for SSR routes on Cloudflare, prerender triggers a real Worker invocation — keep such routes idempotent and watch paid compute.","sources":["https://docs.astro.build/en/guides/prefetch/","https://docs.astro.build/en/reference/experimental-flags/client-prerender/"]},{"id":"images-explicit-width-height-cls","section":"images","title":"Every image has explicit width and height (or aspect-ratio)","severity":"critical","stage":"build","automatable":true,"check_type":"html_element","what":"All <img> elements, including those in Markdown/MDX body content, must carry explicit width and height attributes (or an equivalent CSS aspect-ratio) so the browser reserves space before the image loads.","why":"Missing intrinsic dimensions are the single largest cause of Cumulative Layout Shift (CLS): the page reflows when each image arrives. CLS is a Core Web Vitals ranking signal and must stay below 0.1.","fix":"Use <Image /> / <Picture /> from astro:assets — width/height are inferred automatically for local images imported from src/assets/. For remote images, pass explicit width and height props or enable inferSize (Astro 4.4+; requires domain authorization in image.remotePatterns/domains as of 5.17.3+). In Markdown body content, use MDX so you can use the <Image /> component instead of bare ![]() or <img>. Never set CSS width:100% without a matching height or aspect-ratio.","how_to_check":"HTML audit: parse every <img> and assert both width and height attributes are present and numeric (curl -sL <URL> | grep -oP '<img[^>]+>' | grep -v 'width=' should return zero rows). Confirm the Lighthouse 'Image elements do not have explicit width and height' audit passes and CLS < 0.1.","common_mistakes":"Raw <img> in layouts with no dimensions; CSS width:100% with no aspect-ratio/height; remote images without inferSize and no manual dimensions.","platform_notes":"No platform difference.","sources":["https://docs.astro.build/en/guides/images/","https://web.dev/articles/optimize-cls"]},{"id":"images-descriptive-alt-text","section":"images","title":"Informative images have descriptive alt text; decorative images use alt=\"\"","severity":"high","stage":"build","automatable":true,"check_type":"html_element","what":"Every informative image must have a meaningful, non-empty alt attribute that describes its content/function. Purely decorative images must use alt=\"\" (empty, but present) so assistive tech and crawlers skip them.","why":"Alt text is the primary signal Google uses to understand image content for Google Images ranking and accessibility (WCAG). Missing alt hurts a11y and image SEO; alt=\"\" on informative images discards a ranking signal; verbose/keyword-stuffed alt is treated as spam.","fix":"<Image> from astro:assets requires the alt prop and will error at build if omitted — pass alt={...} with a concise human description, or alt=\"\" explicitly for decorative imagery. Source alt from CMS/frontmatter fields rather than hardcoding when content-driven.","how_to_check":"HTML audit: assert every <img> has an alt attribute (present, including empty), and that informative images (hero/product/inline content) have non-empty alt. Lighthouse 'Image elements have [alt] attributes' audit must pass.","common_mistakes":"alt='' on informational images; missing alt on bare <img> in Markdown; filename-as-alt or keyword stuffing.","platform_notes":"No platform difference.","sources":["https://docs.astro.build/en/guides/images/","https://developers.google.com/search/docs/appearance/google-images"]},{"id":"images-lazy-load-below-fold","section":"images","title":"Below-the-fold images are lazy-loaded with async decoding","severity":"high","stage":"build","automatable":true,"check_type":"lighthouse","what":"Every image not in the initial viewport must have loading='lazy' (defer the network fetch) and decoding='async' (avoid blocking the main thread during decode).","why":"Lazy-loading offscreen images stops the browser from fetching dozens of images at load, reducing initial page weight and freeing bandwidth for the LCP image.","fix":"Astro's <Image>/<Picture> already apply loading='lazy' and decoding='async' by default — for blog card grids and offscreen content, keep the defaults (do not override to eager). Only the single LCP hero should be overridden to eager.","how_to_check":"Lighthouse 'Defer offscreen images' must pass. HTML check: every <img> except the LCP hero has loading='lazy'.","common_mistakes":"Setting loading='eager' globally to fix a hero issue and never resetting offscreen images; bare <img> in Markdown body with no loading attribute.","platform_notes":"No platform difference.","sources":["https://docs.astro.build/en/guides/images/","https://web.dev/articles/optimize-lcp"]},{"id":"images-lcp-eager-priority","section":"images","title":"LCP/hero image is eager-loaded with high fetch priority","severity":"high","stage":"build","automatable":true,"check_type":"lighthouse","what":"The largest above-the-fold image (hero/featured) must NOT be lazy-loaded; it should be eager with high fetch priority so the browser discovers and fetches it immediately. Exactly one image per page should get this treatment — the LCP element.","why":"Lazy-loading or de-prioritizing the LCP image delays its discovery and significantly worsens LCP, a Core Web Vitals ranking factor (target < 2.5s).","fix":"Use the stable priority prop (Astro 5.10+): <Image src={hero} alt='...' priority /> — it sets loading='eager', decoding='sync', and fetchpriority='high' together. Apply it to only the one LCP image. Pre-5.10: manually set loading='eager' fetchpriority='high'. Avoid a shared wrapper that forces loading='lazy' on all images without an override for the hero.","how_to_check":"Run Lighthouse/DevTools Performance, identify the LCP element, and assert it is NOT lazy-loaded and carries fetchpriority='high'; LCP must be < 2.5s. HTML check: the hero <img> has loading != 'lazy' and fetchpriority='high'.","common_mistakes":"Blanket loading='lazy' via a shared component with no hero override; applying priority to multiple images per page.","platform_notes":"fetchpriority is a browser hint and behaves identically on Cloudflare Pages and Vercel.","sources":["https://docs.astro.build/en/guides/images/","https://astro.build/blog/astro-5100/","https://web.dev/articles/optimize-lcp"]},{"id":"images-modern-formats-avif-webp","section":"images","title":"Serve content images as AVIF/WebP with a JPEG/PNG fallback","severity":"high","stage":"build","automatable":true,"check_type":"http_header","what":"Content images (especially hero/large images) must be delivered as AVIF (preferred) or WebP rather than raw JPEG/PNG. Use <Picture> listing formats in priority order ['avif','webp'] with a JPEG/PNG fallback for the bare <img>.","why":"AVIF is ~50% smaller than JPEG at equal quality and WebP ~25-35% smaller, directly cutting LCP resource-load time and bandwidth. AVIF browser support is ~93-95% as of early 2026 (Chrome 85+, Firefox 93+, Safari 16+); the JPEG/PNG fallback covers pre-iOS-16 devices.","fix":"<Picture src={img} formats={['avif','webp']} fallbackFormat='jpg' alt='...' /> — Astro's Sharp service generates each format at build time and emits them as <source> elements in order (browser picks the first it supports, so AVIF must be listed first). <Image> alone defaults to WebP single-format. Always import from src/assets/, never serve from public/.","how_to_check":"Crawl all img src/srcset and <source> URLs, send HEAD requests, and assert the Content-Type response header is image/avif or image/webp for large content images. Confirm a <source type='image/avif'> appears first in <picture>. Lighthouse 'Serve images in next-gen formats' must pass.","common_mistakes":"Listing JPEG before AVIF/WebP in the formats array (browser then always picks JPEG); serving from public/ (no conversion); using <Image> single-format when an AVIF+WebP fallback chain is wanted.","platform_notes":"Cloudflare Pages static and Vercel static serve build output as-is, so AVIF/WebP must be generated at build time. With the Vercel adapter (SSR), /_vercel/image negotiates AVIF/WebP via the Accept header on demand.","sources":["https://docs.astro.build/en/guides/images/","https://caniuse.com/avif","https://developers.google.com/search/docs/appearance/google-images"]},{"id":"images-responsive-srcset-sizes","section":"images","title":"Variable-width images use responsive srcset and accurate sizes","severity":"high","stage":"build","automatable":true,"check_type":"html_element","what":"Images that render at different widths across viewports (heroes, blog thumbnails, cards) must ship a srcset with 2-3+ width variants plus a sizes attribute that accurately describes the CSS layout width at each breakpoint, so the browser fetches the smallest adequate image.","why":"Serving a 1600px image to a 375px mobile viewport wastes 4-8x bandwidth and directly inflates LCP, where failures are most common. Lighthouse / PageSpeed flag this as 'Properly size images'.","fix":"Option A (idiomatic, stable since 5.10.0): set a layout attr — <Image layout='constrained' width={800} src={img} alt='...' /> — and enable image.responsiveStyles: true in astro.config.mjs (or set image.layout globally) so Astro auto-generates srcset/sizes and matching CSS. Option B (manual): <Image src={img} widths={[400,800,1200,1600]} sizes='(max-width:768px) 100vw, 800px' alt='...' />. The same widths/sizes props work on <Picture>.","how_to_check":"Parse HTML: assert content images have a srcset with at least 2 width descriptors (e.g. '400w, 800w') and a sizes attribute that is not a blanket '100vw' for non-full-width images. Throttle DevTools to a 375px viewport and confirm the narrowest covering variant is fetched. Lighthouse 'Properly size images' must pass.","common_mistakes":"widths without an accurate sizes value (over-fetches); sizes='100vw' on a sidebar/card image that only occupies a fraction of the viewport; forgetting that responsiveStyles needs the layout attr to activate.","platform_notes":"Static (Cloudflare/Vercel): srcset entries are hashed build-time assets. Vercel SSR: srcset may use on-demand /_vercel/image?url=...&w=... URLs — ensure the Vercel adapter is installed.","sources":["https://docs.astro.build/en/guides/images/","https://docs.astro.build/en/reference/modules/astro-assets/","https://astro.build/blog/astro-5100/"]},{"id":"images-use-astro-assets-component","section":"images","title":"Significant images use <Image>/<Picture> from astro:assets, not bare <img>","severity":"high","stage":"build","automatable":true,"check_type":"html_element","what":"Local and remote content images should be rendered through the Astro <Image> or <Picture> component rather than bare <img> tags. This is the foundation that enables dimension inference, format conversion, responsive srcset, and required alt enforcement.","why":"<Image>/<Picture> auto-infer width/height (prevents CLS), generate WebP/AVIF variants and responsive srcset (improves LCP), and enforce an alt attribute. Bare <img> tags and images served from public/ bypass the optimization pipeline entirely and ship the original, unoptimized file.","fix":"import { Image, Picture } from 'astro:assets' and import local images from src/assets/ (not public/). For remote/CDN images, configure image.domains or image.remotePatterns in astro.config. Use <Image src={img} alt='...' /> for single-format output, <Picture> when you need a multi-format source set.","how_to_check":"Build/HTML audit: for content images, assert the rendered src points to an optimized /_astro/ path (static) or the platform optimizer endpoint (e.g. /_vercel/image) rather than a raw /public path, and flag any bare <img> with an original .jpg/.png src in .astro templates.","common_mistakes":"Using <img src='/photo.jpg'> from public/ which skips Sharp; forgetting to configure remotePatterns for CDN images; using bare <img> in Markdown instead of MDX + <Image>.","platform_notes":"Cloudflare Pages SSR: Sharp is incompatible with the workerd runtime — set the adapter imageService to 'cloudflare-binding' (default on recent adapters) or 'compile'. Vercel adapter auto-configures its image optimization endpoint.","sources":["https://docs.astro.build/en/guides/images/","https://docs.astro.build/en/reference/modules/astro-assets/"]},{"id":"images-descriptive-filenames","section":"images","title":"Image filenames are descriptive and kebab-cased","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"body_regex","what":"Image source files must use short, meaningful, hyphen-separated names (e.g. golden-retriever-puppy.webp), not IMG00023.jpg, image1.jpg, or photo_FINAL_v3.jpeg.","why":"Google explicitly uses the filename to understand an image's subject for Google Images ranking. Generic names provide no signal; descriptive names reinforce page topic.","fix":"Rename files in src/assets/ before import. Astro appends a content hash at build (golden-retriever-puppy.Bx9KLmQp.webp) but preserves the descriptive stem, which is what Google reads. For remote/CMS images, ensure descriptive stored filenames or rewrite the URL path; the descriptive name must survive in the ?url= param of any optimizer endpoint.","how_to_check":"Crawl all img src / source srcset URLs, extract the filename stem (before the hash), and assert it matches /^[a-z][a-z0-9-]{2,}\\.(avif|webp|jpg|jpeg|png|svg)$/i and is not a generic token (image, photo, img, banner, hero, pic, untitled, IMG\\d+).","common_mistakes":"Stock-download names (shutterstock_12345.jpg); spaces (become %20); CamelCase; trusting UUID-based CDN slugs.","platform_notes":"Cloudflare Images and Vercel Image Optimization expose the original URL in the ?url= parameter — that filename is what Google indexes, so it must be descriptive.","sources":["https://developers.google.com/search/docs/appearance/google-images"]},{"id":"images-quality-tuning","section":"images","title":"Tune WebP/AVIF quality (≈75-85), never quality 100","severity":"medium","stage":"build","automatable":true,"check_type":"lighthouse","what":"Set explicit encoder quality for output: WebP ~80 and AVIF ~60-75. Do not ship quality 100, and do not rely on the Sharp AVIF default of 50 for content images (it can show artifacts on text). Quality ~80 is the perceptual sweet spot.","why":"Image weight is a top LCP contributor: a 600KB image where 80KB looks identical wastes bandwidth and degrades Core Web Vitals. Lighthouse/PageSpeed flags this as 'Efficiently encode images'.","fix":"Set codec defaults in astro.config.mjs: image: { service: { entrypoint: 'astro/assets/services/sharp', config: { webp: { quality: 80 }, avif: { quality: 65 } } } }. Override per image with the quality prop: <Image src={img} quality={85} alt='...' />. Do NOT reference squooshImageService() — Squoosh was deprecated in Astro 4.14 and removed in Astro 5.0 and will break the build; use the default Sharp service.","how_to_check":"Lighthouse 'Efficiently encode images' must report 0 violations (estimated savings < ~100KB). Spot-check built files: ls -la dist/_astro/*.webp dist/_astro/*.avif — a ~1200px WebP hero should land roughly in 50-150KB and content images stay under ~200KB.","common_mistakes":"Leaving Sharp's AVIF default of 50 for content/text images; setting quality=100 for 'max quality'; using the removed squooshImageService().","platform_notes":"Vercel Image Optimization defaults to q=75 in /_vercel/image URLs; Cloudflare Polish applies its own quality reduction. Astro Sharp defaults: WebP 80, AVIF 50.","sources":["https://docs.astro.build/en/reference/modules/astro-assets/","https://sharp.pixelplumbing.com/api-output/","https://github.com/withastro/astro/pull/11780"]},{"id":"images-sitemap-entries","section":"images","title":"Image sitemap entries for key content images","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"sitemap","what":"The XML sitemap includes <image:image> child elements (via the xmlns:image extension) for pages with indexable, SEO-significant images (hero, product, gallery), each with at least <image:loc> and ideally <image:title>.","why":"Google Image Search is a meaningful secondary traffic source. Image sitemap entries help Googlebot discover images it may miss during crawl (e.g. lazily/JS-loaded) and improve image indexing eligibility.","fix":"@astrojs/sitemap does not emit <image:image> automatically. Add a custom endpoint at src/pages/sitemap-images.xml.ts: iterate getCollection('blog'), read each entry's heroImage, and emit an <image:image><image:loc>...</image:loc><image:title>...</image:title></image:image> nested in the parent <url>. Declare xmlns:image='http://www.google.com/schemas/sitemap-image/1.1' and return Content-Type: application/xml. Submit it in Search Console.","how_to_check":"GET /sitemap-images.xml, parse as XML, and assert: the xmlns:image namespace is declared; at least one <image:image> per content page; every <image:loc> is an absolute HTTPS URL; <image:title> is non-empty. Confirm no parse errors in GSC Sitemaps.","common_mistakes":"Omitting the xmlns:image declaration (invalid sitemap); listing images blocked by robots.txt; including cross-domain images without a Sitemap declaration on that domain; including decorative images.","platform_notes":"No platform-specific caveats; submit the image sitemap URL separately in Google Search Console.","sources":["https://developers.google.com/search/docs/crawling-indexing/sitemaps/image-sitemaps","https://docs.astro.build/en/guides/integrations-guide/sitemap/"]},{"id":"urls-canonical-not-blocked-by-robots","section":"urls","title":"Canonical pages are not blocked in robots.txt","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"robots","what":"No URL declared as a canonical (via rel=canonical or sitemap <loc>) is matched by a robots.txt Disallow rule.","why":"If a canonical URL is blocked in robots.txt, Googlebot cannot fetch the page to read its canonical tag and the page is dropped from the index. This is one of the most damaging and hard-to-diagnose misconfigurations.","fix":"Verify public/robots.txt (copied verbatim into the build) contains no Disallow that covers indexable canonical pages. The classic failure is a leftover `Disallow: /` from staging/development reaching production.","how_to_check":"GET /robots.txt, parse Disallow rules, and for each canonical URL in the sitemap assert it is NOT matched by any Disallow rule (use a parser such as the `robots-parser` npm package). Flag any `Disallow: /`.","common_mistakes":"Deploying a staging `Disallow: /`; adding `Disallow: /blog/` to hide drafts but blocking published posts too.","sources":["https://developers.google.com/search/docs/crawling-indexing/robots/intro","https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls"]},{"id":"urls-hreflang-annotations","section":"urls","title":"Multilingual pages carry complete, reciprocal hreflang annotations with x-default","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"html_head","what":"Every localized page includes <link rel=\"alternate\" hreflang=\"xx\"> for all language variants (including a self-referencing one) plus one hreflang=\"x-default\"; all hrefs are absolute HTTPS URLs that return 200 (no redirects), annotations are bidirectional, and the page's canonical is self-referencing (per-locale), not pointing at the default-locale page.","why":"Without complete hreflang Google may serve the wrong language or collapse variants as duplicates. Missing reciprocity, relative/protocol-relative hrefs, hrefs that 301, or a canonical pointing to a different locale all cause Google to ignore the annotations entirely.","fix":"Set `site` in astro.config.mjs, then in the shared layout loop over i18n.locales using `getAbsoluteLocaleUrl(locale, Astro.url.pathname)` from astro:i18n to emit every alternate plus x-default (`getAbsoluteLocaleUrl(i18n.defaultLocale, path)`); the shared-layout loop guarantees reciprocity. Keep canonical self-referencing via `new URL(Astro.url.pathname, Astro.site).href`. Note getAbsoluteLocaleUrl returns a relative URL if `site` is unset.","how_to_check":"GET each localized page: assert hreflang tags exist for every configured locale + x-default, all hrefs are absolute https://, each href GETs to 200 (not 3xx), and the canonical equals the page's own locale URL. For each referenced URL, fetch it and assert a reciprocal hreflang back to the original.","common_mistakes":"hreflang only on the default locale; missing self/x-default; using getRelativeLocaleUrl or protocol-relative (//example.com/fr); hreflang href that 301-redirects; a layout that strips the locale from the canonical so all pages canonicalize to the default locale.","sources":["https://developers.google.com/search/docs/specialty/international/localized-versions","https://docs.astro.build/en/guides/internationalization/","https://docs.astro.build/en/reference/modules/astro-i18n/"]},{"id":"urls-http-to-https-redirect","section":"urls","title":"All HTTP traffic redirects to HTTPS with a 301/308","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"Every HTTP (port 80) request is permanently redirected to its HTTPS equivalent.","why":"HTTP and HTTPS versions are distinct URLs; without enforcement, link equity and crawl signals split across them. HTTPS is also a (minor) confirmed ranking signal.","fix":"Handled at the hosting layer. Both Cloudflare Pages and Vercel enforce HTTPS redirects automatically for custom domains. Verify a custom _redirects rule or upstream reverse proxy is not bypassing it.","how_to_check":"GET http://example.com/ over plain HTTP -> assert status 301/308 with Location `https://example.com/`.","common_mistakes":"A reverse proxy/load balancer that terminates TLS and serves HTTP without redirecting; a misconfigured _redirects rule overriding the platform default.","platform_notes":"Automatic on both Cloudflare Pages and Vercel for custom domains; if a custom proxy sits in front, configure HTTPS enforcement there.","sources":["https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls"]},{"id":"urls-no-redirect-loops","section":"urls","title":"No redirect loops","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"No URL redirects to itself or forms a cycle (A -> B -> A).","why":"Redirect loops return ERR_TOO_MANY_REDIRECTS to users and crawlers, making pages completely inaccessible.","fix":"Avoid stacking conflicting redirect layers. The classic cause is Cloudflare 'Always Use HTTPS' plus a redundant HTTP->HTTPS rule in _redirects, or a www<->apex rule duplicated across dashboard Redirect Rules and _redirects, or a Cloudflare proxy in front of Vercel with both enforcing HTTPS. Consolidate to a single redirect layer.","how_to_check":"curl -L --max-redirs 20 -o /dev/null -w '%{http_code}' https://example.com/ -> if curl aborts with 'Too many redirects', a loop exists. Repeat starting from http:// and from the www host.","common_mistakes":"Double HTTPS enforcement (Cloudflare 'Always Use HTTPS' + a Vercel/Cloudflare proxy redirect); trailing-slash rules layered on top of platform defaults.","platform_notes":"Most common on Cloudflare Pages combining multiple redirect mechanisms, and on a Cloudflare-proxy-in-front-of-Vercel setup.","sources":["https://vercel.com/kb/guide/resolve-err-too-many-redirects-when-using-cloudflare-proxy-with-vercel"]},{"id":"urls-redirects-are-http-not-meta-refresh","section":"urls","title":"Redirects are real HTTP 301/308, never HTML meta-refresh","severity":"critical","stage":"build","automatable":true,"check_type":"redirect","what":"All permanent redirects are served as HTTP 301 (or 308 for non-GET) responses, not HTML <meta http-equiv=\"refresh\"> stubs. Critically, Astro's `redirects` config produces server-side 301s ONLY when an SSR/platform adapter is active; in static output without an adapter it generates meta-refresh HTML files.","why":"Meta-refresh transfers far less link equity than an HTTP 301, can be treated as a soft 404, and delays users. This is the single most common Astro redirect foot-gun.","fix":"SSR with @astrojs/cloudflare or @astrojs/vercel: astro.config.mjs `redirects: { '/old': '/new' }` is translated to real HTTP 301/308. Static output without an adapter: do NOT rely on astro.config redirects for SEO-critical moves; instead use public/_redirects (Cloudflare, append `301`) or vercel.json `redirects` (Vercel). Optionally set `build: { redirects: false }` to stop Astro emitting meta-refresh stubs that duplicate your platform rules.","how_to_check":"For every defined redirect: `curl -sI https://example.com/old` -> assert status 301/308 with correct Location and NO HTML body. If a 200 with a body is returned, grep the body for `<meta http-equiv=\"refresh\"` indicating a static meta-refresh stub.","common_mistakes":"Assuming astro.config.mjs redirects always emit 301s (they do not without an adapter); on Cloudflare Pages SSR, _redirects is bypassed for routes served by Pages Functions so redirects must be handled in middleware/Worker code.","platform_notes":"Cloudflare Pages: _redirects applies to static assets only and is bypassed under SSR. Vercel: @astrojs/vercel adapter translates config redirects to HTTP redirects in SSR; static mode needs explicit vercel.json.","sources":["https://docs.astro.build/en/guides/routing/","https://developers.cloudflare.com/pages/configuration/redirects/","https://vercel.com/docs/routing/redirects"]},{"id":"urls-self-referencing-canonical","section":"urls","title":"Self-referencing canonical tag on every page","severity":"critical","stage":"build","automatable":true,"check_type":"html_head","what":"Every HTML page includes exactly one <link rel=\"canonical\"> in <head> whose href is an absolute HTTPS URL pointing to that page's own preferred URL (correct scheme, host, and trailing-slash form), with query strings stripped.","why":"Canonicals are the baseline defense against duplicate content from trailing-slash, www/non-www, http/https, and parameter variants. Without one, Google picks a canonical from internal links and sitemaps and may choose a URL you do not want, splitting link equity.","fix":"In your base layout (e.g. src/layouts/BaseHead.astro) add `<link rel=\"canonical\" href={new URL(Astro.url.pathname, Astro.site).href} />`. Using `.pathname` (not `Astro.url.href`) keeps the URL absolute via Astro.site and automatically drops query parameters. Set `site` in astro.config.mjs to the production domain. For dynamic routes with a different preferred URL, pass an explicit canonical prop. Paginated pages should self-canonicalize (page 2 -> page 2), not all point to page 1.","how_to_check":"GET each sampled page, parse <head>: assert exactly one <link rel=\"canonical\"> exists, its href matches `^https://`, contains no `?`, and equals the page's own served URL byte-for-byte (including trailing-slash form). `curl -s https://example.com/about/ | grep 'rel=\"canonical\"'` should return the exact self URL.","common_mistakes":"Using Astro.url.href or Astro.request.url (includes query/UTM params in SSR); relative hrefs; setting canonical via client-side JS so it is absent in pre-rendered HTML; canonical left pointing at a *.pages.dev / *.vercel.app preview or staging domain; pointing all paginated pages to page 1.","platform_notes":"Ensure Astro `site` uses the production custom domain, not the *.pages.dev (Cloudflare) or *.vercel.app (Vercel) preview URL.","sources":["https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls","https://docs.astro.build/en/reference/configuration-reference/","https://joost.blog/astro-seo-complete-guide/"]},{"id":"urls-trailing-slash-consistency","section":"urls","title":"Trailing-slash policy is consistent across Astro config, platform, canonicals, and links","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"A page is reachable at only one trailing-slash form: the other 301/308-redirects to it. Astro `trailingSlash` and `build.format` align with the host's serving behavior, and canonicals, sitemap <loc>, and internal links all use that same form.","why":"Dual-URL access (/about and /about/) is duplicate content. Misalignment causes 308 redirect loops on Cloudflare or silent dual-200 serving on Vercel, and a build.format/trailingSlash mismatch makes canonicals point to a different URL than the one served, splitting equity.","fix":"Cloudflare Pages no-slash sites: `build: { format: 'file' }` + `trailingSlash: 'never'` (serves /about.html as /about with no redirect; the default 'directory' format 308-redirects /about -> /about/). Vercel: set `trailingSlash` explicitly (true or false, never undefined) in vercel.json AND a matching Astro `trailingSlash` — leaving vercel.json undefined serves both forms at 200. Note: with format 'file', Astro.url.pathname includes `.html`, which must be stripped when building canonicals.","how_to_check":"GET /about AND GET /about/ -> exactly one returns 200, the other 301/308 to the canonical form; both must never be 200. Then confirm the canonical href, sitemap <loc>, and internal hrefs all match that form.","common_mistakes":"Leaving trailingSlash undefined in vercel.json (dual 200s); `trailingSlash:'never'` with default `build.format:'directory'` on Cloudflare (extra 308 hop); hardcoded internal links without the trailing slash while canonicals have it. Astro v5 has documented edge cases (GitHub issue #12833) between trailingSlash/build.format/Astro.url — verify against actual dist output, not config alone.","platform_notes":"Cloudflare Pages: 'directory' format always 308-redirects to trailing-slash; 'file' serves clean no-slash URLs. Vercel default (undefined trailingSlash) serves both forms without redirect.","sources":["https://realmorrisliu.com/thoughts/fixing-astro-seo-cloudflare-trailing-slash/","https://mirzapandzo.com/astro-vercel-trailingslash-and-redirects","https://vercel.com/docs/project-configuration/vercel-json"]},{"id":"urls-www-nonwww-single-domain","section":"urls","title":"www and non-www redirect to a single canonical domain","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"Exactly one of https://example.com or https://www.example.com serves content (200); the other 301/308-redirects to it for all paths, and Astro `site` matches the chosen form.","why":"Googlebot treats www and non-www as separate hosts. Serving identical content on both is site-wide duplicate content that splits PageRank across two domains.","fix":"This is a platform/DNS concern, not Astro config. Cloudflare Pages: `public/_redirects` is path-only and cannot match by hostname, so configure a dashboard Redirect Rule (or Bulk Redirect) for the www->apex (or apex->www) redirect. Vercel: add both domains in Project Settings > Domains and mark one primary; Vercel issues the redirect (308) automatically. Ensure Astro `site` uses the canonical form.","how_to_check":"curl -I against the non-preferred host -> assert 301/308 with a Location header pointing to the canonical host. GET the preferred host -> assert 200. Verify a subpath redirects too, not just the homepage.","common_mistakes":"Both variants serving 200 with no redirect; redirecting only the homepage; using 302 instead of 301/308; trying to do www->apex in Cloudflare _redirects (host matching is unsupported there).","platform_notes":"Cloudflare Pages: use dashboard Redirect Rules (not _redirects) for host-based www<->apex. Vercel: handled in Settings > Domains primary-domain selection.","sources":["https://developers.cloudflare.com/pages/configuration/redirects/","https://vercel.com/docs/routing/redirects","https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls"]},{"id":"urls-canonical-no-chain","section":"urls","title":"Canonical tags do not chain (A -> B -> C)","severity":"high","stage":"pre-launch","automatable":true,"check_type":"body_regex","what":"If page A canonicalizes to B, page B must canonicalize to itself, not to a third URL. No canonical chains.","why":"Google may not fully resolve canonical chains, leaving ranking signals diluted or the wrong page indexed. Chains typically emerge when a CMS slug changes but the old canonical is not updated.","fix":"Audit at build time: crawl all pages, map each page's URL to its declared canonical, then verify the canonical target's own canonical points to itself. Update stale CMS canonicals and remove canonicals imported from an originating domain.","how_to_check":"For each page, read its canonical URL, GET that URL, read its canonical, and assert the second canonical equals itself (no second hop).","common_mistakes":"Renaming a slug without updating its canonical; importing content with pre-set canonicals pointing to the original domain.","sources":["https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls"]},{"id":"urls-canonical-sitemap-link-consistency","section":"urls","title":"Canonical, sitemap <loc>, and internal links use one identical URL form","severity":"high","stage":"pre-launch","automatable":true,"check_type":"sitemap","what":"For each page, the rel=canonical href, the sitemap <loc>, and every internal <a href> pointing to it are byte-for-byte identical (same scheme, host, case, and trailing-slash form).","why":"Inconsistent signals act as votes against your intended canonical and can invalidate the sitemap submission. @astrojs/sitemap derives URLs from Astro.site, build.format, and trailingSlash, so these must match the canonical and link conventions used in layouts.","fix":"Use a single site-wide href helper (e.g. built from `new URL(path, Astro.site)`) with one trailing-slash convention matching `trailingSlash` in astro.config.mjs, and let @astrojs/sitemap use the same Astro.site/build.format settings.","how_to_check":"For a sample of pages, fetch /sitemap-0.xml (or sitemap-index), the page's canonical, and the inbound internal link hrefs, and assert all three strings are identical.","common_mistakes":"Trailing slashes in nav links but not in the sitemap; sitemap using http:// while canonical uses https://; inconsistent www prefix.","sources":["https://docs.astro.build/en/guides/integrations-guide/sitemap/","https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls"]},{"id":"urls-hreflang-language-codes","section":"urls","title":"hreflang language/region codes are valid BCP 47 (ISO 639-1 + ISO 3166-1 Alpha-2)","severity":"high","stage":"pre-launch","automatable":true,"check_type":"html_attribute","what":"Every hreflang value uses a valid ISO 639-1 language code, optionally combined with a valid ISO 3166-1 Alpha-2 region (e.g. en, en-US, en-GB, zh-CN), plus x-default. Non-standard codes are not used.","why":"Google silently ignores invalid or non-BCP 47 codes; en-UK (correct: en-GB) and es-419 (unsupported by Google) are common mistakes that break the whole annotation set.","fix":"Use correct locale codes in astro.config.mjs i18n.locales and as the @astrojs/sitemap i18n `locales` map values (e.g. `{ en: 'en-US', fr: 'fr-FR' }`), keeping the keys matched to Astro's i18n.locales.","how_to_check":"Parse all hreflang attribute values across pages and validate each against BCP 47 / ISO 639-1 + ISO 3166-1; flag uk (use en-GB), cz (use cs), cn (use zh-CN), and es-419 (unsupported).","common_mistakes":"en-UK instead of en-GB; bare pt/zh where pt-BR/pt-PT or zh-Hans/zh-Hant is meant; es-419.","sources":["https://developers.google.com/search/docs/specialty/international/localized-versions","https://backlinko.com/hreflang-tag"]},{"id":"urls-i18n-routing-and-root","section":"urls","title":"i18n prefixDefaultLocale and root-URL behavior are configured correctly","severity":"high","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"i18n.routing.prefixDefaultLocale matches the intended URL structure, and the root URL `/` either serves the default-locale homepage (200) or 301/302-redirects to a working default-locale URL.","why":"A mismatched prefix generates default-locale pages at the wrong paths, breaking canonicals, hreflang hrefs, and navigation. A root `/` that 404s or is blank is a critical crawlability and usability failure.","fix":"With prefixDefaultLocale:false (default), the default locale serves at /about and `/` works with no extra config. With prefixDefaultLocale:true, the default locale lives at /en/about and you must ALSO set redirectToDefaultLocale:true to make `/` redirect to /en/ — it defaults to false, so otherwise `/` just renders src/pages/index.astro. Add redirects if you change this structure after launch.","how_to_check":"GET / -> assert 200 (content) or 301/302 to a locale prefix that returns 200. If prefixDefaultLocale:false, GET /en/about -> assert 404 or redirect to /about and GET /about -> 200.","common_mistakes":"Expecting prefixDefaultLocale:true to auto-redirect `/` to /en/ without redirectToDefaultLocale:true; switching the prefix setting post-launch without adding old->new redirects.","sources":["https://docs.astro.build/en/guides/internationalization/"]},{"id":"urls-no-redirect-chains","section":"urls","title":"No redirect chains; every redirect resolves in one hop","severity":"high","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"No URL requires more than one redirect hop to reach its final destination; A -> B -> C chains are collapsed to A -> C.","why":"Each hop adds latency (extra round-trip, hurting LCP/TTFB), dilutes link-equity transfer, and Googlebot stops after ~10 hops. Chains commonly arise when an old redirect's target is later moved again, or when HTTP->HTTPS and www->apex rules compound.","fix":"When adding a redirect in astro.config redirects, _redirects, or vercel.json, point each source directly at the final URL and confirm the destination is not itself a redirect source. Neither platform flattens chains automatically.","how_to_check":"For each redirect source: `curl -L --max-redirs 10 -w '%{num_redirects}' -o /dev/null https://example.com/old` -> assert num_redirects == 1 (a single 3xx then 200).","common_mistakes":"Adding /old -> /interim when /interim already redirects to /final; HTTP->HTTPS plus www->apex compounding into two hops.","platform_notes":"Cloudflare _redirects and Vercel vercel.json both process rules without collapsing chains.","sources":["https://www.rankability.com/ranking-factors/google/redirect-chains/","https://vercel.com/docs/routing/redirects","https://developers.cloudflare.com/pages/configuration/redirects/"]},{"id":"urls-no-session-tokens","section":"urls","title":"Session tokens, user IDs, and auth tokens never appear in indexable URLs","severity":"high","stage":"pre-launch","automatable":true,"check_type":"body_regex","what":"No indexable URL contains session IDs (?PHPSESSID=, ?sid=), auth/preview tokens, or personal identifiers as query parameters.","why":"Session-parameterized URLs create infinite crawl space, waste crawl budget, and leak security-sensitive identifiers into logs and referrer headers.","fix":"Astro SSR pages should carry session state in cookies, not URL params. Verify no middleware injects session/preview parameters into page URLs, and keep CMS preview-token URLs out of production output.","how_to_check":"Crawl the sitemap and internal links and assert no URL matches `sid=`, `session=`, `token=`, `auth=`, or `PHPSESSID=`.","common_mistakes":"CMS preview tokens leaking into production URLs; OAuth callback URLs getting indexed.","sources":["https://devdreaming.com/blogs/seo-friendly-urls-developer-guide-2025"]},{"id":"urls-old-urls-redirect-not-404","section":"urls","title":"Renamed or removed pages 301-redirect, not 404","severity":"high","stage":"pre-launch","automatable":false,"check_type":"manual","what":"Any URL previously indexed or linked that has moved or been deleted 301-redirects to the most relevant current page rather than returning 404.","why":"404s on previously indexed pages forfeit accumulated link equity and rankings. Google recommends keeping 301s in place for at least a year after a URL change.","fix":"Maintain a redirect map (astro.config.mjs redirects with an adapter, public/_redirects on Cloudflare, or vercel.json on Vercel). Reconcile regularly against Google Search Console's Not Found (404) report. Remember static-without-adapter config redirects emit meta-refresh, not 301s.","how_to_check":"Pull GSC Coverage > Not Found; for each 404 URL determine if it was previously in the sitemap or has inbound links, and flag any lacking a redirect. (Discovery of which old URLs mattered requires human/GSC judgment.)","common_mistakes":"Relying on astro.config redirects in a static build without an adapter (meta-refresh, not 301); deleting content with no redirect plan.","sources":["https://victorious.com/blog/301-redirects/","https://randomgeekery.org/post/2025/01/server-side-redirects-in-astro-ssg-mode/"]},{"id":"urls-parameters-handled","section":"urls","title":"Tracking, filter, sort, and UI-state parameter URLs are not indexed as duplicates","severity":"high","stage":"pre-launch","automatable":true,"check_type":"body_regex","what":"Pages reachable via query parameters that duplicate content (?utm_*, ?gclid, ?fbclid, ?sort=, ?color=, ?print=true, ?modal=open, ?sessionid=) carry a canonical pointing to the param-clean base URL, and no parameterized URLs appear in the sitemap.","why":"Parameter variants are treated as separate URLs; without a clean canonical, Googlebot crawls all variants, wastes crawl budget, splits ranking signals, and inflates indexed-page counts in Search Console.","fix":"Build the canonical from `new URL(Astro.url.pathname, Astro.site).href`, which drops all query strings by design — never use Astro.url.href. Do not emit parameterized URLs in social/share <link>/<a> tags or in the sitemap. For pagination, give numbered pages their own real paths (/blog/2/) each self-canonicalizing (Google dropped rel=next/prev support in 2019).","how_to_check":"GET a page with `?utm_source=test&sort=price` -> assert the canonical href has no `?`. Fetch the sitemap and assert no <loc> contains `utm_`, `gclid`, `fbclid`, `sid=`, or other params.","common_mistakes":"Setting canonical from Astro.url.href (carries the incoming query string in SSR, e.g. when QA opens a UTM share link); sharing modal/print URLs via social meta tags.","sources":["https://developers.google.com/search/docs/crawling-indexing/canonicalization","https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls"]},{"id":"urls-redirect-type-correct","section":"urls","title":"Redirect type matches intent: 301/308 for permanent, 302/307 for temporary","severity":"high","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"Permanent URL changes return 301 (or 308 for non-GET); only genuinely temporary cases (A/B tests, maintenance, transient locale detection) return 302/307.","why":"302/307 do not pass PageRank or update Googlebot's indexed URL, so a permanent move using 302 leaves the old URL indexed and equity untransferred. Both 301 and 308 are valid permanent redirects.","fix":"Cloudflare _redirects: append explicit `301`. Vercel vercel.json: `\"permanent\": true` produces 308 (NOT 301); use `\"statusCode\": 301` if you specifically need 301. Astro SSR redirects default GET redirects to 301.","how_to_check":"For each redirect: assert status is in {301, 308} for permanent moves and only in {302, 307} for explicitly temporary ones.","common_mistakes":"Using 302 for a permanent move; not realizing Vercel `permanent: true` = 308.","platform_notes":"Vercel `permanent: true` = 308 (per current Vercel docs); both 301 and 308 pass link equity in Google.","sources":["https://www.hikeseo.co/learn/technical/301-vs-302-redirects","https://vercel.com/docs/redirects/configuration-redirects"]},{"id":"urls-sitemap-hreflang-consistent","section":"urls","title":"@astrojs/sitemap emits hreflang xhtml:link entries consistent with the HTML","severity":"high","stage":"build","automatable":true,"check_type":"sitemap","what":"On multilingual sites the generated sitemap includes <xhtml:link rel=\"alternate\" hreflang> entries grouping all language variants per page, and (if hreflang is also in HTML) the URLs and language codes in both implementations are identical.","why":"The sitemap is an additional hreflang signal, important for large sites not fully crawled via internal links. Contradictory values between HTML and sitemap confuse Google's consolidation logic.","fix":"Pass a matching i18n option to the sitemap integration: `sitemap({ i18n: { defaultLocale: 'en', locales: { en: 'en-US', fr: 'fr-FR' } } })`, with `locales` keys matching astro.config i18n.locales exactly. If also rendering hreflang in the layout, build both from getAbsoluteLocaleUrl on the same Astro.site base with the same locale codes.","how_to_check":"GET /sitemap-0.xml; for a multilingual page assert child <xhtml:link rel=\"alternate\" hreflang> elements cover all locales, then compare that set (URLs + lang codes) against the page's HTML hreflang set and assert equality.","common_mistakes":"Configuring Astro i18n but forgetting the i18n option inside the sitemap() call; mismatched locale key names; fr-CA in HTML vs fr in the sitemap.","sources":["https://docs.astro.build/en/guides/integrations-guide/sitemap/","https://developers.google.com/search/docs/specialty/international/localized-versions"]},{"id":"urls-slug-hygiene","section":"urls","title":"URL slugs are lowercase, hyphen-separated, and free of special characters","severity":"high","stage":"build","automatable":true,"check_type":"body_regex","what":"Path segments contain only [a-z0-9-/]: all lowercase, hyphens (not underscores) between words, no spaces, no special/non-ASCII characters, and no double slashes (//). Mixed-case URLs 301-redirect to their lowercase form.","why":"Servers and Google treat /About and /about as different URLs (Vercel's CDN is explicitly case-sensitive), and Google reads underscores as part of a word but hyphens as word separators, affecting keyword tokenization. Special characters, %20-spaces, and // create unreliable, duplicate, or broken URLs.","fix":"Name all files/folders in src/pages/ lowercase with hyphens. For CMS slugs normalize: `slug.toLowerCase().replace(/_/g,'-').replace(/[^a-z0-9-]/g,'-').replace(/-+/g,'-').replace(/^-|-$/g,'')`; transliterate diacritics first (e.g. slugify). Build URLs with `new URL(path, Astro.site)` rather than string concatenation to avoid `https://example.com//slug`.","how_to_check":"Crawl sitemap and build output and assert each path segment matches `^[a-z0-9-]+$` (no uppercase, underscore, space, special char, or //). Exclude Astro system paths such as `_astro/`, `_image`, `_actions/`. `find dist/ -name '*.html' | grep -E '[A-Z]'` should return nothing.","common_mistakes":"snake_case or mixed-case slugs from a headless CMS used unnormalized; component-style filenames like BlogPost.astro producing /BlogPost; concatenating Astro.site (which ends in /) with a leading-slash path producing //.","platform_notes":"Vercel CDN is case-sensitive (no auto-lowercasing) but auto-normalizes consecutive slashes with a 308; Cloudflare Pages does neither — so // risk is a real duplicate on Cloudflare and a redirect-overhead cost on Vercel.","sources":["https://developers.google.com/search/docs/crawling-indexing/url-structure","https://vercel.com/docs/redirects","https://devdreaming.com/blogs/seo-friendly-urls-developer-guide-2025"]},{"id":"urls-internal-links-no-redirect","section":"urls","title":"Internal links point directly to final canonical URLs (no internal redirects)","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"Every internal <a href> resolves with a 200 directly, never through a 301/302 hop.","why":"Linking through redirects wastes link equity, adds navigation latency, and signals a stale internal link graph to crawlers.","fix":"After any slug rename, find-replace all internal hrefs in .astro and markdown/content files to the new URL. For i18n links use Astro's getRelativeLocaleUrl / getAbsoluteLocaleUrl rather than hardcoding paths.","how_to_check":"Crawl internal links recursively from the homepage; issue a HEAD request for each href and assert status 200 (not 3xx). Report every internal link that redirects.","common_mistakes":"Renaming a slug in getStaticPaths without updating the links that point to it.","sources":["https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls"]},{"id":"urls-content-language-header-ssr","section":"urls","title":"Localized SSR pages set a Content-Language response header","severity":"low","stage":"pre-launch","automatable":true,"check_type":"http_header","what":"For SSR (output: 'server') Astro sites, localized pages return a Content-Language HTTP header matching the page locale (e.g. Content-Language: fr).","why":"A very weak signal with no evidence of direct ranking impact; useful for proxy/CDN caching decisions and HTTP client clarity. Far less important than hreflang and not achievable for static output.","fix":"In Astro SSR middleware or a route handler: `return new Response(html, { headers: { 'Content-Language': Astro.currentLocale ?? 'en' } })`. Only applies with a server adapter.","how_to_check":"For SSR deployments only: GET /fr/about -> assert response header `Content-Language: fr`.","common_mistakes":"Treating this as a meaningful ranking factor; attempting it on a static build where it does not apply.","platform_notes":"Set in middleware/Edge function on both Cloudflare Pages SSR and Vercel SSR adapters.","sources":["https://docs.astro.build/en/guides/internationalization/"]},{"id":"urls-descriptive-readable-slugs","section":"urls","title":"URLs are short, descriptive, keyword-relevant, and shallow","severity":"low","stage":"build","automatable":false,"check_type":"manual","what":"Slugs describe the content in human-readable, keyword-relevant terms (no bare DB IDs or UUIDs), stay roughly under 75 characters (under 100 for SERP display), and sit no more than ~4 path segments deep from root.","why":"Descriptive, concise URLs improve click-through and shareability and are a minor relevance signal; deep URLs reduce crawl discovery and priority. URL length itself is not a confirmed ranking factor (per John Mueller) — long URLs are just truncated in SERPs.","fix":"In content collections, define an intentional `slug` field (not the auto-incremented ID) and keep it to the 3-5 most meaningful words. Avoid nesting categories beyond 3-4 levels (prefer /blog/category/slug over /blog/year/month/day/slug).","how_to_check":"Crawl the sitemap: programmatically flag URLs over 75/100 chars, URLs with more than 4 path segments, and `?id=\\d+` or UUID-only segments; then human-review a sample of 10-20 (title, slug) pairs for keyword relevance.","common_mistakes":"Using numeric CMS IDs as the route param; mirroring the full verbose title (with stop words) as the slug; deep date-based blog nesting.","sources":["https://www.octaria.com/blog/seo-friendly-url-structure-best-practices-2025","https://www.collaborada.com/blog/does-url-length-affect-seo-google-says-no"]},{"id":"accessibility-html-lang-valid","section":"accessibility","title":"Set a valid lang attribute on the root html element","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"The root <html> element must carry a valid BCP 47 language tag (e.g. lang=\"en\" or lang=\"en-US\"), matching the page's actual content language.","why":"Missing or wrong lang is a WCAG 3.1.1 (Level A) failure flagged as critical by axe and Lighthouse (html-has-lang, valid-lang). Screen readers pick their pronunciation engine from lang, and search engines use it for geo/language targeting.","fix":"Set lang on <html> in your base layout: <html lang=\"en\">. For multilingual sites, inject the locale with a fallback because Astro.currentLocale can return undefined on SSG index routes (issue #14228): <html lang={Astro.currentLocale ?? 'en'}>. Build the site and check the emitted HTML, not just the dev server.","how_to_check":"GET each page's HTML, parse <html lang=\"...\">, assert the attribute exists and matches /^[a-zA-Z]{2,3}(-[a-zA-Z0-9]{2,8})*$/. axe-core rules html-has-lang and valid-lang automate this. Spot-check multiple locale routes in the built output.","common_mistakes":"Empty lang=\"\", a non-BCP-47 value, hard-coding \"en\" on non-English pages, or relying on Astro.currentLocale with no fallback on SSG index routes.","sources":["https://dequeuniversity.com/rules/axe/4.7/html-has-lang","https://docs.astro.build/en/guides/internationalization/","https://github.com/withastro/astro/issues/14228"]},{"id":"accessibility-image-alt-text","section":"accessibility","title":"Every image has alt text (descriptive for content, empty for decorative)","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"html_attribute","what":"Every <img> must have an alt attribute. Content images need concise, descriptive text (roughly 5-125 chars) describing what the image shows in context. Purely decorative images must use alt=\"\" (explicit empty string, never a missing attribute or a space).","why":"WCAG 1.1.1 Non-text Content (Level A); Lighthouse image-alt is weight 10. Google uses alt text as a primary image-understanding signal for Google Images. WebAIM consistently finds missing alt as the most common failure.","fix":"Astro's <Image /> and <Picture /> from astro:assets require alt at build time (ImageMissingAlt error if omitted). Content: <Image src={hero} alt=\"Aerial view of downtown Reykjavik at dusk\" />. Decorative: <Image src={divider} alt=\"\" />. Raw <img> in .astro/.mdx is NOT enforced, so add alt manually. For CSS background-image, put aria-label on the wrapping element if it conveys meaning.","how_to_check":"Parse rendered HTML; assert every <img> has an alt attribute present (document.querySelectorAll('img:not([alt])').length === 0). For non-decorative images, assert alt is non-empty and reasonable length. Run axe-core / Lighthouse image-alt (no violations); manually review that alt is meaningful, not the filename or keyword-stuffed.","common_mistakes":"alt=\"image\"/alt=\"photo\"/filename; keyword-stuffing; alt=\" \" (space) for decorative; omitting alt on raw <img> assuming Astro enforces it; marking informational images as decorative to skip writing alt.","sources":["https://docs.astro.build/en/reference/errors/image-missing-alt/","https://developers.google.com/search/docs/appearance/google-images","https://docs.astro.build/en/guides/images/"]},{"id":"accessibility-skip-to-content-link","section":"accessibility","title":"Provide a skip-to-content link as the first focusable element","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"A visually hidden 'Skip to main content' link must be the very first focusable element in <body>, become visible on focus, and target a <main> that carries id and tabindex=\"-1\".","why":"WCAG 2.4.1 Bypass Blocks (Level A). Without it, keyboard and switch-access users must tab through the full header and nav on every page.","fix":"Immediately after <body> in the base layout: <a href=\"#main-content\" class=\"skip-link\">Skip to main content</a>, and <main id=\"main-content\" tabindex=\"-1\">. CSS: .skip-link{position:absolute;left:-9999px} .skip-link:focus{left:0}. Do not hide it with display:none (that makes it unfocusable).","how_to_check":"Parse HTML and assert the first focusable element is an <a> whose href starts with '#' and whose text contains 'skip', and that the target id exists. Full verification needs a Playwright/Puppeteer Tab-press to confirm it becomes visible and that focus lands on <main>.","common_mistakes":"Target has no tabindex so focus does not land on it; link hidden with display:none; an injected script (cookie banner, Zaraz, analytics) inserts a focusable element before the skip link.","platform_notes":"On Cloudflare Pages (Zaraz) or Vercel Analytics, verify injected scripts do not place a focusable element before the skip link.","sources":["https://www.w3.org/WAI/test-evaluate/easy-checks/skip-link/","https://www.accessibilitychecker.org/wcag-guides/ensure-all-skip-links-have-a-focusable-target/"]},{"id":"accessibility-viewport-allows-zoom","section":"accessibility","title":"Viewport meta tag must not disable user zoom","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"html_head","what":"The <meta name=\"viewport\"> tag must set width=device-width, initial-scale=1 and must NOT include user-scalable=no or a maximum-scale below 2.","why":"Disabling zoom is a WCAG 1.4.4 Resize Text (Level AA) failure that locks out low-vision users who rely on browser zoom. Lighthouse weights the meta-viewport audit heavily (weight 10).","fix":"In the base layout <head> use exactly: <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />. This is the Astro starter default; do not add user-scalable=no or maximum-scale=1, and check that no UI framework component injects them.","how_to_check":"GET the page HTML, extract the content of <meta name=\"viewport\">, assert it does not contain user-scalable=no or maximum-scale < 2. Lighthouse meta-viewport audit automates this.","common_mistakes":"Pasting outdated boilerplate with user-scalable=no, or a component library that injects a zoom-locking viewport tag.","sources":["https://www.w3.org/WAI/standards-guidelines/act/rules/b4f0c3/","https://developer.chrome.com/docs/lighthouse/accessibility/scoring"]},{"id":"accessibility-aria-valid-and-minimal","section":"accessibility","title":"Use valid, role-appropriate ARIA only when native HTML is insufficient","severity":"high","stage":"pre-launch","automatable":true,"check_type":"html_attribute","what":"ARIA attributes must be spelled correctly, have valid values, match the element's role, and never duplicate semantics that native HTML already provides. First rule of ARIA: prefer a native element over an ARIA role.","why":"Invalid ARIA is worse than none and misleads assistive tech. Lighthouse flags several high-weight ARIA checks (aria-allowed-attr, aria-required-attr, aria-roles, aria-valid-attr, aria-valid-attr-value); WCAG 4.1.2 (Level A) requires correct name/role/value.","fix":"Prefer <button> over <div role=\"button\">, <nav> over <div role=\"navigation\">, <details>/<summary> for disclosures. When using component libraries (Radix, Headless UI) in islands, verify the rendered HTML produces correct ARIA. Avoid pasting unvetted ARIA snippets.","how_to_check":"Run axe-core against the live page: aria-allowed-attr, aria-required-attr, aria-required-children, aria-required-parent, aria-roles, aria-valid-attr, aria-valid-attr-value, aria-hidden-body. Lighthouse maps to these. Manually review custom widgets (accordions, tabs, modals, carousels) in axe DevTools 'Needs Review'.","common_mistakes":"aria-hidden=\"true\" on <body>; role=\"button\" on a <div> without tabindex and key handlers; aria-labelledby pointing to a missing id; aria-expanded on a static element.","sources":["https://developer.chrome.com/docs/lighthouse/accessibility/scoring","https://cerovac.com/a11y/2024/03/common-aria-problems-found-in-accessibility-audits/","https://www.w3.org/WAI/ARIA/apg/practices/landmark-regions/"]},{"id":"accessibility-buttons-links-accessible-names","section":"accessibility","title":"Buttons and links have descriptive accessible names","severity":"high","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"Every <button>/<input type=button|submit|reset> must have a discernible name (visible text, aria-label, or aria-labelledby); icon-only buttons use aria-label. Link text (or aria-label) must describe the destination in isolation; generic 'click here', 'read more', 'learn more', 'here' fail WCAG 2.4.4.","why":"WCAG 4.1.2 (buttons) and 2.4.4 Link Purpose (links), both Level A; Lighthouse button-name is weight 10. Screen reader users scan link/button lists out of context, so generic names are useless; descriptive link text also strengthens anchor-text SEO.","fix":"Icon button: <button aria-label=\"Open navigation menu\"><svg aria-hidden=\"true\">...</svg></button>. For 'read more' cards, add hidden context: Read more <span class=\"sr-only\">about {post.title}</span>, or aria-label={`Read more about ${post.title}`}. Add a .sr-only utility in global CSS.","how_to_check":"Parse HTML; for each button assert non-empty text OR aria-label OR aria-labelledby. For links, flag text matching a blocklist ['click here','read more','learn more','more','here','this','link'] (case-insensitive) and flag empty links. Lighthouse/axe button-name and link-name automate the core checks.","common_mistakes":"Font icon <i class=\"icon-close\"> with no aria-label; button text just '>' or 'X'; using title instead of aria-label; every blog card ending in a bare 'Read more'; pagination links labelled only '<' and '>'.","sources":["https://developer.chrome.com/docs/lighthouse/accessibility/scoring","https://www.section508.gov/blog/accessibility-bytes/descriptive-links-and-hypertext/"]},{"id":"accessibility-color-contrast","section":"accessibility","title":"Meet WCAG AA contrast for text (4.5:1) and UI components (3:1)","severity":"high","stage":"pre-launch","automatable":false,"check_type":"lighthouse","what":"Normal text needs at least 4.5:1 contrast against its background (3:1 for large text >=24px/19px-bold) per WCAG 1.4.3. Non-text UI parts (input borders, custom checkboxes, icon-only buttons, focus rings) need at least 3:1 against adjacent colors per WCAG 1.4.11. Both are Level AA.","why":"Low contrast makes content unreadable for low-vision users and in bright light, and is a basis for ADA/EAA claims. Lighthouse/axe color-contrast catch only ~30% of cases; non-text contrast (1.4.11) is only partially automatable, so manual review is required.","fix":"Enforce contrast in Tailwind tokens / CSS design tokens; avoid light-grey text on white and thin light-grey (#ccc) input borders. Verify in both light and dark themes and for hover/focus/active states. Test scoped-style output in the rendered page since scoping does not change ratios.","how_to_check":"Run Lighthouse/axe color-contrast against the live URL for text. For UI components, inspect computed border/background/icon colors in DevTools and run them through the WebAIM Contrast Checker. Manually check gradient/image backgrounds and dynamic color combinations.","common_mistakes":"Light-grey text on white; text over hero images that passes only in dark areas; untested hover/focus states; custom inputs with thin light-grey borders (e.g. ~1.6:1); low-contrast SVG icons next to white.","sources":["https://webaim.org/articles/contrast/","https://dequeuniversity.com/rules/axe/4.8/color-contrast","https://www.makethingsaccessible.com/guides/contrast-requirements-for-wcag-2-2-level-aa/"]},{"id":"accessibility-form-inputs-labeled","section":"accessibility","title":"All form controls have programmatically associated labels","severity":"high","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"Every <input> (except hidden), <select>, and <textarea> must have an accessible name via an explicit <label for=\"id\">, aria-label, or aria-labelledby referencing visible text. Placeholder alone is never a label.","why":"WCAG 1.3.1 and 4.1.2 (both Level A); Lighthouse label is weight 10. Unlabeled inputs leave screen-reader users unsure what to enter, and placeholders vanish on input, hurting cognitive-disability users.","fix":"Use <label for=\"email\">Email address</label><input id=\"email\" type=\"email\" />. For label-less search: <input type=\"search\" aria-label=\"Search the site\" />. For errors: <input aria-describedby=\"email-error\" aria-invalid=\"true\" />. Never rely on placeholder alone.","how_to_check":"Parse HTML; for each non-hidden input/select/textarea assert one of: aria-label, aria-labelledby pointing to an existing id, or a <label for> matching the control's id. Lighthouse label and axe label automate this.","common_mistakes":"Placeholder as the only label; aria-label text that omits the visible label (violates WCAG 2.5.3); input missing an id when using <label for>; nav search box with no accessible name.","sources":["https://cerovac.com/a11y/2024/03/common-aria-problems-found-in-accessibility-audits/","https://developer.chrome.com/docs/lighthouse/accessibility/scoring"]},{"id":"accessibility-heading-structure","section":"accessibility","title":"Exactly one H1 per page with sequential, non-skipping headings","severity":"high","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"Each page has exactly one <h1> describing the main topic (closely matching the <title>), and subsequent heading levels descend without skipping ranks (H1 then H2, never H1 then H3). Headings reflect content hierarchy, not visual styling.","why":"Screen reader users navigate by heading; duplicate/absent H1 and skipped levels break the document outline (WCAG 2.4.6, Level AA; Lighthouse heading-order). A single descriptive H1 is also a clear content signal.","fix":"Put the H1 in the page-level template, not the layout: <h1>{title}</h1>. Map content-collection `title` to the H1. In MDX/Markdown, do not also emit an H1 in the prose body (avoid leading #). Use CSS classes for visual size; use heading tags only for semantic rank.","how_to_check":"Parse HTML; assert exactly one <h1>; extract all headings in DOM order and assert no rank jump greater than 1. Optionally diff H1 text vs <title>. axe-core heading-order automates the sequence check.","common_mistakes":"Layout adds a site-name H1 while the template also has an article H1; MDX uses # producing a second H1; jumping to H4 for accordion/FAQ headers because they 'look right'.","sources":["https://www.w3.org/WAI/tutorials/page-structure/headings/","https://developer.chrome.com/docs/lighthouse/accessibility/scoring"]},{"id":"accessibility-keyboard-operable","section":"accessibility","title":"All functionality is keyboard-operable with no keyboard traps","severity":"high","stage":"pre-launch","automatable":false,"check_type":"manual","what":"Every interactive element must be reachable and operable with the keyboard alone, in a logical tab order following visual reading order, with no permanent focus trap (WCAG 2.1.2 No Keyboard Trap, Level A). Modals/menus must close with Escape and return focus to their trigger.","why":"Keyboard access is required for motor-disability and screen-reader users. Traps prevent leaving modals, date pickers, or menus with Tab/Shift+Tab/Escape/Arrows. axe-core cannot detect keyboard traps algorithmically, so manual testing is mandatory.","fix":"For React/Preact/Svelte islands (modals, dropdowns, drawers), return focus to the trigger on close and support Escape. Avoid positive tabindex values that disrupt natural order. With Astro's ClientRouter, view transitions restore focus on navigation, but verify any custom transitions do too.","how_to_check":"Manually navigate the whole page using only Tab, Shift+Tab, Enter, Space, Escape, and Arrows; confirm nothing traps focus and every modal/dropdown closes with Escape and restores focus. Playwright can partially assert no permanent trap and Escape behavior.","common_mistakes":"Cookie dialogs that trap focus; dropdowns that respond only to mouse; carousels without arrow-key support; custom view transitions that fail to restore focus.","sources":["https://www.w3.org/WAI/WCAG21/Understanding/keyboard.html","https://docs.astro.build/en/guides/view-transitions/"]},{"id":"accessibility-legible-font-size","section":"accessibility","title":"Legible body text and 16px form inputs to avoid iOS zoom","severity":"high","stage":"pre-launch","automatable":true,"check_type":"lighthouse","what":"Body copy should be at least 16px on mobile and text inputs must be at least 16px to prevent iOS Safari auto-zoom. Secondary text should not drop below 12px (Lighthouse legible-font-sizes flags pages where 40%+ of text is under 12px).","why":"iOS Safari auto-zooms when a focused input has font-size < 16px, breaking layout. Lighthouse 'legible font sizes' (SEO category) checks the 12px/60% coverage threshold. (Do not use GSC's old 'text too small' report; Google removed it in Dec 2023.)","fix":"Set base size in global CSS: html{font-size:16px} or Tailwind text-base as the body default; input{font-size:1rem} (never below 16px). Prefer rem/em units for scaling.","how_to_check":"Playwright at 390px: read getComputedStyle(el).fontSize per text element and assert >=12px overall and >=16px for <p> body text and <input>. Lighthouse 'legible font sizes' (SEO) automates the 12px/60% coverage check.","common_mistakes":"px sizes that look fine on desktop but render tiny on mobile; a component library default input font-size of 14px triggering iOS auto-zoom.","sources":["https://developer.chrome.com/docs/lighthouse/seo/font-size","https://searchengineland.com/google-officially-drops-mobile-usability-report-mobile-friendly-test-tool-and-mobile-friendly-test-api-435377"]},{"id":"accessibility-mobile-responsive-no-overflow","section":"accessibility","title":"Layout is responsive with no horizontal scroll on mobile","severity":"high","stage":"pre-launch","automatable":true,"check_type":"lighthouse","what":"Page content must fit the viewport at common mobile widths (360, 390, 414px) with no horizontal scrolling and no element overflowing wider than the viewport.","why":"Google uses mobile-first indexing, so the mobile rendering is what gets crawled and indexed. Horizontal overflow is poor UX and a negative page-experience signal; mobile-friendliness remains a ranking factor even after GSC retired the Mobile Usability report.","fix":"Use Tailwind responsive prefixes (sm:/md:/lg:) and avoid fixed pixel widths on containers. In global CSS add box-sizing:border-box on *, *::before, *::after and img,video{max-width:100%}. Test with astro dev plus Chrome DevTools device simulator.","how_to_check":"Playwright at 390x844: assert document.documentElement.scrollWidth <= clientWidth (no horizontal overflow), repeat at 360px. Run Lighthouse mobile audit and check 'content properly sized for viewport'.","common_mistakes":"Fixed-width tables, long unbroken URLs/code blocks, fixed-width third-party embeds, absolute-positioned elements running off-canvas.","platform_notes":"Neither platform transforms HTML, but confirm Cloudflare Rocket Loader / Auto Minify do not break responsive CSS.","sources":["https://developers.google.com/search/docs/crawling-indexing/mobile/mobile-sites-mobile-first-indexing"]},{"id":"accessibility-no-intrusive-interstitials","section":"accessibility","title":"No intrusive interstitials blocking content on mobile load","severity":"high","stage":"post-launch","automatable":false,"check_type":"manual","what":"On mobile, pages must not show full-screen popups, newsletter modals, or app-install prompts that cover the main content immediately on load. Legally required dialogs (cookie consent, age gates) and small persistent banners are exempt; Google advises overlays cover no more than 15-25% of the mobile viewport.","why":"Google's intrusive-interstitial policy (since Jan 2017) penalizes overlays that block content access (the violatesMobileInterstitialPolicy signal feeds page experience ranking), and analyses of the Dec 2025 / Feb 2026 Core Updates point to increased weight on page-experience signals.","fix":"Make any Astro modal/overlay delayed (not on first arrival from search), dismissible, and never full-screen on mobile. Configure cookie consent as a banner, not a blocking overlay. Never gate newsletter signups behind a full-page interstitial.","how_to_check":"Playwright cold visit (no cookies) at mobile viewport, wait ~3s, flag any fixed/absolute element with z-index>100 covering >25% of the viewport; back up with a screenshot. Human judgment needed for edge cases (no fully reliable automated check exists).","common_mistakes":"Newsletter modal firing after ~0.5s; full-screen cookie banner on mobile; service-worker app-install prompt on first visit.","platform_notes":"Cloudflare Zaraz can inject scripts that fire popups; Vercel Edge Middleware can set a cookie to suppress first-visit modals. Neither platform blocks intrusive overlays automatically.","sources":["https://developers.google.com/search/docs/appearance/avoid-intrusive-interstitials","https://www.tba-berlin.de/en/seo-topics/intrusive-overlays-and-google-rankings/"]},{"id":"accessibility-page-title-unique","section":"accessibility","title":"Every page has a unique, descriptive title element","severity":"high","stage":"pre-launch","automatable":true,"check_type":"html_head","what":"Each page must have a non-empty, unique <title> in <head> that describes the page (WCAG 2.4.2 Page Titled, Level A). Convention: 'Page Topic | Site Name'. Titles must not be identical across pages or left as the starter default.","why":"Screen readers announce the title first on load; duplicate or missing titles disorient AT users. The title is also Google's primary SERP link-text signal. Lighthouse document-title flags missing titles.","fix":"Use a Layout that accepts a title prop: <title>{title} | My Site</title>. Map content-collection frontmatter `title` to the prop and ensure each template passes a unique value. An astro-seo or custom <SEO> component helps keep head meta consistent.","how_to_check":"Parse <title>; assert non-empty and not a placeholder ('Astro', 'My Site'). For a full crawl, fetch all titles and assert uniqueness across pages. Lighthouse document-title automates the single-page check.","common_mistakes":"Same title on every page; leftover Astro starter 'Astro' title; title containing only the site name with no page-specific text.","sources":["https://developer.chrome.com/docs/lighthouse/accessibility/scoring","https://www.w3.org/WAI/tutorials/page-structure/headings/"]},{"id":"accessibility-semantic-landmarks","section":"accessibility","title":"Use semantic landmarks with one main and uniquely labelled navs","severity":"high","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"Each page uses semantic landmark elements: a <header>, <nav>, exactly one <main>, and a <footer>. When more than one <nav> exists (main, breadcrumb, footer), each must carry a unique, non-empty aria-label.","why":"Landmarks let screen reader users jump between regions and expose correct ARIA roles automatically. Multiple unlabelled navs collapse into indistinguishable 'navigation' entries (axe region, landmark-one-main, landmark-unique). Good structure is a quality signal.","fix":"Base layout: <header>...</header><main><slot /></main><footer>...</footer>. Label multiple navs: <nav aria-label=\"Main\">, <nav aria-label=\"Breadcrumb\">, <nav aria-label=\"Footer\">. Do not add redundant role=\"banner\"/role=\"main\" on semantic elements; their implicit roles suffice.","how_to_check":"Parse HTML; assert presence of header/nav/main/footer (or equivalent roles), exactly one <main>, and that every <nav> beyond the first has a unique aria-label. axe-core landmark-one-main, region, and landmark-unique partially cover this; confirm with a screen reader landmark list.","common_mistakes":"<div class=\"header\"> instead of <header>; no <main>; multiple unlabelled <nav>; mobile hamburger nav duplicating the desktop nav's label; <main> nested inside <header>.","sources":["https://www.w3.org/WAI/ARIA/apg/practices/landmark-regions/","https://a11y-guidelines.orange.com/en/articles/landmarks/"]},{"id":"accessibility-tap-target-size","section":"accessibility","title":"Tap targets are large enough and adequately spaced","severity":"high","stage":"pre-launch","automatable":true,"check_type":"lighthouse","what":"Tappable elements must be at least 24x24 CSS px (WCAG 2.5.8 Target Size (Minimum), Level AA, WCAG 2.2) with at least 24px clearance from adjacent targets. Best practice and Lighthouse's threshold is larger: 44x44 (Apple HIG) / 48x48 with ~48px spacing (Lighthouse SEO tap-targets audit).","why":"Small targets cause mis-taps for motor-impaired and mobile users. WCAG 2.5.8 is Level AA; Lighthouse tap-targets (in the SEO category) flags elements below 48x48px with insufficient spacing.","fix":"Give <a>/<button> enough padding to hit the target size. Tailwind: p-3 (a 0px element becomes ~24px) or, for icon buttons, p-2 min-h-[44px] min-w-[44px]. Never rely on the icon's visual size for the tap area.","how_to_check":"Run Lighthouse with --form-factor=mobile and read the SEO tap-targets audit (flags <48x48px with <48px spacing). For the WCAG 2.5.8 minimum, use Puppeteer to read each interactive element's bounding rect and assert width>=24 and height>=24.","common_mistakes":"16x16px social icon links; inline links in dense nav; tiny modal close (X) buttons; footer links with zero padding.","sources":["https://www.w3.org/WAI/WCAG22/Understanding/target-size-minimum.html","https://developer.chrome.com/docs/lighthouse/seo/tap-targets"]},{"id":"accessibility-visible-focus-indicators","section":"accessibility","title":"All interactive elements have visible keyboard focus indicators","severity":"high","stage":"pre-launch","automatable":false,"check_type":"manual","what":"Every focusable element must show a clearly visible focus indicator on keyboard focus. Never apply outline:none/outline:0 without a replacement. WCAG 2.4.7 Focus Visible (AA) requires a visible indicator; WCAG 2.4.13 Focus Appearance (AA, new in 2.2) adds minimum area and 3:1 contrast for the indicator.","why":"WebAIM finds ~78% of sites have focus-indicator issues. Without visible focus, keyboard-only users cannot tell where they are. :focus-visible shows rings for keyboard nav while suppressing them for mouse clicks.","fix":"Remove any global *:focus{outline:none} reset. Add :focus-visible styles, e.g. .interactive:focus-visible{outline:3px solid #005fcc;outline-offset:2px} or Tailwind focus-visible:ring-2 focus-visible:ring-blue-600. Confirm no CSS framework strips outlines globally.","how_to_check":"Manually Tab through the live page in Chrome and Firefox (and dark mode), confirming each element shows a clear ring. Partially automatable: grep CSS for outline:0/outline:none not paired with a :focus-visible replacement; Playwright can focus each element and screenshot to assert a non-default appearance.","common_mistakes":"Global *:focus{outline:none} with no :focus-visible replacement; focus ring color below 3:1 contrast; styles applied only with :focus (not :focus-visible) so mouse users also see rings.","sources":["https://www.w3.org/WAI/WCAG22/Understanding/focus-appearance.html","https://developer.mozilla.org/en-US/docs/Web/CSS/:focus-visible"]},{"id":"accessibility-data-tables-headers","section":"accessibility","title":"Data tables use th headers with scope; no layout tables","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"Any <table> of tabular data must use <th> elements with scope=\"col\"/scope=\"row\" (or be inside <thead>); complex multi-level headers need id/headers. Tables must not be used for layout.","why":"Screen readers use headers to give each cell context; without them a table is an unnavigable stream of values (WCAG 1.3.1, Level A). Lighthouse td-has-header is weight 10.","fix":"Author tables with <thead><tr><th scope=\"col\">Name</th></tr></thead>. Avoid CMS-generated tables that omit thead. Markdown via remark-gfm correctly emits <thead> and <th>. Use CSS Grid/Flexbox for layout, never tables.","how_to_check":"Parse HTML; for each <table> assert at least one <th>, and that column <th> use scope=\"col\" or sit inside <thead>. Lighthouse td-has-header and axe td-headers-attr automate this; confirm cell announcements with a screen reader.","common_mistakes":"CMS/markdown tables with all <td> and no <th>; tables used for page layout; missing scope on row-header cells.","sources":["https://developer.chrome.com/docs/lighthouse/accessibility/scoring","https://www.w3.org/WAI/tutorials/tables/"]},{"id":"accessibility-reduced-motion","section":"accessibility","title":"Respect prefers-reduced-motion for animations","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"body_regex","what":"Non-essential animations and transitions must be reduced or disabled when the OS 'Reduce Motion' preference is set via prefers-reduced-motion. (WCAG 2.3.3 is Level AAA, but honoring this preference is a widely expected baseline.)","why":"Animations can trigger nausea, vertigo, or seizures for users with vestibular disorders. The media query is supported in all modern browsers and is often contractually required in government/healthcare contexts.","fix":"Global CSS: @media (prefers-reduced-motion: reduce){*,*::before,*::after{animation-duration:.01ms!important;transition-duration:.01ms!important}}. Astro's ClientRouter already disables view-transition animations under reduced motion automatically (no config needed). Gate scroll-driven animations with @media (prefers-reduced-motion: no-preference).","how_to_check":"Static scan of built CSS: assert @keyframes/transition declarations are inside @media (prefers-reduced-motion: no-preference) or paired with a reduce override. Playwright: emulate prefers-reduced-motion and confirm animations are paused/absent. Or DevTools Rendering > Emulate prefers-reduced-motion: reduce.","common_mistakes":"Adding an Animate-On-Scroll library with no reduced-motion override; autoplaying hero video not paused under reduced motion; assuming you must hand-write CSS to stop Astro view-transition animations (the ClientRouter already handles them).","sources":["https://web.dev/learn/accessibility/motion","https://docs.astro.build/en/guides/view-transitions/","https://www.w3.org/WAI/WCAG22/Understanding/animation-from-interactions.html"]},{"id":"accessibility-svg-accessible","section":"accessibility","title":"Name content SVGs and hide decorative SVGs","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"Content-bearing inline SVGs need an accessible name via aria-label or a <title> child referenced by aria-labelledby. Decorative SVGs must have aria-hidden=\"true\" and focusable=\"false\" so AT ignores them.","why":"Inline SVGs are common for icons and illustrations; without names, screen readers announce raw path data or nothing. WCAG 1.1.1 applies to SVGs like <img>.","fix":"Decorative: <svg aria-hidden=\"true\" focusable=\"false\"><use href=\"#icon-menu\" /></svg>. Content: <svg aria-labelledby=\"chart-title\"><title id=\"chart-title\">Monthly visitor growth, Jan-Jun 2026</title>...</svg>. The astro-icon package applies aria-hidden automatically.","how_to_check":"Parse HTML; for each <svg>, pass if aria-hidden=\"true\"; otherwise assert aria-label OR aria-labelledby pointing to a <title> with text. axe-core svg-img-alt partially covers this; confirm with a screen reader.","common_mistakes":"Logo SVG with no name; icon SVG inside an aria-labelled button but not itself aria-hidden (double announcement); omitting focusable=\"false\" so some browsers make the SVG focusable.","sources":["https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Reference/Attributes/aria-label","https://shinagawa-web.com/en/blogs/accessibility-support"]},{"id":"accessibility-video-captions","section":"accessibility","title":"Prerecorded videos have synchronized captions","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"html_element","what":"All prerecorded video with audio must have synchronized captions (WCAG 1.2.2, Level A). Native <video> needs a <track kind=\"captions\"> (or subtitles); unreviewed auto-generated captions are generally insufficient.","why":"Deaf and hard-of-hearing users need captions to access video. Lighthouse video-caption (weight 10) flags <video> without a caption/subtitle track.","fix":"Native: <video><source src=\"...\" /><track kind=\"captions\" src=\"/captions-en.vtt\" srclang=\"en\" label=\"English\" default /></video>. YouTube embeds: add cc_load_policy=1 to the iframe URL; Vimeo: enable captions in settings.","how_to_check":"Parse HTML; assert each <video> has a child <track kind=\"captions|subtitles\">. Lighthouse video-caption automates the native check. YouTube/Vimeo iframes need manual review (play and confirm captions, checking accuracy on domain terms).","common_mistakes":"Providing only a transcript but no synchronized captions; no default track; shipping uncorrected auto-captions.","sources":["https://developer.chrome.com/docs/lighthouse/accessibility/scoring","https://www.w3.org/TR/WCAG21/#captions-prerecorded"]},{"id":"platform-adapter-correct-selection","section":"platform","title":"Install the correct Astro adapter (or none) for the deployment target","severity":"critical","stage":"build","automatable":true,"check_type":"manual","what":"Use @astrojs/cloudflare for Cloudflare Pages/Workers SSR and @astrojs/vercel for Vercel SSR. A fully static site (output:'static') needs no adapter on either platform; adding one unnecessarily wraps every page in a Worker/serverless function, adding latency and cost.","why":"A wrong or spurious adapter causes mis-routed requests, broken SSR, failed deployments, and slower/more expensive static delivery. Matching the adapter to the target is the foundation everything else depends on.","fix":"Static: keep output:'static' (default) and remove any adapter. Cloudflare SSR: `npx astro add cloudflare`, set output:'server', adapter: cloudflare(). Vercel SSR: `npx astro add vercel`, adapter: vercel() (single top-level import; the /serverless and /edge sub-paths were removed in @astrojs/vercel v8+).","how_to_check":"Inspect astro.config.mjs: if output:'static', assert no adapter; if output:'server', assert exactly one adapter matching the platform. In build output assert dist/_worker.js exists for Cloudflare SSR or .vercel/output/ exists for Vercel SSR. Live: confirm cf-ray (Cloudflare) or x-vercel-id (Vercel) response header.","common_mistakes":"Using @astrojs/cloudflare on a Vercel project (or vice versa); adding an adapter to a purely static site; forgetting to swap adapter when migrating platforms; using the removed @astrojs/vercel/serverless sub-path import.","platform_notes":"Cloudflare: an adapter is only needed for SSR or for bindings (KV, D1, R2); static sites deploy as direct uploads. Vercel: @astrojs/vercel is the single standard import for all modes.","sources":["https://docs.astro.build/en/guides/integrations-guide/cloudflare/","https://docs.astro.build/en/guides/integrations-guide/vercel/","https://developers.cloudflare.com/pages/framework-guides/deploy-an-astro-site/"]},{"id":"platform-cloudflare-ssl-mode-full-strict","section":"platform","title":"Cloudflare: set SSL/TLS encryption mode to Full (Strict), never Flexible","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"The Cloudflare zone SSL/TLS encryption mode must be Full (Strict) (or at minimum Full). Flexible mode combined with 'Always Use HTTPS' produces an infinite redirect loop (ERR_TOO_MANY_REDIRECTS) because Cloudflare Pages always redirects HTTP to HTTPS at the origin.","why":"Flexible mode encrypts only browser-to-Cloudflare, leaving Cloudflare-to-origin on HTTP; with Pages this causes redirect loops that take the whole site offline, and Full (Strict) additionally validates the origin certificate.","fix":"Cloudflare dashboard > SSL/TLS > Overview: set Full (Strict). Pages projects use Full (Strict) for the pages.dev origin by default; ensure the zone-level setting matches. Not an Astro config concern.","how_to_check":"`curl -sIL https://www.example.com` should produce only 1-2 HTTP status lines (no redirect loop); 3+ indicates a loop. Verify dashboard SSL/TLS > Overview shows Full or Full (Strict).","common_mistakes":"Leaving Flexible mode from a prior host after migrating to Pages; enabling 'Always Use HTTPS' while still on Flexible.","platform_notes":"Cloudflare-specific. Vercel has no SSL-mode concept (always full mutual TLS).","sources":["https://developers.cloudflare.com/ssl/troubleshooting/too-many-redirects/","https://developers.cloudflare.com/ssl/edge-certificates/universal-ssl/enable-universal-ssl/","https://developers.cloudflare.com/pages/configuration/custom-domains/"]},{"id":"platform-custom-domain-configured","section":"platform","title":"Attach the production custom domain and match it to astro.config site","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"The site must be reachable at the production custom domain (e.g., www.example.com), not only the platform default (*.pages.dev / *.vercel.app), with DNS pointing to the platform and `site` in astro.config.mjs matching the attached hostname.","why":"Without a custom domain, all SEO signals (backlinks, GSC property, canonical URLs, sitemap absolute URLs) accumulate on the wrong hostname.","fix":"Configure in the Cloudflare Pages dashboard (Settings > Custom domains) or Vercel dashboard (Project Settings > Domains). Set site:'https://www.example.com' in astro.config.mjs to the canonical attached domain so generated absolute URLs and the sitemap are correct.","how_to_check":"`dig www.example.com +short` returns a Cloudflare/Vercel CNAME or IP; `GET https://www.example.com` returns 200 with cf-ray (Cloudflare) or x-vercel-id (Vercel) header.","common_mistakes":"Attaching the domain to a preview branch instead of production; adding only www or only apex; `site` config not matching the live domain.","platform_notes":"Cloudflare: production *.pages.dev does NOT auto-noindex (see default-domain rule). Vercel: *.vercel.app system URLs DO auto-noindex.","sources":["https://developers.cloudflare.com/pages/configuration/custom-domains/","https://vercel.com/docs/domains/set-up-custom-domain"]},{"id":"platform-https-enforced-no-mixed-content","section":"platform","title":"Enforce HTTPS site-wide (HTTP 301/308 to HTTPS) with zero mixed content","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"All HTTP (port 80) requests must permanently redirect (301/308) to the HTTPS equivalent before any content is served, and every sub-resource (images, scripts, styles, fonts, iframes) on an HTTPS page must also load over HTTPS — no http:// URLs in rendered HTML or CSS.","why":"HTTPS is a confirmed Google ranking signal and a prerequisite for HTTPS canonicalization. Mixed content triggers browser security warnings, blocks active resources (breaking rendering), and undermines E-E-A-T trust.","fix":"Set site:'https://...' in astro.config.mjs. Cloudflare: enable SSL/TLS > Edge Certificates > Always Use HTTPS. Vercel: HTTPS is enforced automatically on custom domains. Add CSP `upgrade-insecure-requests` as belt-and-suspenders, and fix any hard-coded http:// in CMS/image/embed URLs at the source.","how_to_check":"`curl -I http://example.com/` and `http://www.example.com/` must return 301/308 with a Location starting https://. Then crawl rendered HTML (and CSS url() values) and assert no src/href/action/data-src/url() value starts with http://.","common_mistakes":"Hard-coded http:// in CMS image URLs or in the Astro `site` config; HTTP iframe embeds (YouTube/maps); using 302 instead of 301/308; relying on Cloudflare Automatic HTTPS Rewrites instead of fixing the source.","platform_notes":"Cloudflare: must NOT use Flexible SSL mode (see SSL-mode rule). Vercel: HTTP-to-HTTPS redirect is automatic and cannot be disabled on custom domains.","sources":["https://developers.google.com/search/docs/crawling-indexing/consolidate-duplicate-urls","https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers/Content-Security-Policy/upgrade-insecure-requests","https://vercel.com/docs/domains/working-with-domains"]},{"id":"platform-cloudflare-headers-in-middleware-for-ssr","section":"platform","title":"Cloudflare SSR: set security/cache headers in middleware, not only _headers","severity":"high","stage":"build","automatable":true,"check_type":"http_header","what":"On Cloudflare Pages with @astrojs/cloudflare SSR, the _headers file does NOT apply to responses generated by Pages Functions (the Worker). Security and cache headers for dynamic/SSR routes must be set programmatically in Astro middleware (src/middleware.ts). In hybrid setups, _headers covers prerendered static pages while middleware covers SSR pages.","why":"Per Cloudflare docs, custom headers in _headers are not applied to Pages Functions responses; an SSR site relying on _headers silently serves dynamic routes with no security headers. This also avoids the 100-rule _headers limit.","fix":"Create src/middleware.ts with `export const onRequest = defineMiddleware(async (context, next) => { const response = await next(); response.headers.set('X-Content-Type-Options','nosniff'); response.headers.set('Referrer-Policy','strict-origin-when-cross-origin'); /* all required headers */ return response; });`","how_to_check":"`curl -sI https://www.example.com/<dynamic-ssr-page> | grep -i x-content-type-options` must show nosniff, and a static asset (e.g., /_astro/main.js) must also carry security headers via its own mechanism.","common_mistakes":"Placing all headers in _headers and assuming site-wide coverage; on hybrid builds, forgetting that SSR pages need middleware while static pages use _headers.","platform_notes":"Cloudflare-specific. Does NOT apply to Vercel, where vercel.json headers apply to both static and serverless responses.","sources":["https://developers.cloudflare.com/pages/configuration/headers/"]},{"id":"platform-cloudflare-ssr-404-not-prerendered","section":"platform","title":"Cloudflare SSR: serve 404 via the Worker, not a prerendered 404 page","severity":"high","stage":"build","automatable":true,"check_type":"http_status","what":"On Cloudflare Pages SSR (output:'server' + @astrojs/cloudflare), the 404.astro page must NOT be prerendered (no `export const prerender = true`); the Worker should produce the 404 with status set explicitly. A prerendered 404 in SSR mode triggers Cloudflare error 1042/522 instead of the custom page (GitHub astro#13932).","why":"Returning 5xx (or 200) instead of a proper 404 corrupts Google's understanding of missing pages and harms crawl/index quality; the cross-Worker fetch from a prerendered 404 is blocked by Cloudflare.","fix":"Create src/pages/404.astro without prerender, set `Astro.response.status = 404` in frontmatter; or use a catch-all [...slug].astro that returns 404 when a path does not exist.","how_to_check":"`curl -sI https://[project].pages.dev/nonexistent-page-xyz | grep HTTP` must return 404 (not 200 or 5xx); re-test on the custom domain.","common_mistakes":"Adding `export const prerender = true` to 404.astro on Pages SSR (triggers error 1042); forgetting to set Astro.response.status = 404 in SSR mode.","platform_notes":"Cloudflare Pages SSR-specific. On Vercel SSR, set the 404 status explicitly but the prerender restriction does not apply.","sources":["https://github.com/withastro/astro/issues/13932","https://developers.cloudflare.com/pages/configuration/serving-pages/"]},{"id":"platform-default-domain-noindex","section":"platform","title":"Block the platform default domain (*.pages.dev / *.vercel.app) from indexing","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_header","what":"The production platform default hostname must not be indexable alongside the custom domain. Vercel auto-noindexes *.vercel.app; Cloudflare Pages does NOT auto-noindex the production *.pages.dev URL, so it requires manual action.","why":"Production builds are served on both the default host and the custom domain simultaneously; without noindex or a redirect on the default host, Google can index both, creating duplicate content. Cloudflare is the bigger risk.","fix":"Cloudflare SSR: in src/middleware.ts redirect when hostname.endsWith('.pages.dev') to the canonical domain (301). Cloudflare static (no adapter): use a Cloudflare WAF/Redirect Rule targeting the *.pages.dev hostname — _headers/_redirects cannot match on hostname. Vercel: automatic, no action needed.","how_to_check":"`curl -sI https://mysite.pages.dev | grep -i 'x-robots-tag\\|location'` must show noindex or a 301 to the custom domain; `curl -sI https://mysite.vercel.app | grep -i x-robots-tag` shows noindex (automatic).","common_mistakes":"Assuming Cloudflare auto-noindexes production *.pages.dev (it does not); trying to match the *.pages.dev hostname in _headers/_redirects (path-based only, no hostname matching).","platform_notes":"Cloudflare-specific manual gap; static sites need the WAF rule since there is no server layer. Vercel handles it automatically.","sources":["https://vercel.com/kb/guide/avoiding-duplicate-content-with-vercel-app-urls","https://developers.cloudflare.com/pages/configuration/preview-deployments/"]},{"id":"platform-jsonld-no-xss-injection","section":"platform","title":"Inject JSON-LD only via JSON.stringify, never template literals","severity":"high","stage":"build","automatable":true,"check_type":"body_regex","what":"Every dynamic value placed into a JSON-LD <script type='application/ld+json'> block must be serialized with JSON.stringify() (which escapes </script> and quotes), never via raw string concatenation or template literals.","why":"A title like `</script><script>alert(1)</script>` interpolated via template literal into JSON-LD executes arbitrary JS; neither Cloudflare Pages nor Vercel sanitizes user data embedded in script tags. A real Astro XSS (SNYK-JS-ASTRO-7547139) underscores the risk.","fix":"Always pass an object: `<script type=\"application/ld+json\" set:html={JSON.stringify(schemaObj)} />`, or use the astro-seo-schema package. Never `set:html={`{\"headline\":\"${post.data.title}\"}`}`. Enforce with an ESLint rule in CI.","how_to_check":"Static analysis: grep Astro source for set:html on script[type='application/ld+json'] and assert every occurrence wraps a JSON.stringify(...) object, not a template literal.","common_mistakes":"Using string interpolation for 'simple' schemas; copying older tutorial code that uses template literals.","platform_notes":"No platform difference; neither host server-side-sanitizes embedded user data.","sources":["https://stephen-lunt.dev/blog/astro-structured-data/","https://docs.astro.build/en/reference/directives-reference/","https://security.snyk.io/vuln/SNYK-JS-ASTRO-7547139"]},{"id":"platform-output-hybrid-removed","section":"platform","title":"Remove output:'hybrid' (removed in Astro v5) and use per-page prerender opt-in","severity":"high","stage":"build","automatable":true,"check_type":"body_regex","what":"Astro v5 removed output:'hybrid' entirely (breaking change). output:'static' now prerenders all pages by default with per-page on-demand SSR via `export const prerender = false`; output:'server' SSRs all pages with `export const prerender = true` to opt pages into static.","why":"Leaving output:'hybrid' in a v5 project causes a build error or invalid configuration; the migration is trivial but mandatory after upgrading.","fix":"Delete output:'hybrid' (or set output:'static') in astro.config.mjs — behavior matches the old hybrid. Add `export const prerender = false` to any page needing on-demand SSR; audit prerender directives after migrating.","how_to_check":"Grep astro.config.mjs for output:'hybrid' and assert absent; run `npx astro build` and assert no output-mode errors/deprecation warnings.","common_mistakes":"Carrying output:'hybrid' from a v4 project after upgrading; not re-auditing which pages have prerender directives post-migration.","platform_notes":"Applies equally to Cloudflare Pages and Vercel.","sources":["https://docs.astro.build/en/guides/upgrade-to/v5/","https://astro.build/blog/astro-5/"]},{"id":"platform-preview-deployments-noindex","section":"platform","title":"Ensure preview/staging deployments return X-Robots-Tag: noindex","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_header","what":"Every preview/staging deployment must serve X-Robots-Tag: noindex, including the gap where a custom domain is attached to a non-production branch (Vercel does NOT auto-noindex custom domains, only *.vercel.app system URLs).","why":"Preview deployments are exact replicas of production; if indexed they create large-scale duplicate content and may leak unreleased pages.","fix":"Rely on platform defaults for *.vercel.app and *.pages.dev preview hashes. For custom staging domains, add X-Robots-Tag: noindex in Astro middleware (src/middleware.ts) gated on VERCEL_ENV !== 'production' or CF_PAGES_BRANCH !== production branch. Use the HTTP header rather than robots.txt Disallow (immediate, no redeploy to flip).","how_to_check":"`curl -sI https://<preview-hash>.vercel.app` and `https://<preview-hash>.pages.dev` (and any staging custom domain) | grep -i x-robots-tag must contain noindex; confirm the production custom domain does NOT carry it.","common_mistakes":"Assuming Vercel auto-noindexes custom domains on non-production branches (it does not); serving a crawlable sitemap from a preview URL before launch.","platform_notes":"Cloudflare: all preview branch hashes auto-noindex regardless of custom domain. Vercel: only *.vercel.app system URLs auto-noindex; custom domains on non-prod branches need manual config (GitHub discussion #5714).","sources":["https://vercel.com/kb/guide/are-vercel-preview-deployment-indexed-by-search-engines","https://developers.cloudflare.com/pages/configuration/preview-deployments/"]},{"id":"platform-remote-image-allowlist-and-service","section":"platform","title":"Allowlist remote image domains and configure the right SSR image service","severity":"high","stage":"build","automatable":true,"check_type":"http_status","what":"Remote images used by astro:assets <Image/>/getImage() must have their hostname in image.domains[] or image.remotePatterns[]. For Cloudflare SSR, configure the @astrojs/cloudflare imageService option (Sharp does not run in workerd); the current default is 'cloudflare-binding'.","why":"Unallowlisted remote images bypass optimization and can cause SSR runtime errors / SSRF exposure. On Cloudflare SSR, Sharp needs Node native binaries unavailable in the V8 isolate runtime, so astro:assets throws or serves unoptimized images without the correct service.","fix":"astro.config.mjs: `image: { domains: ['cdn.example.com'], remotePatterns: [{ protocol:'https', hostname:'**.cloudinary.com' }] }` (use remotePatterns for wildcard subdomains; domains[] has no wildcards). Cloudflare SSR: `adapter: cloudflare({ imageService: 'cloudflare-binding' })` (or 'cloudflare' for /cdn-cgi/image/, 'compile' for prerendered-only). Never imageService:'custom' with Sharp on Cloudflare.","how_to_check":"Assert image.domains/remotePatterns is non-empty if any remote <img src> uses astro:assets, and each remote hostname appears in the allowlist. Vercel: /_vercel/image?url= 400s indicate unlisted domains. Cloudflare SSR: confirm <Image/> src is a Cloudflare Images or /cdn-cgi/image/ URL and image endpoints return no 5xx.","common_mistakes":"Bare domain string where a wildcard is needed; overly broad hostname:'*'; not updating allowlist after switching CDN; deploying Cloudflare SSR with imageService:'custom'+Sharp (runtime crash) or stale 'compile' silently serving unoptimized SSR images.","platform_notes":"Vercel optimizes via /_vercel/image automatically (only allowlisted domains). Cloudflare SSR needs the adapter imageService option; static Cloudflare output runs Sharp at build time and is unaffected.","sources":["https://docs.astro.build/en/guides/images/","https://docs.astro.build/en/guides/integrations-guide/cloudflare/","https://vercel.com/docs/image-optimization"]},{"id":"platform-security-headers-baseline","section":"platform","title":"Set the baseline security headers (HSTS, nosniff, frame-ancestors, Referrer-Policy, Permissions-Policy)","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_header","what":"Every HTTPS response should carry the baseline security header set: Strict-Transport-Security (max-age >= 31536000, includeSubDomains, preload), X-Content-Type-Options: nosniff, clickjacking protection via Content-Security-Policy: frame-ancestors 'none' (with X-Frame-Options: DENY legacy fallback), Referrer-Policy: strict-origin-when-cross-origin, and a Permissions-Policy disabling unused features (camera, microphone, geolocation, payment, usb).","why":"These headers are baseline controls expected by security scanners and protect against SSL-stripping, MIME-sniffing execution, clickjacking, referrer leakage, and silent device/API access. (Note: HSTS itself is not a ranking signal — HTTPS is — but it is core security/trust.)","fix":"Cloudflare static: add a /* block in public/_headers with all five headers. Cloudflare SSR: set them in Astro middleware (_headers does not cover Worker responses). Vercel: add them under vercel.json `headers` for source '/(.*)'. Use the parenthesis Permissions-Policy syntax (not deprecated Feature-Policy); frame-ancestors must be an HTTP header (meta CSP does not support it).","how_to_check":"`curl -sI https://www.example.com` and assert: strict-transport-security max-age>=31536000+includeSubDomains; x-content-type-options: nosniff; content-security-policy contains frame-ancestors 'none'/'self'; referrer-policy: strict-origin-when-cross-origin; permissions-policy present with camera=(), microphone=(), geolocation=(). Cross-check securityheaders.com.","common_mistakes":"HSTS max-age < 31536000 (blocks preload); enabling preload before all subdomains are HTTPS; setting frame-ancestors via meta tag; using deprecated Feature-Policy syntax; using Referrer-Policy: no-referrer (breaks analytics); on Cloudflare SSR relying on _headers.","platform_notes":"Cloudflare also has an HSTS toggle in SSL/TLS > Edge Certificates — use either the toggle OR _headers, not both (they can conflict). On Cloudflare SSR, set all of these in middleware.","sources":["https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers/Strict-Transport-Security","https://cheatsheetseries.owasp.org/cheatsheets/Clickjacking_Defense_Cheat_Sheet.html","https://developers.cloudflare.com/pages/configuration/headers/"]},{"id":"platform-trailingslash-consistent","section":"platform","title":"Keep trailingSlash config consistent with build.format and platform routing","severity":"high","stage":"build","automatable":true,"check_type":"redirect","what":"astro.config.mjs trailingSlash must match build.format and the host's routing so each URL has exactly one canonical form. Lock it before launch instead of leaving the default 'ignore', which lets both /page and /page/ be indexed.","why":"Trailing-slash inconsistency makes Google treat /page and /page/ as separate pages, splitting link equity, and can cause redirect loops or 404s depending on adapter/host behavior.","fix":"Clean URLs: trailingSlash:'never' + build.format:'file'. Trailing slash: trailingSlash:'always' + build.format:'directory'. Verify vercel.json has no conflicting trailingSlash. (Note: output:'hybrid' is removed in v5 — use output:'static' with per-page prerender opt-in.)","how_to_check":"In dist/ confirm files match the chosen format (/about.html vs /about/index.html). Live: GET /about and /about/ — exactly one returns 200, the other 301/308 to the canonical form.","common_mistakes":"Leaving trailingSlash:'ignore' in production; mixing 'always' with build.format:'file'; conflicting trailingSlash in vercel.json (GitHub astro#13900).","platform_notes":"Cloudflare Pages serves /page/index.html at both /page and /page/ unless normalized; Vercel filesystem routing can differ from Cloudflare for the same build output.","sources":["https://docs.astro.build/en/reference/configuration-reference/","https://github.com/withastro/astro/issues/13900"]},{"id":"platform-www-apex-canonical-redirect","section":"platform","title":"Pick one canonical host (www or apex) and 301/308 redirect the other","severity":"high","stage":"pre-launch","automatable":true,"check_type":"redirect","what":"Both www and apex must resolve, but exactly one is canonical and the other issues a permanent (301/308) redirect to it. Never serve identical 200 content on both hostnames.","why":"Serving the same site on www.example.com and example.com is classic duplicate content; Google's consolidation is imperfect and may pick the wrong variant, splitting link equity.","fix":"Vercel: add BOTH www and apex in Project Settings > Domains and set the non-canonical one to redirect to the primary. Cloudflare Pages: domain-level (www↔apex) redirects are NOT supported in _redirects — use Cloudflare Bulk Redirects / Redirect Rules in the dashboard.","how_to_check":"`curl -sI https://<non-canonical>` returns 301/308 with Location to the canonical host; `curl -sI https://<canonical>` returns 200. Assert status is 301/308, not 302.","common_mistakes":"Using 302 instead of 301/308; configuring the redirect in Cloudflare _redirects (no hostname matching); adding only one variant on Vercel (the other returns an error page); leaving both at 200.","platform_notes":"Cloudflare: use Bulk Redirects (Rules > Redirect Rules), not _redirects. Vercel: both variants must be added to the project with an explicit redirect direction.","sources":["https://developers.cloudflare.com/pages/how-to/www-redirect/","https://vercel.com/docs/domains/set-up-custom-domain"]},{"id":"platform-cloudflare-redirects-and-headers-limits","section":"platform","title":"Cloudflare: stay within _redirects (2000/100) and _headers (100) rule limits","severity":"medium","stage":"build","automatable":true,"check_type":"redirect","what":"Cloudflare Pages silently ignores rules beyond its limits: _redirects supports 2,000 static + 100 dynamic redirects (1,000-char per line); _headers supports 100 rules (2,000-char per value). Silently dropped rules mean old URLs 404 or security/cache headers go missing.","why":"Dropped redirect rules cause 404s on old URLs (lost ranking signals); dropped header rules create hard-to-detect security gaps — both fail silently with no build error.","fix":"Count lines before deploy (`wc -l public/_redirects`, `grep -c '^/' public/_headers`); put static redirects before dynamic ones; use wildcard /* header blocks instead of per-path rules. Beyond the limits use Cloudflare Bulk Redirects (dashboard) or move logic into Astro middleware.","how_to_check":"Assert `wc -l public/_redirects` < 2100 (wildcard rules count toward the 100 dynamic cap) and `grep -c '^/' public/_headers` < 100; after deploy, test a rule near the bottom of each file to confirm it is honored.","common_mistakes":"Per-page header rules exhausting the 100-rule cap; dynamic rules placed before static; exceeding the 1,000-char per-redirect limit; not realizing wildcards count as dynamic.","platform_notes":"Cloudflare Pages-specific. Vercel allows ~2,048 routes in vercel.json and a bulkRedirectsPath for large sets; for very large redirect sets an edge/middleware solution scales better on either platform.","sources":["https://developers.cloudflare.com/pages/configuration/redirects/","https://developers.cloudflare.com/pages/platform/limits/"]},{"id":"platform-cloudflare-worker-memory-limit","section":"platform","title":"Cloudflare SSR: keep the Worker within the 128 MB isolate memory limit","severity":"medium","stage":"build","automatable":false,"check_type":"manual","what":"Cloudflare Workers / Pages Functions have a 128 MB per-isolate memory limit. Heavy Node dependencies bundled into SSR pages cause runtime crashes (Error 1102) that serve 5xx to users and Googlebot.","why":"Repeated 5xx errors from memory exhaustion lead Googlebot to deindex affected pages and degrade crawl health.","fix":"Test in the workerd runtime with `wrangler pages dev` and watch `wrangler tail`. Avoid bundling heavy libs (image processing, large parsers) into SSR pages; move heavy pages to build time with `export const prerender = true`; offload heavy work to external APIs or Workers AI.","how_to_check":"Load-test the most complex SSR pages on staging and monitor Cloudflare Analytics > Workers for Error 1102 spikes; run `wrangler tail` during load to catch memory-limit errors.","common_mistakes":"Importing large server-side libraries directly in Cloudflare SSR page components; not testing with workerd before deploying (Node behavior differs).","platform_notes":"Cloudflare-specific (128 MB per isolate, current 2025-2026). Vercel functions default to 1 GB (configurable up to 3 GB on Pro), so this is not a Vercel concern.","sources":["https://developers.cloudflare.com/workers/platform/limits/","https://developers.cloudflare.com/workers/framework-guides/web-apps/astro/"]},{"id":"platform-content-security-policy","section":"platform","title":"Ship a Content-Security-Policy (use Astro's CSP to drop unsafe-inline)","severity":"medium","stage":"build","automatable":true,"check_type":"http_header","what":"HTML responses should carry a Content-Security-Policy. A minimal baseline for a content site: `default-src 'self'; img-src 'self' data: https:; frame-ancestors 'none'; upgrade-insecure-requests`. Prefer Astro's CSP support (v5.9+ `security: { csp: true }`) to auto-hash inline island scripts and eliminate unsafe-inline.","why":"A well-configured CSP is the primary XSS defense; absence is flagged by Lighthouse and scanners. Astro auto-generates SHA hashes for hydration scripts that a hand-written CSP cannot cover without unsafe-inline.","fix":"Enable `export default defineConfig({ security: { csp: true } })` (adds a `<meta http-equiv=content-security-policy>` with hashes). Supplement with an HTTP CSP header for directives meta cannot set (frame-ancestors) via _headers (CF static) / vercel.json / middleware (CF SSR). Avoid global unsafe-inline. Astro CSP does not support ClientRouter, Shiki, or dev mode — test with `astro build && astro preview`.","how_to_check":"`curl -sI https://www.example.com | grep -i content-security-policy` shows at least default-src and frame-ancestors; or in built HTML <head> assert a CSP meta with sha256-/sha384- hashes and no unsafe-inline. Confirm zero CSP violations in DevTools console; optionally run csp-evaluator.withgoogle.com.","common_mistakes":"Using only a meta tag (no frame-ancestors/form-action support); global unsafe-inline nullifying protection; enabling Astro CSP with ClientRouter/Shiki without manual hashing; testing only in `astro dev` (CSP off there); on Cloudflare SSR relying on _headers.","platform_notes":"Astro CSP uses meta delivery so works on both CF and Vercel static. Cloudflare SSR: HTTP CSP must be set in middleware, not _headers.","sources":["https://docs.astro.build/en/reference/experimental-flags/csp/","https://csp-evaluator.withgoogle.com","https://developers.cloudflare.com/pages/configuration/headers/"]},{"id":"platform-vercel-headers-no-conflict","section":"platform","title":"Vercel: avoid duplicate/conflicting headers between vercel.json and adapter output","severity":"medium","stage":"build","automatable":true,"check_type":"http_header","what":"@astrojs/vercel can write headers/routes to .vercel/output/config.json during build (e.g., via the staticHeaders option). A hand-maintained root vercel.json with overlapping patterns can produce duplicate or comma-joined conflicting headers (e.g., two Cache-Control or two CSP values).","why":"Comma-joined or conflicting header values can be misinterpreted by browsers, and conflicting redirect rules cause unexpected behavior.","fix":"After `astro build`, review .vercel/output/config.json against root vercel.json and keep source patterns non-overlapping. Prefer setting SSR-specific headers in Astro middleware OR vercel.json — not both for the same directive. (staticHeaders replaced experimentalStaticHeaders; a bug existed in v5.10.0 — verify on your version.)","how_to_check":"Inspect .vercel/output/config.json headers/routes vs root vercel.json. Live: `curl -sI https://www.example.com | grep -i cache-control` must return a single value, not a comma-joined pair; no header should appear twice.","common_mistakes":"Maintaining root vercel.json and adapter-generated config with overlapping routes; setting CSP in both vercel.json and middleware (producing an invalid joined CSP).","platform_notes":"Vercel-specific; not applicable to Cloudflare Pages.","sources":["https://docs.astro.build/en/guides/integrations-guide/vercel/","https://vercel.com/docs/project-configuration/vercel-json","https://github.com/withastro/astro/issues/13996"]},{"id":"platform-security-txt-present","section":"platform","title":"Serve an RFC 9116 security.txt at /.well-known/security.txt","severity":"low","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"Serve a security.txt (RFC 9116) at https://example.com/.well-known/security.txt over HTTPS as text/plain with at least Contact and a future-dated Expires field.","why":"Standardizes vulnerability disclosure; not a ranking factor but a trust signal, and only ~1.25% of the top 1M domains implement it correctly — easy differentiation.","fix":"Create public/.well-known/security.txt with `Contact: mailto:security@example.com`, `Expires: 2027-01-01T00:00:00Z`, `Canonical: https://example.com/.well-known/security.txt`, `Preferred-Languages: en`. The public/ dir maps to the build root; update Expires annually.","how_to_check":"`curl -s https://example.com/.well-known/security.txt | grep -E '^(Contact|Expires):'`; assert 200, Content-Type text/plain, and an Expires date in the future.","common_mistakes":"Past-dated (stale/invalid) Expires; serving as text/html; missing the Expires field.","platform_notes":"No special config on either Cloudflare Pages or Vercel.","sources":["https://securitytxt.org/","https://datatracker.ietf.org/doc/rfc9116/","https://www.uriports.com/blog/security-txt-in-2025/"]},{"id":"trust-analytics-installed-firing","section":"trust","title":"Analytics installed sitewide and firing pageviews (including on View Transitions)","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"body_regex","what":"A web analytics solution (GA4, Plausible, Cloudflare/Vercel Web Analytics, Fathom) is present in a shared layout on every page and confirmed to send pageview events. If ClientRouter (<ViewTransitions />) is enabled, pageviews must also re-fire on client-side navigation.","why":"Without working analytics there is no traffic, conversion, or SEO baseline data — and it can never be recovered retroactively. With ClientRouter, scripts that only fire on initial load miss 80-95% of navigations, so multi-page sessions collapse to single-page sessions and bounce rate is massively overstated.","fix":"Add the analytics snippet to a shared BaseLayout.astro <head>. For GA4/GTM inline scripts use is:inline; for external-src scripts (Plausible) do NOT use is:inline (it applies only to inline bodies). For ClientRouter, re-fire pageviews on the astro:page-load event (NOT astro:after-swap, which fires before the page is visible): document.addEventListener('astro:page-load', () => gtag('event','page_view',{page_path:location.pathname})). If GA4 sends its own pageview, set { send_page_view: false } to avoid double counting. Plausible and Cloudflare/Vercel beacons hook history.pushState automatically and need no extra wiring.","how_to_check":"Fetch page HTML and assert an analytics script tag in <head>. Then run a headless browser: load the page and assert a request to www.google-analytics.com/g/collect, plausible.io/api/event, or cloudflareinsights.com/cdn-cgi/rum fires within 5s. With ClientRouter, navigate A→B without a full reload and assert two distinct pageview events with different paths.","common_mistakes":"Using astro:after-swap instead of astro:page-load; double-counting by leaving GA4 auto pageview on while also firing manually; adding is:inline to an external-src script; installing analytics only on the homepage layout; CF Web Analytics auto-inject silently failing when a Cache-Control: no-transform header is present.","platform_notes":"Cloudflare Web Analytics auto-inject fails silently with Cache-Control: no-transform — use the manual beacon snippet as fallback. Vercel Analytics is opt-in via @vercel/analytics: add the <Analytics /> component to the layout.","sources":["https://docs.astro.build/en/guides/view-transitions/","https://developers.cloudflare.com/web-analytics/get-started/","https://webreaper.dev/posts/astro-google-tag-manager-ga4/"]},{"id":"trust-cookie-consent-gdpr","section":"trust","title":"Cookie consent banner gating non-essential scripts (GDPR / ePrivacy)","severity":"critical","stage":"pre-launch","automatable":false,"check_type":"manual","what":"If the site sets cookies or persistent identifiers for analytics/ads/tracking (GA4 without Consent Mode v2, Meta Pixel, Hotjar), an opt-in consent banner must be shown to EU visitors and those scripts must not load before consent is granted.","why":"The EU/UK ePrivacy Directive requires prior informed opt-in for non-essential cookies; GDPR fines reach €20M or 4% of global turnover (CNIL fined Google €325M in Sept 2025 for banner dark patterns). GA4 without Consent Mode v2 must not load before consent.","fix":"Prefer cookieless analytics (Plausible, Cloudflare/Vercel Web Analytics) to avoid a banner entirely. If using GA4, deploy a CMP (CookieYes, Usercentrics) with Consent Mode v2 where all four signals (ad_storage, ad_user_data, ad_personalization, analytics_storage) default to 'denied' for EU users, and gate script injection behind CMP callbacks. Defaulting to 'granted' is the single most common violation.","how_to_check":"Load the site from an EU locale (Accept-Language: de) in a private window and intercept all network requests for the first 5s: assert no analytics/tracking requests fire before interacting with the consent dialog. Confirm no _ga cookie exists pre-consent (DevTools → Application → Cookies) and that no consent checkbox is pre-checked.","common_mistakes":"Pre-checking analytics in the banner; setting Consent Mode v2 default to 'granted'; not gating Hotjar/Meta Pixel behind consent; assuming Cloudflare/Vercel Web Analytics never needs any legal basis (no cookie is set, but US data transfer may still need a Schrems II assessment).","platform_notes":"Cloudflare and Vercel Web Analytics are cookieless and generally need no banner for the beacon itself, but both process data on US infrastructure — verify adequacy/Schrems II coverage for your jurisdiction.","sources":["https://plausible.io/blog/legal-assessment-gdpr-eprivacy","https://www.bounteous.com/insights/2025/07/30/top-7-google-consent-mode-mistakes-and-how-fix-them-2025/","https://www.goodwinlaw.com/en/insights/publications/2025/09/insights-practices-dpc-cnil-imposes-record-325-million-fine"]},{"id":"trust-gsc-domain-property-dns-verified","section":"trust","title":"Google Search Console Domain property verified via DNS TXT (not only HTML tag)","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"robots","what":"A GSC Domain property (covers all protocols and subdomains) is created and verified using a DNS TXT record. The HTML meta-tag method must not be the sole verification method.","why":"Without verification you cannot submit sitemaps, inspect URLs, see crawl errors, or read CWV field data. Only the Domain property type covers https/http and www/non-www under one property. HTML-tag verification is fragile — any layout/BaseHead refactor that drops the tag revokes access; DNS TXT survives full rebuilds, a known cause of post-launch SEO monitoring outages.","fix":"No Astro code needed. Add a TXT record on the apex (@): google-site-verification=<token> at your registrar or Cloudflare DNS panel, wait for propagation, then verify the Domain property in GSC. Keep the meta tag only as a secondary method. Persist the TXT record indefinitely — GSC re-checks ownership and will unverify if it is removed.","how_to_check":"Run dig TXT example.com and assert a google-site-verification= record is present. Confirm in GSC → Settings → Ownership verification that the Domain property shows 'Verified' via the DNS method. Optionally remove the HTML meta tag on a test branch, redeploy, and confirm GSC still shows verified.","common_mistakes":"Using a URL-prefix property (misses http:// and www variants); relying only on the HTML meta tag and losing access after a BaseHead refactor; adding the TXT record on www instead of the apex; removing the TXT record after first verification.","platform_notes":"Cloudflare Pages: add the TXT record in the Cloudflare DNS dashboard (domain already proxied through CF). Vercel with a custom domain: add via the registrar's DNS panel or Vercel's DNS tab.","sources":["https://support.google.com/webmasters/answer/9008080?hl=en","https://www.incremys.com/en/resources/blog/google-search-console-validation"]},{"id":"trust-gsc-sitemap-submitted","section":"trust","title":"Sitemap submitted to Google Search Console with zero errors","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"sitemap","what":"The sitemap-index.xml produced by @astrojs/sitemap is submitted in GSC (Sitemaps → Add a new sitemap) and reports Success with 0 errors, with submitted URL count matching the page count.","why":"Submitting accelerates initial crawl and surfaces submitted-vs-indexed counts, warnings, and errors. Without it, Googlebot discovers pages only via links, which can take days to weeks for a new domain.","fix":"Install @astrojs/sitemap and set site in astro.config.mjs: defineConfig({ site:'https://example.com', integrations:[sitemap()] }). The build emits /sitemap-index.xml and /sitemap-0.xml. Add 'Sitemap: https://example.com/sitemap-index.xml' to public/robots.txt. Submit the index (not sitemap-0.xml) in GSC.","how_to_check":"GET https://example.com/sitemap-index.xml → 200, Content-Type application/xml, valid XML with at least one <sitemap> child. In GSC → Sitemaps assert Status = Success and a plausible discovered-URL count.","common_mistakes":"Omitting site in astro.config.mjs (sitemap URLs become relative/invalid); over-aggressive filter excluding key pages; submitting sitemap-0.xml instead of the index.","platform_notes":"Both Cloudflare Pages and Vercel serve the sitemap as a static file in static output mode; no adapter changes needed.","sources":["https://docs.astro.build/en/guides/integrations-guide/sitemap/","https://developers.google.com/search/docs/crawling-indexing/sitemaps/build-sitemap"]},{"id":"trust-about-contact-pages-present","section":"trust","title":"About and Contact pages present with real info and a working contact method","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"An About page (real people/organization, credentials, history) and a Contact page (working email, contact form, or physical address) both exist, are publicly accessible, and are linked from nav and/or footer.","why":"Google's Quality Rater Guidelines evaluate 'who is responsible for this site' and the ease of contacting the owner as primary trust factors; their absence lowers quality ratings. GDPR also requires a contact method for data subject requests.","fix":"Create src/pages/about.astro with named individuals, photos (Astro <Image /> with alt text), roles, and Person schema; create src/pages/contact.astro with a mailto: fallback plus a form wired to a serverless/third-party handler (Astro static output cannot process forms). Link both from header nav and/or footer.","how_to_check":"GET the homepage and assert nav/footer <a> links to /about and /contact. GET /about → 200 with >200 words (non-placeholder heuristic). GET /contact → 200 with a mailto: link or a <form> with an action/endpoint.","common_mistakes":"Boilerplate About text with only the name swapped; no named individuals for people-oriented businesses; a contact form with no working backend; an email shown as an image (not crawlable/accessible).","platform_notes":"Form handling: Cloudflare Workers (CF Pages) or Vercel Functions; both also support Formspree/Web3Forms for static forms.","sources":["https://magcloudsolutions.com/2026/01/15/e-e-a-t-explained-how-to-build-trust-and-authority-for-seo-2026-guide/","https://hyfweb.com/e-e-a-t-seo-in-2026-to-build-trust-signals-that-rank/"]},{"id":"trust-author-bio-pages-present","section":"trust","title":"Author bio pages exist for every author referenced in Article schema","severity":"high","stage":"pre-launch","automatable":true,"check_type":"json_ld","what":"Every author named in Article/BlogPosting JSON-LD has a live bio page at the schema's author.url, containing name, photo, credentials, experience, and professional profile links.","why":"Author bios paired with author schema are core E-E-A-T components in 2026, especially for YMYL content where Google weighs author credentials. An orphaned author.url that 404s is worse than no schema.","fix":"Use an Astro content collection (src/content/authors/*.md) and generate pages with getStaticPaths() over getCollection('authors'). In Astro v5, route by entry id, NOT slug (a v5 breaking change). Link each article to its author bio page.","how_to_check":"Extract every author.url from Article JSON-LD across the site and GET each one; assert all return 200 with body word count > 100.","common_mistakes":"author.url that 404s; a generic 'Editorial Team' author on all posts; not linking articles to bio pages; using slug instead of id in v5 content-collection routing.","platform_notes":"No platform differences.","sources":["https://hyfweb.com/e-e-a-t-seo-in-2026-to-build-trust-signals-that-rank/","https://docs.astro.build/en/guides/upgrade-to/v5/"]},{"id":"trust-bing-webmaster-verified-sitemap","section":"trust","title":"Bing Webmaster Tools verified and sitemap submitted","severity":"high","stage":"pre-launch","automatable":true,"check_type":"external_tool","what":"A Bing Webmaster Tools property is verified (CNAME DNS record, meta tag, or XML file) and the sitemap URL is submitted in its Sitemaps section.","why":"Bing/DuckDuckGo/Yahoo together hold roughly 15-25% of US/UK desktop search, and Bing-native IndexNow signals feed multiple engines. Without BWT you have no visibility into Bing crawl, indexation, or security alerts.","fix":"Prefer the DNS CNAME method (no code changes). Otherwise add <meta name='msvalidate.01' content='<VALUE>' /> to the <head> of BaseLayout.astro. Submit https://example.com/sitemap-index.xml in the BWT UI.","how_to_check":"Query the Bing Webmaster API /sites endpoint and assert the site is verified, or GET the homepage and parse for <meta name='msvalidate.01'> (meta method), or confirm the CNAME via dig. In BWT confirm Verified = Yes and the sitemap is listed.","common_mistakes":"Relying on the one-time GSC auto-import (later GSC changes don't sync); not re-submitting the sitemap after a major URL-structure change.","platform_notes":"No platform-specific sitemap differences; CNAME availability may vary by registrar.","sources":["https://blogs.bing.com/webmaster/July-2025/Keeping-Content-Discoverable-with-Sitemaps-in-AI-Powered-Search"]},{"id":"trust-cwv-rum-and-gsc-monitoring","section":"trust","title":"Core Web Vitals monitored via RUM and the GSC CWV report","severity":"high","stage":"post-launch","automatable":true,"check_type":"lighthouse","what":"Real-user CWV (LCP, INP, CLS) are collected immediately via RUM (web-vitals library or a RUM tool), and after ~28 days of traffic the GSC Core Web Vitals report is reviewed with remediation underway for any 'Poor' URLs (LCP >4s, INP >500ms, CLS >0.25).","why":"Lighthouse lab runs cannot measure INP and CrUX lags 28 days, so RUM is the only immediate field signal; GSC then provides ongoing field data. CWV are confirmed page-experience ranking signals (FID was retired and replaced by INP on March 12, 2024).","fix":"npm install web-vitals and report from a deferred/idle inline script in Layout.astro: onLCP(send); onINP(send); onCLS(send) (load with client:idle, not client:load, to avoid TBT). Lean on Astro strengths: <Image /> for intrinsic width/height (no CLS) and AVIF/WebP; client:visible/client:idle over client:load for INP; loading='eager' + fetchpriority='high' on the LCP hero image.","how_to_check":"Confirm web-vitals (or a verified RUM integration) in package.json and built HTML. For field data use the PageSpeed Insights API (strategy=mobile) and assert loadingExperience LCP category 'FAST' and INTERACTION_TO_NEXT_PAINT category not 'SLOW'; add Lighthouse CI gates (LCP <2500ms, CLS <0.1). In GSC → Core Web Vitals, confirm zero 'Poor' URLs or an active remediation plan.","common_mistakes":"Relying solely on desktop Lighthouse (CrUX is mobile-weighted, no INP); reporting metrics nowhere; loading web-vitals with client:load; still referencing FID; ignoring CLS from web fonts shifting layout.","platform_notes":"Cloudflare and Vercel edge caching improve TTFB but do not fix the in-browser LCP/INP/CLS metrics. Cloudflare Web Analytics and Vercel Analytics can both report CWV as a zero/low-JS RUM option.","sources":["https://github.com/GoogleChrome/web-vitals","https://developers.google.com/search/docs/appearance/core-web-vitals","https://web.dev/blog/inp-cwv-march-12"]},{"id":"trust-error-monitoring-configured","section":"trust","title":"JavaScript error/exception monitoring configured with source maps","severity":"high","stage":"post-launch","automatable":true,"check_type":"external_tool","what":"A client-side (and, in SSR mode, server-side) error monitor captures JS exceptions, unhandled rejections, and network errors, with source maps uploaded and alerting on error-rate spikes.","why":"Undetected JS errors cause invisible UX failures (broken forms, search, navigation) that hurt conversions and dwell time; post-launch JS regressions are common and invisible without monitoring.","fix":"npm install @sentry/astro and add to astro.config.mjs: sentry({ dsn: import.meta.env.SENTRY_DSN, sourceMapsUploadOptions: { project:'my-project', authToken: import.meta.env.SENTRY_AUTH_TOKEN } }). SSR mode auto-adds middleware for server capture (Astro >= 3.5.2); static output captures client-side errors only. Guard against init in dev only.","how_to_check":"From the live site console run Sentry.captureException(new Error('test')) and confirm it appears in the Sentry dashboard within ~60s with a readable (source-mapped) stack trace. Alternatively assert the Sentry init script is present in page HTML.","common_mistakes":"Init gated to development only (excluded in prod via NODE_ENV); missing sourceMapsUploadOptions (minified traces); expecting server-side capture in static output (client-only there).","platform_notes":"Cloudflare Pages: @sentry/astro for client errors, @sentry/cloudflare for Workers/SSR; OTLP log export to Sentry available (GA Sept 2025). Vercel: use the Sentry log drain integration for build and runtime logs.","sources":["https://docs.sentry.io/platforms/javascript/guides/astro/","https://sentry.io/changelog/log-drains-for-cloudflare-vercel-heroku-and-supabase/"]},{"id":"trust-gsc-indexation-no-staging-noindex","section":"trust","title":"Post-launch GSC indexing review; no staging noindex/robots leak in production","severity":"high","stage":"post-launch","automatable":true,"check_type":"html_element","what":"Within 1-4 weeks of launch the GSC Page Indexing report is reviewed so indexed pages roughly match sitemap count, and significant Excluded/Error categories (5xx, redirect error, blocked by robots.txt, noindex) are investigated. Production must carry no leftover staging noindex tag or Disallow.","why":"Newly launched sites frequently ship accidental noindex tags or a staging Disallow: / that block indexation of key pages. The GSC indexing report is the only reliable confirmation Googlebot successfully processed pages.","fix":"Audit before deploy: grep -r 'noindex' src/layouts/ and check public/robots.txt. Gate any staging-only noindex behind a production env flag (e.g. PUBLIC_SITE_ENV) so the layout never emits it in production. Verify live with curl -A 'Googlebot' https://example.com/robots.txt.","how_to_check":"GET each key URL and assert no X-Robots-Tag: noindex header and no <meta name='robots' content='noindex'> in HTML. Use the GSC URL Inspection API (urlInspectionResult.indexingState) and review Indexing → Pages for unexpected exclusions.","common_mistakes":"Shipping production with the staging noindex meta still in the layout; copying a Disallow: / robots.txt from staging; expecting instant indexation (new sites may take 4-14 days for first crawl).","platform_notes":"On both Cloudflare Pages and Vercel, set a production-specific env variable so the layout conditionally omits staging-only noindex tags.","sources":["https://support.google.com/webmasters/answer/7451001?hl=en","https://www.paperstreet.com/blog/checklist-for-google-indexing-of-new-websites/"]},{"id":"trust-per-page-head-meta-complete","section":"trust","title":"Every page emits its own complete <head> meta set (no transition persistence assumptions)","severity":"high","stage":"build","automatable":true,"check_type":"html_head","what":"Each page declares its full meta set (title, description, og:title, og:image, canonical) in its layout rather than assuming tags persist from a previously visited page under ClientRouter.","why":"ClientRouter diffs and replaces <head> on navigation. A page that omits og:image expecting it to carry over will have it missing when shared or crawled directly. transition:persist is not supported for meta tags (it targets DOM elements like video/UI islands).","fix":"Ensure Layout.astro (or a Head component) always outputs the complete meta set from frontmatter/props on every route. Do not put transition:persist on meta tags.","how_to_check":"For each sampled page, fetch raw HTML with curl (no JS) and assert <title>, <meta name='description'>, <meta property='og:title'>, <meta property='og:image'>, and <link rel='canonical'> all exist and are non-empty. Cross-check a non-homepage URL in opengraph.xyz.","common_mistakes":"Putting transition:persist on a shared header believing meta tags persist across transitions; omitting tags on individual non-homepage routes.","platform_notes":"Rendering concern; identical on Cloudflare Pages and Vercel.","sources":["https://docs.astro.build/en/guides/view-transitions/"]},{"id":"trust-privacy-policy-present-linked","section":"trust","title":"Privacy policy page present, footer-linked, and accurate","severity":"high","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"A privacy policy at a stable URL (e.g. /privacy-policy) is publicly accessible, linked in the footer on all pages, and covers data collected, cookies, third-party services, user rights (GDPR/CCPA), and contact details.","why":"Required by Google Analytics ToS, GDPR, CCPA, and ad platforms, and listed as a trust/YMYL signal in Google's Quality Rater Guidelines. Its absence is flagged as a trust deficiency.","fix":"Create src/pages/privacy-policy.astro (or .md) and link it from Footer.astro: <a href='/privacy-policy'>Privacy Policy</a>. Name the actual analytics tools in use, and update it whenever new third-party scripts are added.","how_to_check":"GET the homepage and assert the footer contains an <a> with href matching /privacy or /privacy-policy; GET that href → 200 with non-empty, non-placeholder body. Run a link checker (lychee) to confirm reachability.","common_mistakes":"Linking a CMP's externally hosted policy (off-domain, bad for E-E-A-T); a generic template that omits the actual tools used; not updating after adding scripts.","platform_notes":"No platform differences.","sources":["https://seolust.com/blog/the-hidden-seo-benefits-of-having-a-privacy-policy-and-terms-page","https://gdpr.eu/cookies/"]},{"id":"trust-uptime-monitoring-alerting","section":"trust","title":"Uptime monitoring with alerting on key URLs","severity":"high","stage":"post-launch","automatable":true,"check_type":"external_tool","what":"An uptime service checks the homepage and 2-3 critical pages at 1-5 minute intervals and alerts (email/Slack/PagerDuty) on non-200 status or response time over a threshold (e.g. >3s).","why":"Undetected downtime serves Googlebot 5xx errors, which can reduce crawl rate or trigger de-indexation, and harms users. Monitoring with alerting is the baseline operational requirement for a launched site.","fix":"Not an Astro concern. Use Uptime Kuma (self-hosted), Better Stack, or Upptime (GitHub Actions). Monitor https://example.com/, /sitemap-index.xml, and the most critical landing page, each with an alert contact configured.","how_to_check":"Query the monitoring service API to confirm active monitors with alert contacts, or as a basic auditor check GET the homepage → 200, Content-Type text/html, response time < 3000ms.","common_mistakes":"Monitoring only the homepage; alert thresholds set too high (30+ min); monitors with no alert contacts (monitoring without alerting is pointless).","platform_notes":"Cloudflare Health Checks are Enterprise-only (or use a free Workers cron). Vercel exposes deployment status webhooks; pair with an external uptime monitor for continuous checks between deploys.","sources":["https://uptimekuma.org/","https://betterstack.com/community/comparisons/open-source-website-monitoring/"]},{"id":"trust-broken-link-check","section":"trust","title":"Broken-link check pre-launch and scheduled post-launch","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"http_status","what":"All internal links return 200 (no 404s or redirect chains) before launch, with the check re-run automatically after each deploy or weekly.","why":"Internal 404s and redirect chains harm UX, waste crawl budget, and dilute PageRank; they are especially common after URL restructuring, migration, or content deletion.","fix":"At build time run lychee against the output: npx lychee './dist/**/*.html' --base https://example.com. Post-launch schedule lychee https://example.com --recursive via a GitHub Actions cron or post-deploy CI job.","how_to_check":"Run lychee against ./dist/ or the live URL and assert exit code 0; the report lists URL, source page, and HTTP status for any failures.","common_mistakes":"Checking internal links only and missing broken external links; not excluding external URLs that legitimately return non-200; not re-running after content changes.","platform_notes":"Run as a post-deploy step; both Cloudflare Pages and Vercel support post-deploy webhook triggers for CI.","sources":["https://github.com/lycheeverse/lychee"]},{"id":"trust-cookieless-analytics-considered","section":"trust","title":"Cookieless, consent-free analytics evaluated before defaulting to GA4","severity":"medium","stage":"pre-launch","automatable":true,"check_type":"body_regex","what":"Before defaulting to GA4, evaluate whether a cookieless option (Plausible, Cloudflare/Vercel Web Analytics, Fathom, Simple Analytics) meets reporting needs, and avoid running two analytics tools without a clear reason.","why":"GA4 needs an EU consent banner and loses data to consent rejection (a Plausible study reported GA4 captured ~55.6% of traffic vs Plausible on the same site — vendor research, disclosed as such). Cookieless tools eliminate that gap; Plausible is GDPR-compliant without a banner per an independent legal assessment.","fix":"Plausible: <script defer data-domain='example.com' src='https://plausible.io/js/script.js'></script> in BaseLayout.astro head (no is:inline — external src). Cloudflare Web Analytics: enable in the CF Pages dashboard (manual snippet if a no-transform header is set). Keep GA4 only where Google Ads conversion data is required, with Consent Mode v2.","how_to_check":"GET page HTML and check <head> for exactly one analytics loader (plausible.io, cloudflareinsights.com, fathom.com, or googletagmanager.com/gtag/js) unless dual-running is intentional. Confirm requests fire in the network tab / the tool's real-time dashboard.","common_mistakes":"Running GA4 and Plausible together with no purpose (double script weight and compliance overhead); assuming Cloudflare/Vercel Web Analytics is always GDPR-safe without a Schrems II data-transfer check; treating cookieless tools as full event-level conversion analytics.","platform_notes":"Cloudflare Web Analytics is free and integrated for CF Pages; Vercel Analytics is cookieless (free tier + paid). Both are supplemental when event-level conversion tracking is needed, and both involve US data transfer.","sources":["https://plausible.io/cookieless-web-analytics","https://plausible.io/blog/legal-assessment-gdpr-eprivacy","https://ethicaldatahub.com/cloudflare-analytics-cookie-banner/"]},{"id":"trust-ga4-conversion-events","section":"trust","title":"GA4 key conversion events configured and verified (if GA4 is used)","severity":"medium","stage":"post-launch","automatable":true,"check_type":"external_tool","what":"If GA4 is the analytics platform, at least one conversion event (e.g. generate_lead, form_submit, purchase) is configured, marked as a conversion, and verified firing in DebugView; staging/preview traffic is excluded.","why":"Pageview data alone is near-useless for business decisions; a GA4 install with no configured conversions has largely wasted the install.","fix":"Fire the event in the form success handler: gtag('event','generate_lead',{ method:'contact_form' }), then mark it as a conversion in GA4 Admin → Events. With ClientRouter, re-attach form handlers on each astro:page-load (handlers bound at initial load are lost after client navigation). Gate firing by checking window.location.hostname so staging doesn't pollute data.","how_to_check":"In GA4 DebugView, submit the form on the live site and assert the conversion event appears within ~30s. Automated: a headless test that submits the form, intercepts the GA4 collect endpoint, and asserts the event name in the payload.","common_mistakes":"Marking page_view as a conversion; not testing in DebugView; firing conversions in dev/staging; attaching success handlers only at DOMContentLoaded so they're lost after View Transitions.","platform_notes":"For Cloudflare Pages/Vercel preview deployments, gate firing: if (window.location.hostname === 'example.com') gtag(...).","sources":["https://astroseoblog.com/blog/astro-google-analytics-integration-guide","https://docs.astro.build/en/guides/view-transitions/"]},{"id":"trust-indexnow-configured","section":"trust","title":"IndexNow configured to push changed URLs to Bing and partner engines","severity":"medium","stage":"build","automatable":true,"check_type":"http_status","what":"An IndexNow API key file is hosted at the site root and changed-page URLs are submitted to the IndexNow endpoint after each build.","why":"IndexNow removes multi-day crawl delays for Bing, DuckDuckGo, and Yandex by proactively pushing changed URLs; Bing's 2025 guidance positions it as complementary to sitemaps for near-real-time AI-search freshness. Google does not support IndexNow as of 2026.","fix":"Add the astro-indexnow integration (manual config required — astro add does not inject values): integrations:[indexnow({ key: process.env.INDEXNOW_KEY })] with site set; place <key>.txt in public/. The plugin walks final HTML at build and submits only changed URLs via hash diffing.","how_to_check":"GET https://example.com/<key>.txt → 200 with body equal to the key string. After a build, confirm an IndexNow submission in the CI logs, or POST a urlList to https://api.indexnow.org/indexnow and expect 200/202.","common_mistakes":"Hosting the key only in dev so it's excluded from public/ build output; submitting every build including unchanged pages (use hash diffing).","platform_notes":"Both platforms run the Astro build before deploy so the hook fires at build time. Set INDEXNOW_KEY in the CF Pages dashboard or Vercel Project Settings → Environment Variables.","sources":["https://github.com/velohost/astro-indexnow","https://blog.cloudflare.com/cloudflare-now-supports-indexnow/"]},{"id":"antipatterns-no-cloaking","section":"antipatterns","title":"Do not cloak or show different content to crawlers than to users","severity":"critical","stage":"build","automatable":true,"check_type":"manual","what":"Never serve materially different content, markup, or redirects to Googlebot/Bingbot (detected by user-agent or IP) than you serve to real users. This includes server-rendering keyword-rich HTML only for bots while showing users something else.","why":"Cloaking is an explicit violation of Google's spam policies and can trigger manual actions or full deindexing. With Astro SSR/edge functions it is easy to accidentally (or deliberately) branch on user-agent; the safe rule is parity for everyone.","fix":"In Astro, render the same HTML regardless of user-agent. Do not branch SSR output, redirects, or `Astro.request.headers.get('user-agent')` logic to give bots special content. If you need bot-specific behavior (e.g. prerendering for JS-heavy widgets), ensure the visible content is identical to what users get. Geo/locale redirects must apply equally to bots and users and should be reversible.","how_to_check":"Fetch a page twice with a normal browser UA and with `Googlebot` UA and diff the rendered HTML/main content and final URL; any meaningful difference in body content or redirect target is cloaking. Use Google Search Console URL Inspection (\"View crawled page\") and compare to the live page a user sees.","common_mistakes":"User-agent sniffing to swap content; redirecting bots to a different page than users; injecting hidden keyword blocks only into the SSR response. Note: serving WebP/AVIF or compression by Accept header is NOT cloaking.","platform_notes":"Both Vercel Functions and Cloudflare Pages Functions expose the request UA easily; resist the temptation to branch content on it.","sources":["https://developers.google.com/search/docs/essentials/spam-policies#cloaking","https://developers.google.com/search/docs/crawling-indexing/javascript/dynamic-rendering"]},{"id":"antipatterns-no-indexable-staging-preview","section":"antipatterns","title":"Never let staging or preview deployments get indexed","severity":"critical","stage":"pre-launch","automatable":true,"check_type":"http_header","what":"Preview and staging URLs (Cloudflare Pages *.pages.dev preview aliases, Vercel *.vercel.app preview deployments, branch deploys) must not be crawlable or indexable, and they must not compete with the production domain.","why":"Indexed staging/preview domains create exact-duplicate content that splits ranking signals, can outrank or replace the canonical production domain in results, and may leak unfinished or confidential content. This is one of the most common and most damaging launch mistakes.","fix":"Gate non-production environments with HTTP Basic Auth or platform access protection so crawlers never reach them, and emit `X-Robots-Tag: noindex, nofollow` plus a `robots.txt` `Disallow: /` on those hosts only. In Astro, branch on the deploy context: read `import.meta.env.PROD`/a custom `PUBLIC_ENV` var (or `CF_PAGES_BRANCH` / `VERCEL_ENV`) and conditionally render `<meta name=\"robots\" content=\"noindex\">` and serve a blocking robots.txt for any host that is not the production domain. Never hardcode noindex into shared layout where it can leak to production.","how_to_check":"Request a preview URL (e.g. a *.vercel.app or *.pages.dev preview) and assert it returns `X-Robots-Tag: noindex` (or 401 behind auth) and a `robots.txt` with `Disallow: /`; then assert the production domain does NOT carry those. Also `site:*.vercel.app yourbrand` / `site:*.pages.dev` in Google to confirm nothing leaked.","common_mistakes":"Hardcoding noindex globally and forgetting to strip it for production; protecting the canonical production preview alias but leaving per-branch preview aliases open; relying only on robots.txt (which blocks crawl but not indexing of already-known URLs).","platform_notes":"Vercel: set Deployment Protection (Vercel Authentication) on Preview/branch deployments; use `VERCEL_ENV` (production|preview|development) to branch. Cloudflare Pages: enable Access policy on preview deployments and branch on `CF_PAGES_BRANCH`; the production alias is the only one that should be public.","sources":["https://developers.google.com/search/docs/crawling-indexing/block-indexing","https://vercel.com/docs/security/deployment-protection","https://developers.cloudflare.com/pages/configuration/preview-deployments/"]},{"id":"antipatterns-no-buying-or-spammy-links","section":"antipatterns","title":"Don't buy links or build spammy link schemes","severity":"high","stage":"post-launch","automatable":false,"check_type":"manual","what":"Do not participate in link schemes: paid links that pass PageRank, large-scale guest-post/article spam for links, link exchanges, PBNs, or sitewide footer/widget links with keyword-rich anchors.","why":"Link schemes are a Google spam policy violation that can trigger manual actions and algorithmic suppression. For a freshly launched site this is a common growth-hack temptation that risks the whole domain.","fix":"Earn links via genuinely useful content and outreach. Any paid or sponsored/affiliate link you control must be marked `rel=\"sponsored\"` or `rel=\"nofollow\"`; user-generated links should use `rel=\"ugc\"`. Set these attributes on the relevant `<a>` tags in your Astro components/MDX.","how_to_check":"Manual link-profile review (Search Console Links report / a backlink tool) for unnatural anchor patterns and known link-farm sources; audit outbound paid/affiliate links for missing `rel=\"sponsored\"`/`nofollow`.","common_mistakes":"Buying a backlink package on launch; mass guest posting with exact-match anchors; forgetting rel=sponsored on affiliate links.","sources":["https://developers.google.com/search/docs/essentials/spam-policies#link-spam","https://developers.google.com/search/docs/crawling-indexing/qualify-outbound-links"]},{"id":"antipatterns-no-doorway-pages","section":"antipatterns","title":"Avoid doorway pages and mass-generated thin location/keyword pages","severity":"high","stage":"build","automatable":false,"check_type":"manual","what":"Do not generate large sets of near-identical, low-value pages that exist only to rank for permutations of keywords or locations (e.g. \"[service] in [city]\" templated pages with swapped tokens and no unique substance) that all funnel users to the same destination.","why":"Doorway pages are a named Google spam policy violation. Astro's content collections and `getStaticPaths` make it trivially easy to programmatically spin up thousands of templated pages, which is exactly the pattern Google penalizes when the pages lack unique value.","fix":"When using `getStaticPaths` to fan out pages, ensure each generated page has substantively unique, useful content (unique copy, data, media) and a distinct intent. Consolidate thin permutations into fewer richer pages. If pages must exist for navigation but add no search value, mark them `noindex`.","how_to_check":"Sample a set of programmatically generated routes and compute body-text similarity; high cross-page similarity with only token substitution flags doorway/thin patterns. Manually review whether each templated page would stand alone as useful. Watch Search Console for \"Thin content\" / manual actions.","common_mistakes":"Generating a page per city/keyword from a spreadsheet with identical boilerplate; auto-generating tag/filter pages with near-zero unique content and leaving them indexable.","sources":["https://developers.google.com/search/docs/essentials/spam-policies#doorways","https://developers.google.com/search/docs/essentials/spam-policies#scaled-content-abuse"]},{"id":"antipatterns-no-hidden-text-keyword-stuffing","section":"antipatterns","title":"No hidden text, sneaky links, or keyword stuffing","severity":"high","stage":"build","automatable":true,"check_type":"body_regex","what":"Do not hide text or links from users to manipulate rankings (white-on-white text, `display:none`/`visibility:hidden`/off-screen positioning used to stash keywords, 1px fonts, alt-text stuffed with keywords) and do not stuff unnatural repeated keyword lists into copy, headings, or meta.","why":"Hidden text and keyword stuffing are direct spam-policy violations that risk manual actions, and they hurt real UX and accessibility. Modern Google ranks on semantic relevance, so stuffing provides no upside and real downside.","fix":"Write natural prose for humans. Use CSS hiding only for genuine UX patterns (accessible toggles, screen-reader-only labels with real meaning), not to conceal keyword text. Keep `alt` attributes descriptive of the image, not keyword lists. Remove any visually-hidden blocks whose only purpose is keywords.","how_to_check":"Scan rendered HTML/CSS for text nodes with near-invisible styling (color matching background, font-size <= 1px, large negative text-indent, off-screen absolute positioning containing body keywords). Compute keyword density on main content and flag unnatural repetition; check for stuffed alt attributes.","common_mistakes":"Stashing a keyword paragraph in a `display:none` div; repeating the target phrase dozens of times; stuffing meta description or alt text with comma-separated keywords.","sources":["https://developers.google.com/search/docs/essentials/spam-policies#hidden-text-and-links","https://developers.google.com/search/docs/essentials/spam-policies#keyword-stuffing"]},{"id":"antipatterns-no-blocking-css-js-in-robots","section":"antipatterns","title":"Don't block CSS, JS, or asset directories in robots.txt","severity":"medium","stage":"build","automatable":true,"check_type":"robots","what":"Do not `Disallow` your CSS, JavaScript, image, or `_astro`/build asset directories in robots.txt. Google needs to fetch these to render and evaluate the page.","why":"Blocking render-critical resources prevents Googlebot from seeing the page as users do, which can cause broken rendering evaluation, missed content, and mobile-usability issues. It's a legacy practice from when crawlers didn't render JS.","fix":"Keep robots.txt minimal: allow asset paths (including Astro's `/_astro/` hashed bundle directory and `/images/`). Only disallow truly non-public or infinite-crawl-space paths (e.g. faceted-search query URLs). Generate robots.txt via an Astro endpoint or a vetted integration rather than hand-copying an old one.","how_to_check":"Fetch `/robots.txt` and assert it does not `Disallow` `/_astro/`, `*.css`, `*.js`, or image directories; cross-check with Search Console URL Inspection \"Page resources\" for blocked render resources.","common_mistakes":"Pasting a CMS-era robots.txt that blocks `/assets/` or `/js/`; disallowing the whole site (`Disallow: /`) on production by accident.","sources":["https://developers.google.com/search/docs/crawling-indexing/robots/intro","https://developers.google.com/search/docs/crawling-indexing/robots/create-robots-txt"]},{"id":"antipatterns-no-fake-or-misused-structured-data","section":"antipatterns","title":"Don't add fake, invisible, or irrelevant structured data","severity":"medium","stage":"build","automatable":true,"check_type":"json_ld","what":"Do not mark up content that isn't visible on the page, fabricate reviews/ratings, apply schema types that don't match the page (e.g. Product/Recipe schema on a page that is neither), or self-serve aggregate review markup. This is structured-data spam.","why":"Misleading or invisible structured data violates Google's structured-data guidelines and can cause a manual action that strips ALL rich results from the site, not just the bad page.","fix":"Only emit JSON-LD that describes content actually present and visible on the page. Build your `<script type=\"application/ld+json\">` from the same data you render (e.g. content collection frontmatter), keep types accurate (Article, BreadcrumbList, Organization, etc.), and don't inject self-authored review/rating markup.","how_to_check":"Validate every page's JSON-LD with the Rich Results Test / Schema.org validator; assert each declared entity's key fields correspond to on-page visible content, and flag review/rating, Product, or FAQ markup that has no matching visible content.","common_mistakes":"Copy-pasting a Product schema block onto blog pages; fabricating aggregateRating; marking up FAQ content that isn't shown to users.","sources":["https://developers.google.com/search/docs/appearance/structured-data/sd-policies","https://developers.google.com/search/docs/appearance/structured-data/intro-structured-data"]},{"id":"antipatterns-no-fid-era-cwv-advice","section":"antipatterns","title":"Optimize INP, not the retired FID metric","severity":"medium","stage":"post-launch","automatable":true,"check_type":"lighthouse","what":"Do not target First Input Delay (FID) — it was retired as a Core Web Vital in March 2024 and replaced by Interaction to Next Paint (INP). Advice and tooling that still optimize for FID are out of date.","why":"FID only measured input delay of the first interaction and was easy to pass while the page still felt sluggish. INP measures responsiveness across all interactions and is the current ranking-relevant CWV, so optimizing for the old metric misses real UX problems.","fix":"Measure and optimize INP (target <= 200ms, plus LCP <= 2.5s and CLS <= 0.1). In Astro, leverage its zero/low-JS default: ship HTML-first, use Islands with the lightest viable `client:*` directive (`client:visible`/`client:idle` over `client:load`), avoid hydrating large interactive trees, and break up long tasks. Use the field-data INP from CrUX/Search Console, not just lab FID.","how_to_check":"Run Lighthouse / PageSpeed Insights and CrUX field data and assert INP is reported and within budget; flag any config, third-party script, or doc still referencing FID as the responsiveness target.","common_mistakes":"Reporting a passing FID and declaring CWV done; following 2022-era guides that never mention INP; over-hydrating Astro islands with `client:load` everywhere.","sources":["https://web.dev/blog/inp-cwv-march-12","https://web.dev/articles/inp","https://docs.astro.build/en/reference/directives-reference/#client-directives"]},{"id":"antipatterns-no-noindex-plus-disallow-conflict","section":"antipatterns","title":"Never combine noindex with a robots.txt Disallow on the same URL","severity":"medium","stage":"build","automatable":true,"check_type":"robots","what":"Do not try to deindex a page by both `noindex`-ing it and `Disallow`-ing it in robots.txt. If the URL is blocked from crawling, Google can't see the noindex directive, so the page can still get indexed (URL-only) and won't drop out.","why":"This is a self-defeating, extremely common pattern. The robots block prevents Google from reading the very tag that would remove the page, so the page lingers in the index as a thin URL-only entry.","fix":"To remove a page from the index: allow it to be crawled and serve `<meta name=\"robots\" content=\"noindex\">` (or `X-Robots-Tag: noindex` header). Only after it has dropped out should you consider disallowing it. To merely save crawl budget on never-index junk, disallow is fine — but don't expect existing indexed URLs to disappear from a disallow alone.","how_to_check":"Cross-reference: for each URL carrying noindex, assert it is NOT also Disallowed in robots.txt. Flag any URL that is both noindex and robots-blocked.","common_mistakes":"Adding both 'just to be safe'; using robots.txt to remove an already-indexed page instead of noindex; disallowing a path then wondering why it's still in search results.","sources":["https://developers.google.com/search/docs/crawling-indexing/block-indexing","https://developers.google.com/search/docs/crawling-indexing/robots/intro"]},{"id":"antipatterns-no-exact-match-domain-spam","section":"antipatterns","title":"Don't rely on exact-match domains or keyword-stuffed URLs","severity":"low","stage":"build","automatable":false,"check_type":"manual","what":"Do not assume a keyword-stuffed exact-match domain (e.g. best-cheap-running-shoes-online.com) or hyphen-laden keyword URLs will rank. Google's EMD update (2012) removed the boost low-quality exact-match domains used to get.","why":"Choosing a brand strategy around keyword domains is a persistent myth; it produces a spammy, low-trust brand and no ranking advantage. Worse, over-optimized hyphenated keyword URLs read as spam to users.","fix":"Pick a short, memorable, brandable domain. Keep URL slugs clean and descriptive but human (`/running-shoes`, not `/best-cheap-running-shoes-online-2026`). In Astro, derive slugs from content collection IDs/titles and avoid jamming keywords into the path.","how_to_check":"Manual review of domain and slug strategy: flag domains/slugs that are long strings of hyphenated target keywords rather than a brand + concise topic.","common_mistakes":"Buying an EMD expecting a ranking head start; generating slugs that concatenate every keyword; stuffing dates/keywords into permalinks.","sources":["https://developers.google.com/search/docs/crawling-indexing/url-structure","https://www.searchenginejournal.com/google-emd-update/"]},{"id":"antipatterns-no-keywords-meta-tag","section":"antipatterns","title":"Drop the keywords meta tag (and other dead meta SEO tags)","severity":"low","stage":"build","automatable":true,"check_type":"html_head","what":"Do not add `<meta name=\"keywords\">`; it has been ignored by Google for ranking since 2009. Also skip other defunct ranking meta tags (e.g. `<meta name=\"revisit-after\">`, `<meta name=\"author\">` as an SEO signal, generic `<meta name=\"distribution\">`).","why":"These tags provide zero ranking benefit, clutter the head, and a populated keywords tag visibly exposes your target keyword list to competitors. Including them signals outdated SEO advice.","fix":"Remove any `<meta name=\"keywords\">` from your Astro layout/head. Keep only meta tags that do something: `<title>`, `<meta name=\"description\">`, robots, canonical, viewport, charset, and Open Graph/Twitter tags. Centralize head tags in a single `<BaseHead>` component so dead tags don't creep back in.","how_to_check":"Parse the HTML `<head>` and assert `<meta name=\"keywords\">` (and other deprecated SEO meta tags) are absent across pages.","common_mistakes":"Copying a 2010-era head template; an SEO plugin or CMS field that re-injects a keywords tag.","sources":["https://developers.google.com/search/blog/2009/09/google-does-not-use-keywords-meta-tag","https://developers.google.com/search/docs/crawling-indexing/special-tags"]},{"id":"antipatterns-no-rel-next-prev-for-google","section":"antipatterns","title":"Don't rely on rel=next/prev as a Google SEO tactic","severity":"low","stage":"build","automatable":true,"check_type":"html_head","what":"Do not add `<link rel=\"next\">`/`<link rel=\"prev\">` expecting Google to use them for pagination — Google dropped support in 2019 and does not crawl URLs discovered only via these hints. They are not an SEO requirement.","why":"Treating rel=next/prev as a Google ranking/indexing mechanism is a myth that wastes effort and can hide pagination behind links Google ignores. (They remain harmless and may still help Bing and assistive tech, so this is a low-severity 'don't depend on it' rather than 'never use it'.)","fix":"For paginated Astro routes built with `paginate()`/`getStaticPaths`, give each page a self-referencing canonical and ensure every paginated URL is reachable via crawlable in-page `<a href>` links (and listed in the sitemap) so Google can discover them independently of rel=next/prev. Keep rel=next/prev only if you specifically care about Bing or accessibility.","how_to_check":"Parse the head: if rel=next/prev are present, verify paginated pages are ALSO linked via real anchors and present in the sitemap (so discovery doesn't depend on the hints). Confirm each paginated page has a self-canonical to itself, not to page 1.","common_mistakes":"Canonicalizing every paginated page to page 1 (drops deep pages from the index); using rel=next/prev as the only link between pages so Google never crawls them.","sources":["https://developers.google.com/search/blog/2019/03/two-pages-in-one-or-pagination","https://ahrefs.com/blog/rel-prev-next-pagination/"]}]};
